import * as React from "react";

const MOBILE_BREAKPOINT = 768;

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined);

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    };
    mql.addEventListener("change", onChange);
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    return () => mql.removeEventListener("change", onChange);
  }, []);

  return !!isMobile;
}

import * as React from "react";

import type { ToastActionElement, ToastProps } from "@/components/ui/toast";

const TOAST_LIMIT = 1;
const TOAST_REMOVE_DELAY = 1000000;

type ToasterToast = ToastProps & {
  id: string;
  title?: React.ReactNode;
  description?: React.ReactNode;
  action?: ToastActionElement;
};

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const;

let count = 0;

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER;
  return count.toString();
}

type ActionType = typeof actionTypes;

type Action =
  | {
      type: ActionType["ADD_TOAST"];
      toast: ToasterToast;
    }
  | {
      type: ActionType["UPDATE_TOAST"];
      toast: Partial<ToasterToast>;
    }
  | {
      type: ActionType["DISMISS_TOAST"];
      toastId?: ToasterToast["id"];
    }
  | {
      type: ActionType["REMOVE_TOAST"];
      toastId?: ToasterToast["id"];
    };

interface State {
  toasts: ToasterToast[];

}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>();

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return;
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId);
    dispatch({
      type: "REMOVE_TOAST",
      toastId,
    });
  }, TOAST_REMOVE_DELAY);

  toastTimeouts.set(toastId, timeout);
};

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      };

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t,
        ),
      };

    case "DISMISS_TOAST": {
      const { toastId } = action;
      if (toastId) {
        addToRemoveQueue(toastId);
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id);
        });
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined

            ? {
                ...t,
                open: false,
              }
            : t,
        ),
      };
    }

    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        };
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      };
  }
};

const listeners: Array<(state: State) => void> = [];
let memoryState: State = { toasts: [] };

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action);
  listeners.forEach((listener) => {
    listener(memoryState);
  });
}

type Toast = Omit<ToasterToast, "id">;

function toast({ ...props }: Toast) {
  const id = genId();

  const update = (next: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...next, id },
    });
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id });

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,

      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss();
      },
    },
  });

  return {
    id,
    dismiss,
    update,
  };
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState);

  React.useEffect(() => {
    listeners.push(setState);
    return () => {
      const index = listeners.indexOf(setState);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    };
  }, []);

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  };
}

export { useToast, toast };

import { useState, useCallback, useRef, useEffect } from 'react';

// MISS-006 — AC Pressure Generation (Crown Jewel #11)
// Paired Golden Lotus chambers operating 180° out of phase create alternating
// push/pull pressure waves (AC wave). Frequency governed by Ouralis cycle. No external pumps.

export type ACPhase = 'push_A' | 'neutral' | 'push_B' | 'neutral_B';

export interface GoldenLotusState {
  id: 'A' | 'B';
  angle: number;       // 0–360 degrees
  pressure: number;    // -1.0 to 1.0 (negative = push, positive = pull)
  flowRate: number;    // 0–1
}

export interface ACPressureState {
  phase: ACPhase;
  cycleStep: number;         // 0–11 (tracks Ouralis cycle)
  waveFrequency: number;     // Hz equivalent (cycles per game turn)
  peakPressure: number;      // PSI at current step
  acAmplitude: number;       // 0–1, combined AC wave amplitude
  chamberA: GoldenLotusState;
  chamberB: GoldenLotusState;
  totalCycles: number;
  gameTurn: number;
  isRunning: boolean;
  tickMs: number;
}

export interface ACPressureControls {
  start: () => void;
  pause: () => void;
  reset: () => void;
  tick: () => void;
  setTickMs: (ms: number) => void;
}

function buildChamber(id: 'A' | 'B', offset: number): GoldenLotusState {
  return { id, angle: offset, pressure: 0, flowRate: 0 };
}

function derivePhase(step: number): ACPhase {
  if (step <= 2) return 'push_A';
  if (step <= 5) return 'neutral';
  if (step <= 8) return 'push_B';
  return 'neutral_B';
}

export function useACPressureGeneration(initialTickMs = 700): {
  state: ACPressureState;

  controls: ACPressureControls;
} {
  const [state, setState] = useState<ACPressureState>({
    phase: 'neutral',
    cycleStep: 0,
    waveFrequency: 1,
    peakPressure: 0,
    acAmplitude: 0,
    chamberA: buildChamber('A', 0),
    chamberB: buildChamber('B', 180),
    totalCycles: 0,
    gameTurn: 0,
    isRunning: false,
    tickMs: initialTickMs,
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const tick = useCallback(() => {
    setState(prev => {
      const nextStep = (prev.cycleStep + 1) % 12;
      const total = prev.totalCycles + 1;
      const gameTurn = Math.floor(total / 12);
      const phase = derivePhase(nextStep);

      // Chamber A leads; Chamber B is 180° offset
      const angleA = (prev.chamberA.angle + 30) % 360;
      const angleB = (prev.chamberB.angle + 30) % 360;

      const sinA = Math.sin((angleA * Math.PI) / 180);
      const sinB = Math.sin((angleB * Math.PI) / 180);

      // AC amplitude is combination — chambers push/pull alternately
      const acAmplitude = Math.abs(sinA - sinB) / 2;
      const peakPressure = parseFloat((acAmplitude * 2.17).toFixed(3)); // max 2.17 PSI

      return {
        ...prev,
        phase,
        cycleStep: nextStep,
        totalCycles: total,
        gameTurn,
        acAmplitude,
        peakPressure,
        waveFrequency: parseFloat((1 / (12 * (prev.tickMs / 1000))).toFixed(3)),
        chamberA: { ...prev.chamberA, angle: angleA, pressure: sinA, flowRate: Math.max(0, sinA) },
        chamberB: { ...prev.chamberB, angle: angleB, pressure: sinB, flowRate: Math.max(0, sinB) },
      };
    });
  }, []);

  const start = useCallback(() => setState(prev => ({ ...prev, isRunning: true })), []);
  const pause = useCallback(() => setState(prev => ({ ...prev, isRunning: false })), []);

  const reset = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    setState(prev => ({
      ...prev,
      phase: 'neutral',
      cycleStep: 0,
      totalCycles: 0,
      gameTurn: 0,
      acAmplitude: 0,
      peakPressure: 0,
      chamberA: buildChamber('A', 0),
      chamberB: buildChamber('B', 180),
      isRunning: false,
    }));
  }, []);

  const setTickMs = useCallback((ms: number) => {
    setState(prev => ({ ...prev, tickMs: ms }));
  }, []);

  useEffect(() => {
    if (state.isRunning) {
      intervalRef.current = setInterval(tick, state.tickMs);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [state.isRunning, state.tickMs, tick]);

  return { state, controls: { start, pause, reset, tick, setTickMs } };
}

import { useState, useCallback } from 'react';

// STUB-007 — Airtight Hydraulic Snap-Fit Assembly
// Stub implementation — depends on MISS-001 (Wave 3).
// RootLockSystem snap-fit; airtight simulation not wired.
// Requires: pressure-seal-integrity indicator + snap-force feedback at connection points.

export type SnapFitStatus = 'unconnected' | 'engaging' | 'snapped' | 'sealed' | 'leak';
export type SealIntegrity = 'none' | 'partial' | 'airtight' | 'pressurized';

export interface ConnectionPoint {
  id: string;
  label: string;             // e.g. 'N', 'NE', 'SE', 'S', 'SW', 'NW'
  snapStatus: SnapFitStatus;
  sealIntegrity: SealIntegrity;
  snapForceN: number;        // Newtons — snap force feedback
  pressureBarAtPoint: number;
  leakRateML: number;        // mL/min — 0 if sealed
}

export interface RootLockSnapState {
  connectionPoints: ConnectionPoint[];
  systemPressureBar: number;
  overallSealIntegrity: SealIntegrity;
  snapCount: number;            // how many points are snapped
  sealedCount: number;          // how many are fully sealed
  isAirtight: boolean;
  // MISS-001 dependency stub — not wired
  miss001Connected: false;
  // Note: full airtight simulation pending MISS-001 hydraulic root system
  simulationStubNote: string;
}

export interface SnapFitControls {
  init: () => void;
  snapPoint: (pointId: string) => void;
  snapAll: () => void;
  pressurize: (targetBar: number) => void;
  releasePoint: (pointId: string) => void;
  releaseAll: () => void;
  reset: () => void;
}

const HEX_DIRECTIONS = ['N', 'NE', 'SE', 'S', 'SW', 'NW'];

function buildConnectionPoints(): ConnectionPoint[] {
  return HEX_DIRECTIONS.map((label, i) => ({
    id: `cp-${label.toLowerCase()}`,
    label,
    snapStatus: 'unconnected',

    sealIntegrity: 'none',
    snapForceN: 0,
    pressureBarAtPoint: 0,
    leakRateML: 0,
  }));
}

function snapForceForStatus(status: SnapFitStatus): number {
  switch (status) {
    case 'unconnected': return 0;
    case 'engaging':    return 12;
    case 'snapped':     return 35;
    case 'sealed':      return 42;
    case 'leak':        return 28;
    default: return 0;
  }
}

function computeOverallIntegrity(points: ConnectionPoint[]): SealIntegrity {
  const sealedAll = points.every(p => p.sealIntegrity === 'airtight' || p.sealIntegrity === 'pressurized');
  const anyPartial = points.some(p => p.sealIntegrity === 'partial');
  const anyPressurized = points.some(p => p.sealIntegrity === 'pressurized');
  if (anyPressurized && sealedAll) return 'pressurized';
  if (sealedAll) return 'airtight';
  if (anyPartial) return 'partial';
  return 'none';
}

export function useAirtightHydraulicSnapFitAssembly(): {
  state: RootLockSnapState;
  controls: SnapFitControls;
} {
  const [state, setState] = useState<RootLockSnapState>({
    connectionPoints: buildConnectionPoints(),
    systemPressureBar: 0,
    overallSealIntegrity: 'none',
    snapCount: 0,
    sealedCount: 0,
    isAirtight: false,
    miss001Connected: false,
    simulationStubNote: 'STUB-007: Airtight hydraulic simulation pending MISS-001 (Wave 3). Snap-fit geometry and force feedback are implemented; pressure seal sim is stubbed.',
  });

  const init = useCallback(() => {
    setState(prev => ({ ...prev, connectionPoints: buildConnectionPoints(), systemPressureBar: 0, overallSealIntegrity: 'none', snapCount: 0, sealedCount: 0, isAirtight: false }));
  }, []);

  const snapPoint = useCallback((pointId: string) => {
    setState(prev => {
      const points = prev.connectionPoints.map(p => {

        if (p.id !== pointId) return p;
        if (p.snapStatus === 'unconnected' || p.snapStatus === 'engaging') {
          return {
            ...p,
            snapStatus: 'snapped' as SnapFitStatus,
            sealIntegrity: 'partial' as SealIntegrity,
            snapForceN: snapForceForStatus('snapped'),
            leakRateML: 2.5,
          };
        }
        if (p.snapStatus === 'snapped') {
          return {
            ...p,
            snapStatus: 'sealed' as SnapFitStatus,
            sealIntegrity: 'airtight' as SealIntegrity,
            snapForceN: snapForceForStatus('sealed'),
            leakRateML: 0,
          };
        }
        return p;
      });
      const overallSealIntegrity = computeOverallIntegrity(points);
      const snapCount = points.filter(p => p.snapStatus !== 'unconnected').length;
      const sealedCount = points.filter(p => p.snapStatus === 'sealed').length;
      return { ...prev, connectionPoints: points, overallSealIntegrity, snapCount, sealedCount, isAirtight: sealedCount === 6 };
    });
  }, []);

  const snapAll = useCallback(() => {
    setState(prev => {
      const points = prev.connectionPoints.map(p => ({
        ...p,
        snapStatus: 'sealed' as SnapFitStatus,
        sealIntegrity: 'airtight' as SealIntegrity,
        snapForceN: snapForceForStatus('sealed'),
        leakRateML: 0,
      }));
      return { ...prev, connectionPoints: points, overallSealIntegrity: 'airtight', snapCount: 6, sealedCount: 6, isAirtight: true };
    });
  }, []);

  const pressurize = useCallback((targetBar: number) => {
    setState(prev => {
      if (!prev.isAirtight) return prev; // can't pressurize if not sealed
      const points = prev.connectionPoints.map(p => ({
        ...p,
        sealIntegrity: 'pressurized' as SealIntegrity,
        pressureBarAtPoint: targetBar * (0.85 + Math.random() * 0.1),
      }));
      return { ...prev, connectionPoints: points, systemPressureBar: targetBar, overallSealIntegrity: 'pressurized' };

    });
  }, []);

  const releasePoint = useCallback((pointId: string) => {
    setState(prev => {
      const points = prev.connectionPoints.map(p =>
        p.id === pointId
          ? { ...p, snapStatus: 'unconnected' as SnapFitStatus, sealIntegrity: 'none' as SealIntegrity, snapForceN: 0, pressureBarAtPoint: 0, leakRateML: 0 }
          : p
      );
      const overallSealIntegrity = computeOverallIntegrity(points);
      const snapCount = points.filter(p => p.snapStatus !== 'unconnected').length;
      const sealedCount = points.filter(p => p.snapStatus === 'sealed').length;
      return { ...prev, connectionPoints: points, overallSealIntegrity, snapCount, sealedCount, isAirtight: false, systemPressureBar: 0 };
    });
  }, []);

  const releaseAll = useCallback(() => {
    setState(prev => ({
      ...prev,
      connectionPoints: buildConnectionPoints(),
      systemPressureBar: 0,
      overallSealIntegrity: 'none',
      snapCount: 0,
      sealedCount: 0,
      isAirtight: false,
    }));
  }, []);

  const reset = useCallback(() => {
    setState({
      connectionPoints: buildConnectionPoints(),
      systemPressureBar: 0,
      overallSealIntegrity: 'none',
      snapCount: 0,
      sealedCount: 0,
      isAirtight: false,
      miss001Connected: false,
      simulationStubNote: 'STUB-007: Airtight hydraulic simulation pending MISS-001 (Wave 3). Snap-fit geometry and force feedback are implemented; pressure seal sim is stubbed.',
    });
  }, []);

  return { state, controls: { init, snapPoint, snapAll, pressurize, releasePoint, releaseAll, reset } };
}

import { useMemo } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { ALCOVES, ALCOVE_REWARDS, PATTERN_KEYS, type Alcove, type AlcoveTier, type PatternKeyLevel } from "@/lib/alcoveSystem";

type AlcoveProgressRow = {
  stop_slug: string;
  tier: number;
  visited_at: string | null;
  comprehended_at: string | null;
  marks_awarded: number | null;
};

export type AlcoveProgressItem = {
  alcove: Alcove;
  visited: boolean;
  comprehended: boolean;
  marksAwarded: number;
  visitedAt: string | null;
  comprehendedAt: string | null;
};

export type UseAlcoveProgressResult = {
  isLoading: boolean;
  stops: AlcoveProgressItem[];
  completedCount: number;
  currentTier: AlcoveTier;
  totalMarks: number;
  patternKeys: PatternKeyLevel[];
  foundersForgeUnlocked: boolean;
  markVisited: (alcove: Alcove) => Promise<void>;
  markComprehended: (alcove: Alcove) => Promise<void>;
};

export function useAlcoveProgress(): UseAlcoveProgressResult {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  const { data, isLoading } = useQuery({
    queryKey: ["alcove-progress", user?.id],
    enabled: !!user?.id,
    queryFn: async () => {
      const { data, error } = await supabase
        .from("alcove_progress" as never)
        .select("stop_slug,tier,visited_at,comprehended_at,marks_awarded")
        .eq("user_id", user!.id);
      if (error) throw error;
      return (data ?? []) as AlcoveProgressRow[];
    },

    staleTime: 15_000,
  });

  const rowBySlug = useMemo(() => {
    const map = new Map<string, AlcoveProgressRow>();
    (data ?? []).forEach((row) => map.set(row.stop_slug, row));
    return map;
  }, [data]);

  const stops = useMemo<AlcoveProgressItem[]>(() => {
    return ALCOVES.map((alcove) => {
      const row = rowBySlug.get(alcove.id);
      return {
        alcove,
        visited: !!row?.visited_at,
        comprehended: !!row?.comprehended_at,
        marksAwarded: Number(row?.marks_awarded ?? 0),
        visitedAt: row?.visited_at ?? null,
        comprehendedAt: row?.comprehended_at ?? null,
      };
    });
  }, [rowBySlug]);

  const completedCount = useMemo(() => stops.filter((s) => s.comprehended).length, [stops]);

  const currentTier = useMemo<AlcoveTier>(() => {
    if (completedCount >= 12) return 3;
    if (completedCount >= 6) return 2;
    return 1;
  }, [completedCount]);

  const patternKeys = useMemo<PatternKeyLevel[]>(() => {
    const result: PatternKeyLevel[] = [];
    ([1, 2, 3] as const).forEach((tier) => {
      const done = stops.filter((s) => s.alcove.tier === tier).every((s) => s.comprehended);
      if (done) result.push(PATTERN_KEYS[tier]);
    });
    return result;
  }, [stops]);

  const totalMarks = useMemo(() => {
    const base = stops.reduce((sum, stop) => sum + stop.marksAwarded, 0);
    const tierBonus = patternKeys.length * ALCOVE_REWARDS.tierComplete;
    const allCompleteBonus = completedCount === 18 ? ALCOVE_REWARDS.allComplete : 0;
    return base + tierBonus + allCompleteBonus;
  }, [stops, patternKeys, completedCount]);

  const refresh = async () => {
    await queryClient.invalidateQueries({ queryKey: ["alcove-progress", user?.id] });
  };

  const markVisited = async (alcove: Alcove) => {
    if (!user?.id) return;
    const existing = rowBySlug.get(alcove.id);
    const existingMarks = Number(existing?.marks_awarded ?? 0);
    const nextMarks = Math.max(existingMarks, ALCOVE_REWARDS.visit);
    await supabase.from("alcove_progress" as never).upsert(
      {
        user_id: user.id,
        stop_slug: alcove.id,
        tier: alcove.tier,
        visited_at: existing?.visited_at ?? new Date().toISOString(),
        marks_awarded: nextMarks,
      } as never,
      { onConflict: "user_id,stop_slug" },
    );
    await refresh();
  };

  const markComprehended = async (alcove: Alcove) => {
    if (!user?.id) return;
    const existing = rowBySlug.get(alcove.id);
    const visitReward = ALCOVE_REWARDS.visit;
    const questionRewards = alcove.questions.reduce((sum, q) => sum + q.reward, 0);
    const maxReward = visitReward + questionRewards;
    const existingMarks = Number(existing?.marks_awarded ?? 0);
    await supabase.from("alcove_progress" as never).upsert(
      {
        user_id: user.id,
        stop_slug: alcove.id,
        tier: alcove.tier,
        visited_at: existing?.visited_at ?? new Date().toISOString(),
        comprehended_at: new Date().toISOString(),
        marks_awarded: Math.max(existingMarks, maxReward),
      } as never,
      { onConflict: "user_id,stop_slug" },
    );
    await refresh();
  };

  return {
    isLoading,
    stops,
    completedCount,
    currentTier,
    totalMarks,
    patternKeys,
    foundersForgeUnlocked: completedCount === 18,
    markVisited,
    markComprehended,

/**
 * useAuthGateContext — Reads context message set by a gated route.
 * ================================================================
 * ProtectedRoute / CaptainRoute may set sessionStorage[AUTH_GATE_CONTEXT_KEY]
 * when redirecting an unauthenticated member to /auth. The Auth page uses
 * this hook to retrieve that context and pass it to <MascotAuthGate />,
 * so the mascot explanation bubble can say:
 *
 *   "To {gateContext}, you'll need to sign in so we know it's you."
 *
 * The value is cleared after read so stale contexts don't bleed between
 * unrelated auth prompts.
 *
 * Introduced B080.
 */

import { useEffect, useState } from 'react';
import { AUTH_GATE_CONTEXT_KEY } from '@/components/ProtectedRoute';

export function useAuthGateContext(): string | undefined {
  const [context, setContext] = useState<string | undefined>(undefined);

  useEffect(() => {
    const stored = sessionStorage.getItem(AUTH_GATE_CONTEXT_KEY);
    if (stored) {
      setContext(stored);
      sessionStorage.removeItem(AUTH_GATE_CONTEXT_KEY);
    }
  }, []);

  return context;
}

import { useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

interface BackProjectInput {
  projectId: string;
  tier: string;
  creditsPaid: number;
  fulfillmentType: 'shipped' | 'print_yourself' | 'digital';
}

export function useBackProject() {
  const { user } = useAuth();
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: BackProjectInput) => {
      if (!user) throw new Error('Not authenticated');

      const { error: backErr } = await supabase
        .from('turnkey_backers' as never)
        .insert({
          project_id: input.projectId,
          user_id: user.id,
          tier: input.tier,
          credits_paid: input.creditsPaid,
          fulfillment_type: input.fulfillmentType,
          status: 'backed',
        } as never);

      if (backErr) throw backErr;

      const { data: proj } = await supabase
        .from('turnkey_projects' as never)
        .select('early_adopter_filled, community_matched')
        .eq('id', input.projectId)
        .single() as { data: { early_adopter_filled: number; community_matched: number } | null };

      if (proj) {
        await supabase
          .from('turnkey_projects' as never)
          .update({
            early_adopter_filled: proj.early_adopter_filled + 1,
            community_matched: proj.community_matched + input.creditsPaid,
          } as never)
          .eq('id', input.projectId);
      }

      return true;
    },

    onSuccess: (_data, vars) => {
      qc.invalidateQueries({ queryKey: ['turnkey-project'] });
      qc.invalidateQueries({ queryKey: ['turnkey-projects'] });
