function deadlineFromTier(tier: number): string {
  const now = new Date();
  const offsets: Record<number, number> = {
    1: 8 * 60 * 60 * 1000,
    2: 24 * 60 * 60 * 1000,
    3: 3 * 24 * 60 * 60 * 1000,
    4: 7 * 24 * 60 * 60 * 1000,
    5: 14 * 24 * 60 * 60 * 1000,
    6: 90 * 24 * 60 * 60 * 1000,
  };
  return new Date(now.getTime() + (offsets[tier] || offsets[6])).toISOString();
}

