}

export function usePledgeCampaign() {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async ({
      campaignId,
      creditAmount,
      pledgeType = "advance_order",
      note,
    }: {
      campaignId: string;
      creditAmount: number;
      pledgeType?: "advance_order" | "recurring" | "marks_seed";
      note?: string;
    }) => {
      if (!user) throw new Error("Must be logged in to pledge");

      const { data, error } = await supabase
        .from("campaign_pledges" as any)
        .upsert(
          {
            campaign_id: campaignId,
            user_id: user.id,
            pledge_type: pledgeType,
            credit_amount: creditAmount,
            note: note || null,
          },
          { onConflict: "campaign_id,user_id" }
        )
        .select()
        .single();

      if (error) throw error;

      // Update campaign aggregate counts
      const { data: agg } = await supabase
        .from("campaign_pledges" as any)
        .select("credit_amount")
        .eq("campaign_id", campaignId);

      const pledgeCount = agg?.length ?? 0;
      const pledgeTotal = (agg ?? []).reduce(
        (sum: number, p: any) => sum + Number(p.credit_amount),
        0
      );

      await supabase
        .from("business_campaigns" as any)
        .update({
          pledge_count: pledgeCount,
          pledge_total_credits: pledgeTotal,
          ...(pledgeCount >= 30 ? { status: "threshold_met" } : {}),
        })
        .eq("id", campaignId);

      return data as CampaignPledge;
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ["business-campaigns"] });
      queryClient.invalidateQueries({ queryKey: ["business-campaign"] });
      queryClient.invalidateQueries({ queryKey: ["campaign-pledges", vars.campaignId] });
    },
  });
}

export function useNominateBusiness() {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async (input: {
      businessName: string;
      businessType: string;
      businessCity: string;
      businessState?: string;
      businessAddress?: string;
      businessWebsite?: string;
      businessPhone?: string;
      nominationReason: string;
      proposedDiscountPct?: number;
      initialPledge?: number;
    }) => {
      if (!user) throw new Error("Must be logged in to nominate");

      const slug = input.businessName
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, "-")
        .replace(/(^-|-$)/g, "");

      const { data, error } = await supabase
        .from("business_campaigns" as any)
        .insert({
          business_name: input.businessName,
          business_type: input.businessType,
          business_city: input.businessCity,
          business_state: input.businessState || null,

          business_address: input.businessAddress || null,
          business_website: input.businessWebsite || null,
          business_phone: input.businessPhone || null,
          nominated_by: user.id,
          nomination_reason: input.nominationReason,
          slug,
          proposed_discount_pct: input.proposedDiscountPct ?? 10,
        })
        .select()
        .single();

      if (error) throw error;

      const campaign = data as BusinessCampaign;

      if (input.initialPledge && input.initialPledge > 0) {
        await supabase.from("campaign_pledges" as any).insert({
          campaign_id: campaign.id,
          user_id: user.id,
          pledge_type: "advance_order",
          credit_amount: input.initialPledge,
          note: "Nominator's seed pledge",
        });

        await supabase
          .from("business_campaigns" as any)
          .update({
            pledge_count: 1,
            pledge_total_credits: input.initialPledge,
          })
          .eq("id", campaign.id);
      }

      return campaign;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["business-campaigns"] });
    },
  });
}

export function useGeneratePitchPacket() {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async ({
      campaignId,
      campaign,
    }: {

      campaignId: string;
      campaign: BusinessCampaign;
    }) => {
      if (!user) throw new Error("Must be logged in");

      const avgOrder =
        campaign.pledge_count > 0
          ? campaign.pledge_total_credits / campaign.pledge_count
          : 0;

      const qrUrl = `${window.location.origin}/campaigns/${campaign.slug}`;

      const { data, error } = await supabase
        .from("pitch_packets" as any)
        .insert({
          campaign_id: campaignId,
          captain_id: user.id,
          pledge_count: campaign.pledge_count,
          total_pledged: campaign.pledge_total_credits,
          avg_order_value: Math.round(avgOrder * 100) / 100,
          proposed_discount: `${campaign.proposed_discount_pct}% volume discount`,
          qr_code_url: qrUrl,
        })
        .select()
        .single();

      if (error) throw error;
      return data as PitchPacket;
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ["pitch-packet", vars.campaignId] });
    },
  });
}

export function usePitchPacket(campaignId: string | undefined) {
  const { user } = useAuth();

  return useQuery({
    queryKey: ["pitch-packet", campaignId, user?.id],
    queryFn: async () => {
      if (!campaignId || !user) return null;
      const { data, error } = await supabase
        .from("pitch_packets" as any)
        .select("*")
        .eq("campaign_id", campaignId)
        .eq("captain_id", user.id)
        .order("generated_at", { ascending: false })
        .limit(1)
        .maybeSingle();

      if (error) throw error;
      return data as PitchPacket | null;
    },
    enabled: !!campaignId && !!user,
  });
}

export function useClaimCaptain() {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async ({ campaignId }: { campaignId: string }) => {
      if (!user) throw new Error("Must be logged in");

      const { data, error } = await supabase
        .from("business_campaigns" as any)
        .update({ captain_id: user.id })
        .eq("id", campaignId)
        .is("captain_id", null)
        .select()
        .single();

      if (error) throw error;
      return data as BusinessCampaign;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["business-campaigns"] });
      queryClient.invalidateQueries({ queryKey: ["business-campaign"] });
    },
  });
}

import { useQuery, useMutation } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface CreditPurchase {
  id: string;
  user_id: string;
  amount_credits: number;
  amount_usd: number;
  stripe_session_id: string | null;
  status: string;
  package_size: string | null;
  bonus_pct: number;
  created_at: string;
}

export function useCreditBalance() {
  const { user } = useAuth();
  return useQuery({
    queryKey: ["credit-balance", user?.id],
    queryFn: async () => {
      if (!user) return 0;
      const { data, error } = await supabase
        .from("transaction_ledger" as any)
        .select("amount")
        .eq("user_id", user.id)
        .in("ledger_category", [
          "project_funder_credit",
          "commerce_creator",
          "project_funding",
        ]);
      if (error) return 0;
      const total = (data ?? []).reduce(
        (sum: number, r: { amount: number }) => sum + (r.amount ?? 0),
        0
      );
      return Math.max(0, total);
    },
    enabled: !!user,
  });
}

export function usePurchaseHistory() {
  const { user } = useAuth();
  return useQuery({
    queryKey: ["credit-purchases", user?.id],
    queryFn: async () => {
      if (!user) return [];
      const { data, error } = await supabase
        .from("credit_purchases" as any)

        .select("*")
        .eq("user_id", user.id)
        .order("created_at", { ascending: false })
        .limit(25);
      if (error) throw error;
      return (data ?? []) as CreditPurchase[];
    },
    enabled: !!user,
  });
}

export function useBuyCredits() {
  return useMutation({
    mutationFn: async (packageSize: string) => {
      const { data, error } = await supabase.functions.invoke(
        "create-credit-checkout",
        { body: { package_size: packageSize } }
      );
      if (error) throw error;
      const body = data as { url?: string; error?: string };
      if (body.error) throw new Error(body.error);
      if (body.url) {
        window.location.href = body.url;
      }
      return body;
    },
  });
}

/**
 * useCalendarSources — Calendar Plug Interface (K115 D3 / Innovation #1868)
 *
 * Typed source registration system. Each CalendarSourceType attaches via a
 * standard interface. The hook queries relevant tables based on user roles
 * and returns unified CalendarPlugEvent objects for FullCalendar rendering.
 */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

// ─── Source Type Enum ──────────────────────────────────────────────────────
export type CalendarSourceType =
  | 'storefront'
  | 'coalition'
  | 'platform'
  | 'route'
  | 'crew';

// ─── Standard Event Schema ─────────────────────────────────────────────────
export interface CalendarPlugEvent {
  id: string;
  title: string;
  start: string;
  end: string | null;
  sourceType: CalendarSourceType;
  sourceId: string;
  metadata: Record<string, unknown>;
}

// ─── Source Descriptor ─────────────────────────────────────────────────────
export interface CalendarSourceDescriptor {
  type: CalendarSourceType;
  label: string;
  emoji: string;
  color: string;
  description: string;
  editable: boolean;
  /** Roles that see this source enabled by default */
  defaultForRoles: string[];
}

export const CALENDAR_SOURCE_REGISTRY: CalendarSourceDescriptor[] = [
  {
    type: 'storefront',
    label: 'Storefront',
    emoji: '🏪',
    color: '#f97316',

    description: 'Order cutoffs, flash sales, business hours',
    editable: true,
    defaultForRoles: ['storefront_owner', 'provider'],
  },
  {
    type: 'coalition',
    label: 'Coalition',
    emoji: '🤝',
    color: '#14b8a6',
    description: 'Coalition meetings, group buys, joint promotions',
    editable: true,
    defaultForRoles: ['member', 'builder'],
  },
  {
    type: 'platform',
    label: 'Platform',
    emoji: '📢',
    color: '#6366f1',
    description: 'Launches, maintenance windows, community events',
    editable: false,
    defaultForRoles: ['all'],
  },
  {
    type: 'route',
    label: 'Route',
    emoji: '🚗',
    color: '#eab308',
    description: 'Delivery windows, pickup times, route schedules',
    editable: true,
    defaultForRoles: ['runner', 'provider'],
  },
