import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import type { BusinessCampaign } from "@/hooks/useBusinessCampaigns";

export type PipelineStage =
  | "early"
  | "rallying"
  | "ready_to_pitch"
  | "pitched"
  | "accepted"
  | "declined"
  | "onboarded";

export interface PipelineCampaign extends BusinessCampaign {
  stage: PipelineStage;
}

function deriveStage(c: BusinessCampaign): PipelineStage {
  if (c.status === "accepted" || c.status === "onboarded") return "onboarded";
  if (c.status === "declined") return "declined";
  if (c.status === "pitched") {
    if (c.accepted_at) return "onboarded";
    return "pitched";
  }
  if (c.pitched_at) return "pitched";

  const threshold = c.pledge_threshold || 30;
  const ratio = c.pledge_count / threshold;
  if (ratio >= 1) return "ready_to_pitch";
  if (ratio >= 0.33) return "rallying";
  return "early";
}

export function useCaptainPipeline() {
  const { user } = useAuth();

  return useQuery({
    queryKey: ["captain-pipeline", user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("business_campaigns" as any)
        .select("*")
        .eq("captain_id", user!.id)
        .order("created_at", { ascending: false });

      if (error) throw error;

      const campaigns = (data ?? []) as BusinessCampaign[];
      return campaigns.map((c): PipelineCampaign => ({

        ...c,
        stage: deriveStage(c),
      }));
    },
    enabled: !!user,
  });
}

const STAGE_ORDER: Record<PipelineStage, number> = {
  ready_to_pitch: 0,
  rallying: 1,
  early: 2,
  pitched: 3,
  onboarded: 4,
  accepted: 5,
  declined: 6,
};

export function groupByStage(campaigns: PipelineCampaign[]) {
  const active = campaigns.filter(
    (c) => c.stage === "early" || c.stage === "rallying" || c.stage === "ready_to_pitch"
  );
  active.sort((a, b) => STAGE_ORDER[a.stage] - STAGE_ORDER[b.stage]);

  const pitched = campaigns.filter((c) => c.stage === "pitched");
  const onboarded = campaigns.filter((c) => c.stage === "onboarded");
  const declined = campaigns.filter((c) => c.stage === "declined");

  return { active, pitched, onboarded, declined };
}

import { useState, useCallback, useRef, useEffect } from 'react';

// MISS-010 — Cascading Hexagonal Containers (#16)
// Water cascades between nested hex containers at different elevations.
// Each container overflows into the next level when threshold reached.
// Gravity-driven cascade chain.

export type CascadeLevel = 0 | 1 | 2 | 3 | 4;

export interface HexContainer {
  level: CascadeLevel;
  elevationCm: number;
  capacityL: number;       // liters
  currentL: number;        // current fill
  overflowThreshold: number; // fraction 0–1
  isOverflowing: boolean;
  overflowRate: number;    // L per tick
}

export interface CascadeState {
  containers: HexContainer[];
  activeCascades: number;  // how many containers currently overflowing
  totalVolumeProcessed: number; // cumulative liters moved
  gameTurn: number;
  tickCount: number;
  isRunning: boolean;
  tickMs: number;
  fillRate: number;        // liters per tick added to top container
}

export interface CascadeControls {
  start: () => void;
  pause: () => void;
  reset: () => void;
  tick: () => void;
  setFillRate: (rate: number) => void;
  setTickMs: (ms: number) => void;
}

function buildContainers(): HexContainer[] {
  return [
    { level: 0, elevationCm: 100, capacityL: 2.0,  currentL: 0, overflowThreshold: 0.9, isOverflowing: false, overflowRate: 0 },
    { level: 1, elevationCm: 75,  capacityL: 3.5,  currentL: 0, overflowThreshold: 0.9, isOverflowing: false, overflowRate: 0 },
    { level: 2, elevationCm: 50,  capacityL: 5.0,  currentL: 0, overflowThreshold: 0.9, isOverflowing: false, overflowRate: 0 },
    { level: 3, elevationCm: 25,  capacityL: 7.0,  currentL: 0, overflowThreshold: 0.9, isOverflowing: false, overflowRate: 0 },
    { level: 4, elevationCm: 0,   capacityL: 10.0, currentL: 0, overflowThreshold: 1.0, isOverflowing: false, overflowRate: 0 },
  ];
}

export function useCascadingHexagonalContainers(initialTickMs = 600): {

  state: CascadeState;
  controls: CascadeControls;
} {
  const [state, setState] = useState<CascadeState>({
    containers: buildContainers(),
    activeCascades: 0,
    totalVolumeProcessed: 0,
    gameTurn: 0,
    tickCount: 0,
    isRunning: false,
    tickMs: initialTickMs,
    fillRate: 0.3, // L per tick
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const tick = useCallback(() => {
    setState(prev => {
      const containers = prev.containers.map(c => ({ ...c }));
      let totalProcessed = prev.totalVolumeProcessed;

      // Add water to top container
      containers[0].currentL = Math.min(containers[0].currentL + prev.fillRate, containers[0].capacityL);

      // Cascade downward
      for (let i = 0; i < containers.length - 1; i++) {
        const c = containers[i];
        const fillFraction = c.currentL / c.capacityL;
        if (fillFraction >= c.overflowThreshold) {
          const overflow = c.currentL - c.capacityL * c.overflowThreshold;
          const rate = Math.min(overflow, 0.5); // max 0.5L overflow per tick
          c.currentL -= rate;
          containers[i + 1].currentL = Math.min(containers[i + 1].currentL + rate, containers[i + 1].capacityL);
          c.isOverflowing = true;
          c.overflowRate = rate;
          totalProcessed += rate;
        } else {
          c.isOverflowing = false;
          c.overflowRate = 0;
        }
      }

      const activeCascades = containers.filter(c => c.isOverflowing).length;
      const tickCount = prev.tickCount + 1;
      const gameTurn = Math.floor(tickCount / 12);

      return { ...prev, containers, activeCascades, totalVolumeProcessed: parseFloat(totalProcessed.toFixed(2)), tickCount, gameTurn };
    });
  }, []);

  const start = useCallback(() => setState(prev => ({ ...prev, isRunning: true })), []);
  const pause = useCallback(() => setState(prev => ({ ...prev, isRunning: false })), []);

  const reset = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    setState(prev => ({
      ...prev,
      containers: buildContainers(),
      activeCascades: 0,
      totalVolumeProcessed: 0,
      gameTurn: 0,
      tickCount: 0,
      isRunning: false,
    }));
  }, []);

  const setFillRate = useCallback((rate: number) => {
    setState(prev => ({ ...prev, fillRate: rate }));
  }, []);

  const setTickMs = useCallback((ms: number) => {
    setState(prev => ({ ...prev, tickMs: ms }));
  }, []);

  useEffect(() => {
    if (state.isRunning) {
      intervalRef.current = setInterval(tick, state.tickMs);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [state.isRunning, state.tickMs, tick]);

  return { state, controls: { start, pause, reset, tick, setFillRate, setTickMs } };
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

/* ───── types ───── */

export type ResourceType =
  | "tutorial" | "tool" | "example" | "documentation"
  | "video" | "podcast" | "book" | "other";

export type ResourceStatus = "pending" | "community" | "recommended" | "featured" | "hidden";

export interface CephasResource {
  id: string;
  article_slug: string;
  submitted_by: string;
  url: string;
  title: string;
  description: string | null;
  resource_type: ResourceType | null;
  upvotes: number;
  downvotes: number;
  flags: number;
  status: ResourceStatus;
  marks_earned: number;
  created_at: string;
  my_vote?: number | null;
}

export type VoteValue = -1 | 0 | 1;

export interface KnowledgeEdge {
  id: string;
  source_type: string;
  source_id: string;
  target_type: string;
  target_id: string;
  edge_type: string;
  auto_generated: boolean;
  created_at: string;
}

/* ───── helpers ───── */

function statusForCounts(up: number, flags: number): ResourceStatus {
  if (up >= 25 && flags === 0) return "featured";
  if (up >= 10) return "recommended";
  if (up >= 3) return "community";
  return "pending";
}

/* ───── resource hooks ───── */

export function useResourceLinks(articleSlug: string | undefined) {
  const { user } = useAuth();
  return useQuery({
    queryKey: ["cephas-resources", articleSlug],
    enabled: !!articleSlug,
    queryFn: async () => {
      const { data: resources, error } = await supabase
        .from("cephas_resource_links" as any)
        .select("*")
        .eq("article_slug", articleSlug!)
        .in("status", ["community", "recommended", "featured"])
        .order("upvotes", { ascending: false });
      if (error) throw error;

      let myVotes: Record<string, number> = {};
      if (user) {
        const ids = (resources as any[]).map((r: any) => r.id);
        if (ids.length) {
          const { data: votes } = await supabase
            .from("cephas_resource_votes" as any)
            .select("resource_id, vote")
            .eq("voter_id", user.id)
            .in("resource_id", ids);
          for (const v of (votes ?? []) as any[]) {
            myVotes[v.resource_id] = v.vote;
          }
        }
      }

      return (resources as any[]).map((r: any) => ({
        ...r,
        my_vote: myVotes[r.id] ?? null,
      })) as CephasResource[];
    },
  });
}

export function useSubmitResource() {
  const qc = useQueryClient();
  const { user } = useAuth();
  return useMutation({
    mutationFn: async (input: {
      article_slug: string;
      url: string;
      title: string;
      description?: string;
      resource_type?: ResourceType;

    }) => {
      if (!user) throw new Error("Must be signed in");
      const { data, error } = await supabase
        .from("cephas_resource_links" as any)
        .insert({
          article_slug: input.article_slug,
          submitted_by: user.id,
          url: input.url,
          title: input.title,
          description: input.description ?? null,
          resource_type: input.resource_type ?? "other",
        } as any)
        .select()
        .single();
      if (error) throw error;
      return data;
    },
    onSuccess: (_d, vars) => {
      qc.invalidateQueries({ queryKey: ["cephas-resources", vars.article_slug] });
    },
  });
}

export function useVoteOnResource() {
  const qc = useQueryClient();
  const { user } = useAuth();
  return useMutation({
    mutationFn: async (input: { resourceId: string; articleSlug: string; vote: VoteValue }) => {
      if (!user) throw new Error("Must be signed in");

      const { data: existing } = await supabase
        .from("cephas_resource_votes" as any)
        .select("id, vote")
        .eq("resource_id", input.resourceId)
        .eq("voter_id", user.id)
        .maybeSingle();

      if (existing) {
        const { error } = await supabase
          .from("cephas_resource_votes" as any)
          .update({ vote: input.vote } as any)
          .eq("id", (existing as any).id);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from("cephas_resource_votes" as any)
          .insert({
            resource_id: input.resourceId,
            voter_id: user.id,
            vote: input.vote,

          } as any);
        if (error) throw error;
      }

      const oldVote = existing ? (existing as any).vote as number : 0;
      const upDelta = (input.vote === 1 ? 1 : 0) - (oldVote === 1 ? 1 : 0);
      const downDelta = (input.vote === -1 ? 1 : 0) - (oldVote === -1 ? 1 : 0);
      const flagDelta = (input.vote === 0 ? 1 : 0) - (oldVote === 0 ? 1 : 0);

      const { data: resource } = await supabase
        .from("cephas_resource_links" as any)
        .select("upvotes, downvotes, flags")
        .eq("id", input.resourceId)
        .single();

      if (resource) {
        const r = resource as any;
        const newUp = (r.upvotes ?? 0) + upDelta;
        const newDown = (r.downvotes ?? 0) + downDelta;
        const newFlags = (r.flags ?? 0) + flagDelta;
        const newStatus = newFlags >= 3 ? "hidden" : statusForCounts(newUp, newFlags);
        await supabase
          .from("cephas_resource_links" as any)
          .update({
            upvotes: newUp,
            downvotes: newDown,
            flags: newFlags,
            status: newStatus,
          } as any)
          .eq("id", input.resourceId);
      }
    },
    onSuccess: (_d, vars) => {
      qc.invalidateQueries({ queryKey: ["cephas-resources", vars.articleSlug] });
    },
  });
}

