  const getCampaign = (slug: string) =>
    campaignsQuery.data?.find((c) => c.slug === slug) ?? null;

  return {
    campaigns: campaignsQuery.data ?? [],
    getCampaign,
    isLoading: campaignsQuery.isLoading,
  };
}

