export type CodexBindStatus = "verified" | "tampered" | "missing" | "pending" | "bound";

export interface CodexBindResult {
  codexId: string;
  status: CodexBindStatus;
  storedHmac?: string;
  computedHmac?: string;
  edition?: string;
  title?: string;
  chapters?: number;
  message?: string;
