      codex_id: codexId,
      content_payload: contentPayload,
    },
    headers: { Authorization: `Bearer ${session.access_token}` },
  });

  if (response.error) throw response.error;

  const data = response.data as {
    codex_id: string;
    status: CodexBindStatus;
    stored_hmac?: string;
    computed_hmac?: string;
    edition?: string;
    title?: string;
    chapters?: number;
    message?: string;
    ts: string;
