  return {
    codexId: data.codex_id,
    status: data.status,
    storedHmac: data.stored_hmac,
    computedHmac: data.computed_hmac,
    edition: data.edition,

    title: data.title,
    chapters: data.chapters,
    message: data.message,
    ts: data.ts,
  };
