}

export function useContests(portal?: string) {
  return useQuery({
    queryKey: ["contests", portal],
    queryFn: async () => {
      let q = supabase
        .from("platform_contests" as any)
        .select("*")
        .order("submission_start", { ascending: true });

      if (portal && portal !== "all") {
        q = q.eq("portal", portal);
      }

      const { data, error } = await q;
      if (error) throw error;
      return (data ?? []) as Contest[];
    },
  });
}

export function useContest(slug: string | undefined) {
  return useQuery({
    queryKey: ["contest", slug],
    queryFn: async () => {
      if (!slug) return null;
      const { data, error } = await supabase
        .from("platform_contests" as any)
        .select("*")
        .eq("slug", slug)
        .single();
      if (error) throw error;
      return data as Contest;
    },
    enabled: !!slug,
  });
}

export function useContestEntries(contestId: string | undefined) {
  return useQuery({
    queryKey: ["contest-entries", contestId],
    queryFn: async () => {
      if (!contestId) return [];
      const { data, error } = await supabase
        .from("contest_entries" as any)
        .select("*, project:turnkey_projects(id, title, slug, description, images, creator_id, status)")
        .eq("contest_id", contestId)

        .order("vote_count", { ascending: false });
      if (error) throw error;
      return (data ?? []) as ContestEntry[];
    },
    enabled: !!contestId,
  });
}

export function useUserContestVotes(contestId: string | undefined) {
  const { user } = useAuth();
  return useQuery({
    queryKey: ["contest-user-votes", contestId, user?.id],
    queryFn: async () => {
      if (!contestId || !user) return [];
      const { data, error } = await supabase
        .from("contest_votes" as any)
        .select("*")
        .eq("contest_id", contestId)
        .eq("user_id", user.id);
      if (error) throw error;
      return (data ?? []) as ContestVote[];
    },
    enabled: !!contestId && !!user,
  });
}

export function useVoteEntry() {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async ({
      contestId,
      entryId,
      voteType = "want",
      creditsPledged = 0,
    }: {
      contestId: string;
      entryId: string;
      voteType?: "want" | "pledge";
      creditsPledged?: number;
    }) => {
      if (!user) throw new Error("Must be logged in to vote");

      const { data, error } = await supabase
        .from("contest_votes" as any)
        .upsert(
          {
            contest_id: contestId,
            entry_id: entryId,

            user_id: user.id,
            vote_type: voteType,
            credits_pledged: creditsPledged,
          },
          { onConflict: "contest_id,entry_id,user_id" }
        )
        .select()
        .single();

      if (error) throw error;

      // Increment vote_count on the entry
      await supabase.rpc("increment_contest_vote" as any, {
        _entry_id: entryId,
        _pledge_amount: creditsPledged,
      });

      return data;
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ["contest-entries", vars.contestId] });
      queryClient.invalidateQueries({ queryKey: ["contest-user-votes", vars.contestId] });
    },
  });
}

export function useSubmitEntry() {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async ({
      contestId,
      projectId,
      entryStatement,
    }: {
      contestId: string;
      projectId: string;
      entryStatement?: string;
    }) => {
      if (!user) throw new Error("Must be logged in to enter a contest");

      const { data, error } = await supabase
        .from("contest_entries" as any)
        .insert({
          contest_id: contestId,
          project_id: projectId,
          user_id: user.id,
          entry_statement: entryStatement || null,
        })

        .select()
        .single();

      if (error) throw error;
      return data as ContestEntry;
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ["contest-entries", vars.contestId] });
    },
  });
}

export function getContestPhase(contest: Contest): "upcoming" | "submissions" | "voting" | "judging" | "complete" {
  const now = new Date();
  const subStart = new Date(contest.submission_start);
  const subEnd = new Date(contest.submission_end);
  const voteStart = new Date(contest.voting_start);
  const voteEnd = new Date(contest.voting_end);

  if (contest.status === "complete") return "complete";
  if (now < subStart) return "upcoming";
  if (now >= subStart && now < subEnd) return "submissions";
  if (now >= voteStart && now < voteEnd) return "voting";
  return "judging";
}

import { useState, useCallback, useRef, useEffect } from 'react';

// MISS-011 — Continuous Fluid Loop (#17)
// Water recirculates without external pumps.
// Uses height differential + Sawtooth60 directional flow + Golden Lotus timing
// to create a perpetual loop. Flow rate tracks with game turn.

export type LoopSegment = 'reservoir' | 'descent' | 'sawtooth' | 'golden_lotus' | 'ascent';

export interface FluidSegmentState {
  segment: LoopSegment;
  label: string;
  flowRateL: number;      // liters per minute
  pressureBar: number;
  waterLevel: number;     // 0–1 fill fraction
  isBottleneck: boolean;
}

export interface ContinuousFluidLoopState {
  segments: FluidSegmentState[];
  loopFlowRate: number;         // overall loop L/min
  heightDifferentialCm: number; // driving head
  lotusPhaseAngle: number;      // Golden Lotus angle (0–360)
  sawtoothPosition: number;     // 0–60 tooth position
  totalLoopCompletions: number;
  gameTurn: number;
  tickCount: number;
  isRunning: boolean;
  tickMs: number;
  efficiency: number;           // 0–1, loop efficiency
}

export interface FluidLoopControls {
  start: () => void;
  pause: () => void;
  reset: () => void;
  tick: () => void;
  setTickMs: (ms: number) => void;
}

function buildSegments(): FluidSegmentState[] {
  return [
    { segment: 'reservoir',    label: 'Reservoir',      flowRateL: 0, pressureBar: 0, waterLevel: 0.85, isBottleneck: false },
    { segment: 'descent',      label: 'Gravity Descent', flowRateL: 0, pressureBar: 0, waterLevel: 0.5,  isBottleneck: false },
    { segment: 'sawtooth',     label: 'Sawtooth60',      flowRateL: 0, pressureBar: 0, waterLevel: 0.3,  isBottleneck: false },
    { segment: 'golden_lotus', label: 'Golden Lotus',    flowRateL: 0, pressureBar: 0, waterLevel: 0.4,  isBottleneck: false },
    { segment: 'ascent',       label: 'Return Ascent',   flowRateL: 0, pressureBar: 0, waterLevel: 0.2,  isBottleneck: false },
  ];
}

export function useContinuousFluidLoop(initialTickMs = 650): {
  state: ContinuousFluidLoopState;
  controls: FluidLoopControls;
} {
  const [state, setState] = useState<ContinuousFluidLoopState>({
    segments: buildSegments(),
    loopFlowRate: 0,
    heightDifferentialCm: 91.44, // 3-foot head in cm
    lotusPhaseAngle: 0,
    sawtoothPosition: 0,
    totalLoopCompletions: 0,
    gameTurn: 0,
    tickCount: 0,
    isRunning: false,
    tickMs: initialTickMs,
    efficiency: 0.87,
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const tick = useCallback(() => {
    setState(prev => {
      const tickCount = prev.tickCount + 1;
      const gameTurn = Math.floor(tickCount / 12);

      const lotusPhaseAngle = (prev.lotusPhaseAngle + 30) % 360;
      const sawtoothPosition = (prev.sawtoothPosition + 1) % 60;

      // Gravity-driven flow from height differential
      const gravityFlow = (prev.heightDifferentialCm / 100) * 1.2; // L/min
      // Sawtooth adds directional boost (peaks every 5 teeth)
      const sawtoothBoost = sawtoothPosition % 5 === 0 ? 0.3 : 0.1;
      // Golden Lotus converts flow to rotation — phase amplifies or damps
      const lotusAmplitude = 0.8 + 0.2 * Math.sin((lotusPhaseAngle * Math.PI) / 180);
      const loopFlowRate = parseFloat((gravityFlow * lotusAmplitude * prev.efficiency + sawtoothBoost).toFixed(3));

      const segments: FluidSegmentState[] = prev.segments.map((s, i) => {
        const phaseOffset = (i * 72); // 5 segments, 360/5 = 72°
        const phaseFlow = loopFlowRate * (0.7 + 0.3 * Math.sin(((lotusPhaseAngle + phaseOffset) * Math.PI) / 180));
        const pressure = parseFloat(((prev.heightDifferentialCm - i * 15) / 100 * 0.094).toFixed(4)); // PSI→bar per segment
        const wl = Math.max(0.05, Math.min(0.95, s.waterLevel + (i === 0 ? -0.02 : i === 4 ? 0.02 : 0)));
        return {
          ...s,
          flowRateL: parseFloat(Math.max(0, phaseFlow).toFixed(3)),
          pressureBar: Math.max(0, pressure),
          waterLevel: wl,
          isBottleneck: phaseFlow < loopFlowRate * 0.5,
        };
      });

      const completions = sawtoothPosition === 0 ? prev.totalLoopCompletions + 1 : prev.totalLoopCompletions;

      return { ...prev, segments, loopFlowRate, lotusPhaseAngle, sawtoothPosition, totalLoopCompletions: completions, gameTurn, tickCount };
    });
  }, []);

  const start = useCallback(() => setState(prev => ({ ...prev, isRunning: true })), []);
  const pause = useCallback(() => setState(prev => ({ ...prev, isRunning: false })), []);

  const reset = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    setState(prev => ({
      ...prev,
      segments: buildSegments(),
      loopFlowRate: 0,
      lotusPhaseAngle: 0,
      sawtoothPosition: 0,
      totalLoopCompletions: 0,
      gameTurn: 0,
      tickCount: 0,
      isRunning: false,
    }));
  }, []);

  const setTickMs = useCallback((ms: number) => setState(prev => ({ ...prev, tickMs: ms })), []);

  useEffect(() => {
    if (state.isRunning) {
      intervalRef.current = setInterval(tick, state.tickMs);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [state.isRunning, state.tickMs, tick]);

  return { state, controls: { start, pause, reset, tick, setTickMs } };
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface CooperativePurchase {
  id: string;
  tip_id: string | null;
  initiator_id: string;
  title: string;
  description: string | null;
  store_name: string | null;
  store_location: string | null;
  unit_price_retail: number | null;
  unit_price_cooperative: number | null;
  savings_percentage: number | null;
  target_quantity: number;
  threshold_quantity: number;
  current_quantity: number;
  status: string;
  participants: Participant[];
  expires_at: string;
  created_at: string;
  updated_at: string;
}

export interface Participant {
  member_id: string;
  quantity: number;
  joined_at: string;
}

interface StartGroupBuyOptions {
  tipId?: string;
  title: string;
  description?: string;
  storeName?: string;
  storeLocation?: string;
  unitPriceRetail?: number;
  unitPriceCooperative?: number;
  targetQuantity: number;
  thresholdQuantity?: number;
  expiresInHours?: number;
}

export function useCooperativePurchasing(filters?: { tipId?: string; status?: string[] }) {
  const { user } = useAuth();
  const qc = useQueryClient();

  const { data: groupBuys, isLoading } = useQuery({
    queryKey: ["cooperative-purchases", filters],

    queryFn: async () => {
      let query = supabase
        .from("cooperative_purchases" as never)
        .select("*")
        .order("created_at", { ascending: false });

      if (filters?.tipId) {
        query = query.eq("tip_id", filters.tipId);
      }
      if (filters?.status?.length) {
        query = query.in("status", filters.status);
      }

      const { data, error } = await query;
      if (error) return [];
      return (data ?? []) as CooperativePurchase[];
    },
  });

  const startGroupBuy = useMutation({
    mutationFn: async (opts: StartGroupBuyOptions) => {
      if (!user) throw new Error("Sign in to start a group buy");
      const expiresAt = new Date();
      expiresAt.setHours(expiresAt.getHours() + (opts.expiresInHours ?? 72));

      const { data, error } = await supabase
        .from("cooperative_purchases" as never)
        .insert({
          tip_id: opts.tipId ?? null,
          initiator_id: user.id,
          title: opts.title,
          description: opts.description ?? null,
          store_name: opts.storeName ?? null,
          store_location: opts.storeLocation ?? null,
          unit_price_retail: opts.unitPriceRetail ?? null,
          unit_price_cooperative: opts.unitPriceCooperative ?? null,
          target_quantity: opts.targetQuantity,
          threshold_quantity: opts.thresholdQuantity ?? 5,
          current_quantity: 0,
          participants: [],
          expires_at: expiresAt.toISOString(),
        } as never)
        .select()
        .single();
      if (error) throw error;
      return data as CooperativePurchase;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["cooperative-purchases"] });
    },

  });

  const joinGroupBuy = useMutation({
    mutationFn: async ({ purchaseId, quantity }: { purchaseId: string; quantity: number }) => {
      if (!user) throw new Error("Sign in to join");

      const { data: current, error: fetchErr } = await supabase
        .from("cooperative_purchases" as never)
        .select("participants, current_quantity, status")
        .eq("id", purchaseId)
        .single();
      if (fetchErr) throw fetchErr;
      const row = current as CooperativePurchase;
      if (row.status !== "gathering" && row.status !== "threshold_met")
        throw new Error("This group buy is no longer accepting members");

      const participants = (row.participants ?? []) as Participant[];
      const existing = participants.find((p) => p.member_id === user.id);
      let updatedParticipants: Participant[];
      let qtyDelta: number;

      if (existing) {
        qtyDelta = quantity - existing.quantity;
        updatedParticipants = participants.map((p) =>
          p.member_id === user.id ? { ...p, quantity } : p
        );
      } else {
        qtyDelta = quantity;
        updatedParticipants = [
          ...participants,
          { member_id: user.id, quantity, joined_at: new Date().toISOString() },
        ];
      }

      const newQty = (row.current_quantity ?? 0) + qtyDelta;
      const thresholdMet = newQty >= (row as unknown as CooperativePurchase).threshold_quantity;

      const { error: updateErr } = await supabase
        .from("cooperative_purchases" as never)
        .update({
          participants: updatedParticipants,
          current_quantity: newQty,
          ...(thresholdMet && row.status === "gathering" ? { status: "threshold_met" } : {}),
          updated_at: new Date().toISOString(),
        } as never)
        .eq("id", purchaseId);
      if (updateErr) throw updateErr;

      return { newQty, thresholdMet };
    },

    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["cooperative-purchases"] });
    },
  });

  const leaveGroupBuy = useMutation({
    mutationFn: async (purchaseId: string) => {
      if (!user) throw new Error("Sign in");

      const { data: current, error: fetchErr } = await supabase
        .from("cooperative_purchases" as never)
        .select("participants, current_quantity, threshold_quantity")
        .eq("id", purchaseId)
        .single();
      if (fetchErr) throw fetchErr;
      const row = current as CooperativePurchase;

      const participants = (row.participants ?? []) as Participant[];
      const me = participants.find((p) => p.member_id === user.id);
      if (!me) return;

      const updatedParticipants = participants.filter((p) => p.member_id !== user.id);
      const newQty = Math.max(0, (row.current_quantity ?? 0) - me.quantity);
      const backToGathering = newQty < row.threshold_quantity;

      const { error } = await supabase
        .from("cooperative_purchases" as never)
        .update({
          participants: updatedParticipants,
          current_quantity: newQty,
          ...(backToGathering ? { status: "gathering" } : {}),
          updated_at: new Date().toISOString(),
        } as never)
        .eq("id", purchaseId);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["cooperative-purchases"] });
    },
  });

  const getActiveGroupBuys = useQuery({
    queryKey: ["cooperative-purchases-active"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("cooperative_purchases" as never)
        .select("*")
        .in("status", ["gathering", "threshold_met"])
        .gt("expires_at", new Date().toISOString())
        .order("created_at", { ascending: false });

      if (error) return [];
      return (data ?? []) as CooperativePurchase[];
    },
  });

  const getGroupBuyForTip = (tipId: string) => {
    return (groupBuys ?? []).find(
      (gb) => gb.tip_id === tipId && (gb.status === "gathering" || gb.status === "threshold_met")
    );
  };

  const myParticipation = (purchase: CooperativePurchase) => {
    if (!user) return null;
    return (purchase.participants ?? []).find((p) => p.member_id === user.id) ?? null;
  };

  return {
    groupBuys: groupBuys ?? [],
    activeGroupBuys: getActiveGroupBuys.data ?? [],
    isLoading,
    startGroupBuy,
    joinGroupBuy,
    leaveGroupBuy,
    getGroupBuyForTip,
    myParticipation,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface TreasureMapStep {
  order: number;
  title: string;
  description: string;
  link: string;
  time_estimate: string;
  cost_estimate: string;
}

export interface CraftTreasureMap {
  id: string;
  craft_type: string;
  title: string;
  slug: string;
  tagline: string;
  description: string | null;
  icon: string;
  steps: TreasureMapStep[];
  cue_card_slug: string | null;
  recommended_products: { title: string; slug: string }[];
  startup_cost_low: number | null;
  startup_cost_high: number | null;
  first_sale_timeline: string | null;
  projected_monthly_low: number | null;
  projected_monthly_high: number | null;
  difficulty: 'beginner' | 'intermediate' | 'advanced';
  time_commitment: string | null;
  created_at: string;
  updated_at: string;
}

export interface CraftTreasureMapProgress {
  id: string;
  user_id: string;
  treasure_map_id: string;
  current_step: number;
  completed_steps: number[];
  started_at: string;
  last_activity: string;
}

export function useCraftTreasureMaps() {
  return useQuery({
    queryKey: ['craft-treasure-maps'],
    queryFn: async () => {
      const { data, error } = await supabase

        .from('craft_treasure_maps' as never)
        .select('*')
        .order('craft_type', { ascending: true }) as { data: CraftTreasureMap[] | null; error: unknown };
      if (error) throw error;
      return (data || []) as CraftTreasureMap[];
    },
    staleTime: 10 * 60 * 1000,
  });
}

export function useCraftTreasureMap(slug: string | undefined) {
  const { user } = useAuth();

  const mapQuery = useQuery({
    queryKey: ['craft-treasure-map', slug],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('craft_treasure_maps' as never)
        .select('*')
        .eq('slug', slug!)
        .single() as { data: CraftTreasureMap | null; error: unknown };
      if (error) throw error;
      return data as CraftTreasureMap;
    },
    enabled: !!slug,
    staleTime: 10 * 60 * 1000,
  });

  const progressQuery = useQuery({
    queryKey: ['craft-treasure-map-progress', mapQuery.data?.id, user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('craft_treasure_map_progress' as never)
        .select('*')
        .eq('user_id', user!.id)
        .eq('treasure_map_id', mapQuery.data!.id)
        .maybeSingle() as { data: CraftTreasureMapProgress | null; error: unknown };
      if (error) throw error;
      return data as CraftTreasureMapProgress | null;
    },
    enabled: !!mapQuery.data?.id && !!user?.id,
  });

  return {
    map: mapQuery.data,
    progress: progressQuery.data,
    isLoading: mapQuery.isLoading,
    isProgressLoading: progressQuery.isLoading,
  };
}

export function useCraftTreasureMapProgress() {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  const toggleStep = useMutation({
    mutationFn: async ({ mapId, stepOrder, completed }: { mapId: string; stepOrder: number; completed: boolean }) => {
      if (!user) throw new Error('Must be logged in');

      const { data: existing } = await supabase
        .from('craft_treasure_map_progress' as never)
        .select('*')
        .eq('user_id', user.id)
        .eq('treasure_map_id', mapId)
        .maybeSingle() as { data: CraftTreasureMapProgress | null };

      const currentSteps: number[] = existing?.completed_steps || [];
      const newSteps = completed
        ? [...new Set([...currentSteps, stepOrder])]
        : currentSteps.filter((s: number) => s !== stepOrder);
      const nextStep = Math.max(0, ...newSteps) + 1;

      if (existing) {
        const { error } = await supabase
          .from('craft_treasure_map_progress' as never)
          .update({ completed_steps: newSteps, current_step: nextStep, last_activity: new Date().toISOString() } as never)
          .eq('id', existing.id) as { error: unknown };
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('craft_treasure_map_progress' as never)
          .insert({ user_id: user.id, treasure_map_id: mapId, completed_steps: newSteps, current_step: nextStep } as never) as { error: unknown };
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['craft-treasure-map-progress'] });
    },
  });

  return { toggleStep };
}

type Intent = 'sell' | 'buy' | 'support' | 'manufacture' | 'cold-start' | 'idea';
type CraftType = 'terrain' | 'leather' | 'kitchen' | 'jewelry' | 'board_games' | 'woodworking' | 'digital' | 'other';
type ReadinessLevel = 'idea' | 'prototype' | 'selling' | 'scale';

export interface StartFlowState {
  step: 1 | 2 | 3 | 'result';
  intent: Intent | null;

  craftType: CraftType | null;
  readiness: ReadinessLevel | null;
}

const READINESS_TO_START_STEP: Record<ReadinessLevel, number> = {
  idea: 1,
  prototype: 2,
  selling: 3,
  scale: 4,
};

const CRAFT_TO_SLUG: Record<CraftType, string | null> = {
  terrain: 'terrain-maker',
  leather: 'leather-crafter',
  kitchen: 'kitchen-creator',
  jewelry: 'jewelry-maker',
  board_games: 'board-game-designer',
  woodworking: 'woodworker',
  digital: 'digital-creator',
  other: null,
};

export function useStartFlow() {
  const getRoute = (state: StartFlowState): string => {
    if (state.intent === 'buy') return '/marketplace';
    if (state.intent === 'support') return '/projects';
    if (state.intent === 'manufacture') return '/network';
    if (state.intent === 'idea') return '/cue-cards/campaigns';

    if (state.intent === 'sell' && state.craftType) {
      const slug = CRAFT_TO_SLUG[state.craftType];
      if (slug) return `/treasure-map/${slug}`;
      return '/cue-cards/campaigns';
    }

    return '/welcome';
  };

  const getStartStep = (readiness: ReadinessLevel): number => {
    return READINESS_TO_START_STEP[readiness];
  };

  return { getRoute, getStartStep, CRAFT_TO_SLUG, READINESS_TO_START_STEP };
}

import { useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

interface CreateTurnKeyInput {
  title: string;
  category: string;
  description: string;
  images: string[];
  production_method: string | null;
  stl_file_url: string | null;
  creator_backing_credits: number;
  matching_cap: number;
  early_adopter_slots: number;
  cue_card_id: string | null;
}

function toSlug(title: string): string {
  return title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
    .slice(0, 80);
}

export function useCreateTurnKey() {
  const { user } = useAuth();
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: CreateTurnKeyInput) => {
      if (!user) throw new Error('Not authenticated');

      const baseSlug = toSlug(input.title);
      const slug = `${baseSlug}-${Date.now().toString(36)}`;

      const { data: project, error: projErr } = await supabase
        .from('turnkey_projects' as never)
        .insert({
          creator_id: user.id,
          title: input.title,
          slug,
          description: input.description,
          category: input.category,
          images: input.images,
          status: 'active',
          creator_backing_credits: input.creator_backing_credits,
          community_matched: 0,
          matching_cap: input.matching_cap,
          current_tier: 'early_adopter',

          early_adopter_slots: input.early_adopter_slots,
          early_adopter_filled: 0,
          production_method: input.production_method,
          stl_file_url: input.stl_file_url,
          cue_card_id: input.cue_card_id,
        } as never)
        .select('id, slug')
        .single() as { data: { id: string; slug: string } | null; error: unknown };

      if (projErr || !project) throw projErr || new Error('Failed to create project');

      const unitPrice = Math.ceil(input.creator_backing_credits * 1.2);

      await supabase
        .from('turnkey_tier_history' as never)
        .insert({
          project_id: project.id,
          tier: 'early_adopter',
          units_target: input.early_adopter_slots,
          units_filled: 0,
          unit_price_credits: unitPrice,
          production_method: input.production_method,
        } as never);

      return project;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['turnkey-projects'] });
    },
  });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface CreatorBridge {
  id: string;
  user_id: string;
  service_type: string;
  service_url: string;
  display_name: string | null;
  is_primary: boolean;
  verified: boolean;
  created_at: string;
}

export function useCreatorBridges(userId?: string) {
  return useQuery({
    queryKey: ['creator-bridges', userId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('creator_bridges' as never)
        .select('*')
        .eq('user_id', userId!) as { data: CreatorBridge[] | null; error: unknown };

      if (error) throw error;
      return (data || []) as CreatorBridge[];
    },
    enabled: !!userId,
  });
}

export function useManageBridge() {
  const { user } = useAuth();
  const qc = useQueryClient();

  const createBridge = useMutation({
    mutationFn: async (input: {
      service_type: string;
      service_url: string;
      display_name?: string;
      is_primary?: boolean;
    }) => {
      if (!user) throw new Error('Not authenticated');

      const { data, error } = await supabase
        .from('creator_bridges' as never)
        .insert({
          user_id: user.id,
          service_type: input.service_type,
          service_url: input.service_url,

          display_name: input.display_name || null,
          is_primary: input.is_primary || false,
          verified: false,
        } as never)
        .select('*')
        .single() as { data: CreatorBridge | null; error: unknown };

      if (error || !data) throw error || new Error('Failed to create bridge');
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['creator-bridges'] });
    },
  });

  const updateBridge = useMutation({
    mutationFn: async ({ id, ...updates }: { id: string; service_url?: string; display_name?: string; is_primary?: boolean }) => {
      const { error } = await supabase
        .from('creator_bridges' as never)
        .update(updates as never)
        .eq('id', id) as { error: unknown };

      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['creator-bridges'] });
    },
  });

  const deleteBridge = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('creator_bridges' as never)
        .delete()
        .eq('id', id) as { error: unknown };

      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['creator-bridges'] });
    },
  });

  const verifyBridge = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('creator_bridges' as never)
        .update({ verified: true } as never)
        .eq('id', id) as { error: unknown };

      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['creator-bridges'] });
    },
  });

  return { createBridge, updateBridge, deleteBridge, verifyBridge };
}

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface CreditWallet {
  balance: number;
  lifetime_purchased: number;
  lifetime_spent: number;
  lifetime_earned: number;
}

export interface CreditTransaction {
  id: string;
  amount: number;
  type: string;
  description: string | null;
  created_at: string;
}

export function useCreditWallet() {
  const { user } = useAuth();
  return useQuery({
    queryKey: ["credit-wallet", user?.id],
    queryFn: async (): Promise<CreditWallet> => {
