/**
 * DISCOVERY STATE HOOK
 * ====================
 * Provides shared discovery state for progressive disclosure across the app.
 * Components can check if features/cards are discovered and reveal content accordingly.
 */

import { useState, useEffect, useCallback, createContext, useContext, ReactNode } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

// Discovery card slugs mapped to dashboard sections
export const DASHBOARD_DISCOVERY_MAP = {
  // Essential (always visible after signup)
  'membership-status': 'essentials',
  'guild-stake': 'essentials',

  // Initiatives (discovered via navigation)
  'lets-make-dinner': 'initiatives',
  'defense-klaus': 'initiatives',
  'lets-get-groceries': 'initiatives',
  'lets-go-shopping': 'initiatives',

  // Exploration (discovered via navigation)
  'crowdfunding-hub': 'exploration',
  'medallion-management': 'exploration',
  'hofund-studio': 'exploration',
  'herald-subscription': 'exploration',

  // Economy (discovered via navigation)
  'eoi-dashboard': 'economy',
  'project-preferences': 'economy',
  'participation-breakdown': 'economy',
  'contribution-timeline': 'economy',

  // Governance (discovered via navigation)
  'legal-formation': 'governance',
  'charitable-loan': 'governance',

  // Tools
  'referral-manager': 'tools',
  'physical-badge': 'tools',
} as const;

export type DiscoverySlug = keyof typeof DASHBOARD_DISCOVERY_MAP;

interface DiscoveryState {
  discoveries: Set<string>;
  categoryDiscoveries: Set<string>;
  isLoading: boolean;

  isDiscovered: (slug: string) => boolean;
  isCategoryDiscovered: (category: string) => boolean;
  discoverCard: (slug: string, category?: string) => Promise<void>;
  discoveryLevel: number; // 0 = new, increases as user discovers more
}

const DiscoveryContext = createContext<DiscoveryState | null>(null);

export function DiscoveryProvider({ children }: { children: ReactNode }) {
  const { user } = useAuth();
  const [discoveries, setDiscoveries] = useState<Set<string>>(new Set());
  const [categoryDiscoveries, setCategoryDiscoveries] = useState<Set<string>>(new Set());
  const [isLoading, setIsLoading] = useState(true);

  // Load discoveries from database or localStorage (for ghosts)
  useEffect(() => {
    loadDiscoveries();
  }, [user]);

  const loadDiscoveries = async () => {
    setIsLoading(true);

    if (user) {
      // Load from database
      const { data } = await supabase
        .from('user_discovery_state')
        .select('card_slug, category_slug')
        .eq('user_id', user.id);

      if (data) {
        const cards = new Set(data.filter(d => d.card_slug).map(d => d.card_slug as string));
        const categories = new Set(data.map(d => d.category_slug));

        // Auto-discover essentials for all authenticated users
        cards.add('membership-status');
        cards.add('guild-stake');
        categories.add('essentials');

        setDiscoveries(cards);
        setCategoryDiscoveries(categories);
      } else {
        // New user - start with essentials
        setDiscoveries(new Set(['membership-status', 'guild-stake']));
        setCategoryDiscoveries(new Set(['essentials']));
      }
    } else {
      // Ghost user - check localStorage
      const ghostDiscoveries = localStorage.getItem('lb_ghost_discoveries');
      if (ghostDiscoveries) {
        try {

        const parsed = JSON.parse(ghostDiscoveries);
        setDiscoveries(new Set(parsed.cards || []));
        setCategoryDiscoveries(new Set(parsed.categories || []));
      } catch {
        setDiscoveries(new Set());
        setCategoryDiscoveries(new Set());
      }
    } else {
      setDiscoveries(new Set());
      setCategoryDiscoveries(new Set());
    }
  }

  setIsLoading(false);
};

const isDiscovered = useCallback((slug: string): boolean => {
  return discoveries.has(slug);
}, [discoveries]);

const isCategoryDiscovered = useCallback((category: string): boolean => {
  return categoryDiscoveries.has(category);
}, [categoryDiscoveries]);

const discoverCard = useCallback(async (slug: string, category?: string) => {
  // Already discovered
  if (discoveries.has(slug)) return;

  const cardCategory = category || DASHBOARD_DISCOVERY_MAP[slug as DiscoverySlug] || 'exploration';

  if (user) {
    // Save to database
    await supabase.from('user_discovery_state').upsert({
      user_id: user.id,
      card_slug: slug,
      category_slug: cardCategory,
      discovered_at: new Date().toISOString(),
    }, { onConflict: 'user_id,card_slug' });
  } else {
    // Save to localStorage for ghosts
    const ghostDiscoveries = localStorage.getItem('lb_ghost_discoveries');
    const parsed = ghostDiscoveries ? JSON.parse(ghostDiscoveries) : { cards: [], categories: [] };
    parsed.cards = [...new Set([...parsed.cards, slug])];
    parsed.categories = [...new Set([...parsed.categories, cardCategory])];
    localStorage.setItem('lb_ghost_discoveries', JSON.stringify(parsed));
  }

  // Update local state
  setDiscoveries(prev => new Set([...prev, slug]));
  setCategoryDiscoveries(prev => new Set([...prev, cardCategory]));

  }, [user, discoveries]);

  // Calculate discovery level based on number of discoveries
  const discoveryLevel = Math.min(10, Math.floor(discoveries.size / 3));

  return (
    <DiscoveryContext.Provider value={{
      discoveries,
      categoryDiscoveries,
      isLoading,
      isDiscovered,
      isCategoryDiscovered,
      discoverCard,
      discoveryLevel,
    }}>
      {children}
    </DiscoveryContext.Provider>
  );
}

export function useDiscovery(): DiscoveryState {
  const context = useContext(DiscoveryContext);
  if (!context) {
    // Return a default state when not wrapped in provider (for backwards compatibility)
    return {
      discoveries: new Set(),
      categoryDiscoveries: new Set(),
      isLoading: false,
      isDiscovered: () => true, // Show everything if no provider
      isCategoryDiscovered: () => true,
      discoverCard: async () => {},
      discoveryLevel: 10,
    };
  }
  return context;
}

/**
 * DISCOVERY TRACKER HOOK
 * =======================
 * Watches the current route. When a user visits a route that matches
 * a discoverable_card.discovery_route, automatically marks it as discovered.
 *
 * Also handles:
 * - Mirror + Compass as core onboarding items
 * - Ghost discovery storage in localStorage
 * - Triggers chalk-outline reveal animations
 * - Fires discovery toasts
 */

import { useEffect, useRef } from "react";
import { useLocation } from "react-router-dom";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

const GHOST_DISCOVERIES_KEY = "lb_ghost_discoveries";

// Core items that everyone should find
const CORE_ITEMS = {
  mirror: { route: "/durins-door", name: "The Mirror", icon: "\uD83E\uDE9E" },
  compass: { route: "/the-helm", name: "The Compass", icon: "\uD83E\uDDED" },
};

export function useDiscoveryTracker() {
  const { user } = useAuth();
  const location = useLocation();
  const discoveredThisSession = useRef<Set<string>>(new Set());
  const cardsRef = useRef<Array<{ slug: string; category_slug: string; discovery_route: string | null }>>([]);
  const loadedRef = useRef(false);

  // Load discoverable cards once
  useEffect(() => {
    loadCards();
  }, []);

  // Track route changes
  useEffect(() => {
    if (loadedRef.current) {
      checkDiscovery(location.pathname);
    }
  }, [location.pathname, user]);

  const loadCards = async () => {
    const { data } = await supabase
      .from("discoverable_cards")
      .select("slug, category_slug, discovery_route");

  if (data) {
    cardsRef.current = data;
    loadedRef.current = true;
  }
};

const checkDiscovery = async (path: string) => {
  // Find matching cards
  const matches = cardsRef.current.filter(
    (c) => c.discovery_route && path.startsWith(c.discovery_route)
  );

  for (const card of matches) {
    if (discoveredThisSession.current.has(card.slug)) continue;
    discoveredThisSession.current.add(card.slug);

    if (user) {
      // Authenticated: write to database
      const { error } = await supabase
        .from("user_discovery_state")
        .upsert({
          user_id: user.id,
          category_slug: card.category_slug,
          card_slug: card.slug,
        }, { onConflict: "user_id,category_slug,card_slug" });

      if (!error) {
        // Also discover the category itself
        await supabase
          .from("user_discovery_state")
          .upsert({
            user_id: user.id,
            category_slug: card.category_slug,
            card_slug: null,
          }, { onConflict: "user_id,category_slug,card_slug" });

        toast.success(`Discovered: ${card.slug.replace(/-/g, " ")}`, {
          description: "A new card has been added to your collection.",
          duration: 3000,
        });
      }
    } else {
      // Ghost: store in localStorage
      const existing = JSON.parse(localStorage.getItem(GHOST_DISCOVERIES_KEY) || "[]");
      if (!existing.includes(card.slug)) {
        existing.push(card.slug);
        localStorage.setItem(GHOST_DISCOVERIES_KEY, JSON.stringify(existing));

        toast.success(`Discovered: ${card.slug.replace(/-/g, " ")}`, {
          description: "This discovery will carry over when you join.",

            duration: 3000,
          });
        }
      }
    }

    // Check core items
    if (path.startsWith(CORE_ITEMS.mirror.route)) {
      handleCoreDiscovery("mirror");
    }
    if (path.startsWith(CORE_ITEMS.compass.route)) {
      handleCoreDiscovery("compass");
    }
  };

  const handleCoreDiscovery = (item: "mirror" | "compass") => {
    const key = `lb_core_${item}`;
    if (localStorage.getItem(key)) return;
    localStorage.setItem(key, "true");

    const core = CORE_ITEMS[item];

    if (item === "mirror") {
      toast.success(`${core.icon} You found The Mirror!`, {
        description: "Your Crow Feathers meter has been revealed. The Mirror shows who you are.",
        duration: 5000,
      });
    } else {
      toast.success(`${core.icon} You found The Compass!`, {
        description: "Navigation unlocked. Your bookshelf expands. The Compass shows where you're going.",
        duration: 5000,
      });
    }
  };
}

/**
 * Get ghost discoveries from localStorage (for carry-over on signup)
 */
export function getGhostDiscoveries(): string[] {
  try {
    return JSON.parse(localStorage.getItem(GHOST_DISCOVERIES_KEY) || "[]");
  } catch {
    return [];
  }
}

/**
 * Check if a core item has been found
 */

export function hasCoreItem(item: "mirror" | "compass"): boolean {
  return localStorage.getItem(`lb_core_${item}`) === "true";
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface DoorConfig {
  id: string;
  medallion_id: string;
  default_template: string;
  default_data: Record<string, unknown>;
  active_from: string;
  active_until: string | null;
  created_at: string;
}

export interface DoorRule {
  id: string;
  config_id: string;
  key_type: 'phrase' | 'email' | 'code' | 'any';
  key_value: string;
  case_sensitive: boolean;
  single_use: boolean;
  used: boolean;
  template: string;
  experience_data: Record<string, unknown>;
  intended_recipient: string | null;
  sort_order: number;
  created_at: string;
}

export interface DoorConfigWithRules extends DoorConfig {
  rules: DoorRule[];
}

export function useDurinsDoorForMedallion(medallionId: string | undefined) {
  return useQuery({
    queryKey: ['durins-door', medallionId],
    queryFn: async (): Promise<DoorConfigWithRules | null> => {
      if (!medallionId) return null;

      const { data: configs } = await supabase
        .from('durins_door_configs' as never)
        .select('*')
        .eq('medallion_id', medallionId)
        .order('created_at', { ascending: false })
        .limit(1) as { data: DoorConfig[] | null };

      if (!configs || configs.length === 0) return null;
      const config = configs[0];

      const { data: rules } = await supabase

        .from('durins_door_rules' as never)
        .select('*')
        .eq('config_id', config.id)
        .order('sort_order') as { data: DoorRule[] | null };

      return { ...config, rules: rules || [] };
    },
    enabled: !!medallionId,
    staleTime: 30_000,
  });
}

export function useMyDoorConfigs() {
  const { user } = useAuth();
  return useQuery({
    queryKey: ['my-door-configs', user?.id],
    queryFn: async () => {
      const { data } = await supabase
        .from('durins_door_configs' as never)
        .select('*')
        .eq('medallion_id', user!.id)
        .order('created_at', { ascending: false }) as { data: DoorConfig[] | null };
      return data || [];
    },
    enabled: !!user,
  });
}

export function useCreateDoorConfig() {
  const qc = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async (params: {
      default_template?: string;
      default_data?: Record<string, unknown>;
      active_until?: string | null;
    }) => {
      const { data, error } = await supabase
        .from('durins_door_configs' as never)
        .insert({ medallion_id: user!.id, ...params } as never)
        .select()
        .single();
      if (error) throw error;
      return data as unknown as DoorConfig;
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['my-door-configs'] }),
  });
}

export function useCreateDoorRule() {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (rule: Omit<DoorRule, 'id' | 'created_at' | 'used'>) => {
      const { data, error } = await supabase
        .from('durins_door_rules' as never)
        .insert(rule as never)
        .select()
        .single();
      if (error) throw error;
      return data as unknown as DoorRule;
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['durins-door'] }),
  });
}

export function evaluateDoorRule(
  rules: DoorRule[],
  input: string
): DoorRule | null {
  return rules.find((r) => {
    if (r.single_use && r.used) return false;
    if (r.key_type === 'any') return true;
    return r.case_sensitive
      ? r.key_value === input
      : r.key_value.toLowerCase() === input.toLowerCase();
  }) || null;
}

export function isDoorConfigActive(config: DoorConfig): boolean {
  const now = new Date();
  if (config.active_from && new Date(config.active_from) > now) return false;
  if (config.active_until && new Date(config.active_until) < now) return false;
  return true;
}

import { useQuery, useMutation } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface EarningsSummary {
  totalEarned: number;
  availableToWithdraw: number;
  platformFee: number;
  netPayout: number;
  connectStatus: "connected" | "pending" | "none";
  payoutsEnabled: boolean;
}

export interface PayoutRecord {
  id: string;
  amount_cents: number;
  fee_cents: number;
  net_amount_cents: number;
  status: string;
  created_at: string;
  completed_at: string | null;
}

export function useEarnings() {
  const { user } = useAuth();
  return useQuery({
    queryKey: ["earnings-summary", user?.id],
    queryFn: async (): Promise<EarningsSummary> => {
      if (!user) {
        return { totalEarned: 0, availableToWithdraw: 0, platformFee: 0, netPayout: 0, connectStatus: "none", payoutsEnabled: false };
      }

      const { data: wallet } = await supabase
        .from("credit_wallets" as never)
        .select("lifetime_earned")
        .eq("user_id", user.id)
        .maybeSingle() as { data: { lifetime_earned: number } | null };

      // Sum credits earned from backing/reward transactions still in wallet
      const { data: available } = await supabase
        .from("credit_transactions" as never)
        .select("amount")
        .eq("user_id", user.id)
        .in("type", ["reward", "match"]) as { data: { amount: number }[] | null };

      const availableCredits = (available ?? []).reduce((s, r) => s + r.amount, 0);
      const earned = wallet?.lifetime_earned || 0;

      // Check Connect account
      const { data: connect } = await supabase

        .from("member_connect_accounts" as never)
        .select("onboarding_status, payouts_enabled")
        .eq("user_id", user.id)
        .maybeSingle() as { data: { onboarding_status: string; payouts_enabled: boolean } | null };

      const platformFee = Math.round(availableCredits * 0.167);
      const netPayout = availableCredits - platformFee;

      return {
        totalEarned: earned,
        availableToWithdraw: Math.max(0, availableCredits),
        platformFee,
        netPayout: Math.max(0, netPayout),
        connectStatus: connect?.onboarding_status === "complete" ? "connected" : connect ? "pending" : "none",
        payoutsEnabled: connect?.payouts_enabled ?? false,
      };
    },
    enabled: !!user,
    staleTime: 30_000,
  });
}

export function usePayoutHistory() {
  const { user } = useAuth();
  return useQuery({
    queryKey: ["payout-history", user?.id],
    queryFn: async (): Promise<PayoutRecord[]> => {
      if (!user) return [];

      const { data, error } = await supabase
        .from("member_payouts" as never)
        .select("id, amount_cents, fee_cents, net_amount_cents, status, created_at, completed_at")
        .eq("user_id", user.id)
        .order("created_at", { ascending: false })
        .limit(25) as { data: PayoutRecord[] | null; error: any };

      if (error) return [];
      return data ?? [];
    },
    enabled: !!user,
  });
}

export function useRequestPayout() {
  return useMutation({
    mutationFn: async (amount: number) => {
      const { data, error } = await supabase.functions.invoke(
        "stripe-connect-payout",
        { body: { amount } }
      );

      if (error) throw error;
      const body = data as { success?: boolean; error?: string; net_payout_usd?: string };
      if (body.error) throw new Error(body.error);
      return body;
    },
  });
}

/**
 * useEnergyInnovationCluster2427
 * =================================
 * MISS-013 — Energy Innovation Cluster (#24-27)
 * Wave 2 / Old One: urIm / Bushel 29 (BP025)
 *
 * Depends on MISS-006 (AC Pressure Generation) + MISS-012 (Water Table).
 * Interface stubs provided for both dependencies.
 *
 * Four sub-innovations:
 *   #24 — Solar-Assisted Pump Integration
 *   #25 — Piezoelectric Harvest from Hexel Vibration
 *   #26 — Kinetic-to-Hydraulic from Player Movement
 *   #27 — Battery-Free LED via Flow-Driven Dynamo
 */

import { useState, useCallback, useEffect, useRef } from 'react';

// ── Dependency stubs ──────────────────────────────────────────────────────────

/** MISS-006: AC Pressure Generation interface stub */
export interface ACPressureInterface {
  acFrequencyHz: number;
  peakPressurePsi: number;
  waveformActive: boolean;
}

/** MISS-012: Water Table interface stub */
export interface WaterTableInterface {
  currentLevelMm: number;
  flowRateMlPerSec: number;
  tableTemperatureCelsius: number;
  gravityHeadFt: number;
}

// ── Sub-innovation states ─────────────────────────────────────────────────────

export interface SolarPumpState {
  /** Solar irradiance (0–1000 W/m²) */
  irradianceWm2: number;
  /** Pump boost factor applied to base hydraulic flow */
  pumpBoostFactor: number;
  /** Effective flow rate including solar assist (mL/s) */
  effectiveFlowMlPerSec: number;
  /** Panel tilt angle (degrees) */
  panelTiltDeg: number;
}

export interface PiezoelectricState {
  /** Hexel vibration amplitude (0–1) from player/water activity */

  vibrationAmplitude: number;
  /** Harvested microwatts */
  harvestedMicrowatts: number;
  /** Accumulated energy in mJ */
  accumulatedEnergyMj: number;
  /** Piezo array size */
  arrayCount: number;
}

export interface KineticHydraulicState {
  /** Steps taken by player (simulated) */
  playerSteps: number;
  /** Kinetic energy captured per step (mJ) */
  energyPerStepMj: number;
  /** Hydraulic pressure boost from kinetic capture (psi) */
  hydraulicBoostPsi: number;
  /** Flywheel charge (0–100%) */
  flywheelChargePct: number;
}

export interface FlowDynamoState {
  /** Flow velocity through dynamo (mL/s) */
  flowVelocityMlPerSec: number;
  /** Generated voltage (V) */
  generatedVoltageV: number;
  /** LED illumination level (0–1) */
  ledIlluminationLevel: number;
  /** Dynamos online */
  dynamosOnline: number;
}

export interface EnergyInnovationCluster2427State {
  acPressure: ACPressureInterface;
  waterTable: WaterTableInterface;
  solar: SolarPumpState;
  piezo: PiezoelectricState;
  kinetic: KineticHydraulicState;
  dynamo: FlowDynamoState;
  running: boolean;
  tick: number;
  activeTab: '24' | '25' | '26' | '27';
}

// ── Default values ────────────────────────────────────────────────────────────

const DEFAULT_AC: ACPressureInterface = { acFrequencyHz: 0.5, peakPressurePsi: 2.17, waveformActive: true };
const DEFAULT_WT: WaterTableInterface = { currentLevelMm: 380, flowRateMlPerSec: 42, tableTemperatureCelsius: 20, gravityHeadFt: 3 };

// ── Hook ──────────────────────────────────────────────────────────────────────

export function useEnergyInnovationCluster2427(
  acPressureOverride?: Partial<ACPressureInterface>,
  waterTableOverride?: Partial<WaterTableInterface>,
) {
  const acPressure: ACPressureInterface = { ...DEFAULT_AC, ...acPressureOverride };
  const waterTableBase: WaterTableInterface = { ...DEFAULT_WT, ...waterTableOverride };

  const [state, setState] = useState<EnergyInnovationCluster2427State>({
    acPressure,
    waterTable: waterTableBase,
    solar: {
      irradianceWm2: 600,
      pumpBoostFactor: 1.0,
      effectiveFlowMlPerSec: waterTableBase.flowRateMlPerSec,
      panelTiltDeg: 35,
    },
    piezo: {
      vibrationAmplitude: 0,
      harvestedMicrowatts: 0,
      accumulatedEnergyMj: 0,
      arrayCount: 12,
    },
    kinetic: {
      playerSteps: 0,
      energyPerStepMj: 2.4,
      hydraulicBoostPsi: 0,
      flywheelChargePct: 0,
    },
    dynamo: {
      flowVelocityMlPerSec: waterTableBase.flowRateMlPerSec,
      generatedVoltageV: 0,
      ledIlluminationLevel: 0,
      dynamosOnline: 6,
    },
    running: false,
    tick: 0,
    activeTab: '24',
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const setActiveTab = useCallback((tab: '24' | '25' | '26' | '27') => {
    setState(prev => ({ ...prev, activeTab: tab }));
  }, []);

  const setIrradiance = useCallback((wm2: number) => {
    setState(prev => {
      const boost = 1 + (wm2 / 1000) * 0.4;
      return {
        ...prev,

        solar: {
          ...prev.solar,
          irradianceWm2: wm2,
          pumpBoostFactor: boost,
          effectiveFlowMlPerSec: prev.waterTable.flowRateMlPerSec * boost,
        },
      };
    });
  }, []);

  const setPanelTilt = useCallback((deg: number) => {
    setState(prev => ({ ...prev, solar: { ...prev.solar, panelTiltDeg: deg } }));
  }, []);

  const triggerPlayerStep = useCallback(() => {
    setState(prev => {
      const steps = prev.kinetic.playerSteps + 1;
      const flywheel = Math.min(prev.kinetic.flywheelChargePct + 3, 100);
      const boost = (flywheel / 100) * 0.8; // up to 0.8 psi boost
      return {
        ...prev,
        kinetic: { ...prev.kinetic, playerSteps: steps, flywheelChargePct: flywheel, hydraulicBoostPsi: boost },
      };
    });
  }, []);

  const setVibrationAmplitude = useCallback((amp: number) => {
    setState(prev => {
      const microwatts = amp * prev.piezo.arrayCount * 18;
      return {
        ...prev,
        piezo: { ...prev.piezo, vibrationAmplitude: amp, harvestedMicrowatts: microwatts },
      };
    });
  }, []);

  const setDynamosOnline = useCallback((count: number) => {
    setState(prev => {
      const voltage = (prev.dynamo.flowVelocityMlPerSec / 100) * count * 0.35;
      const led = Math.min(voltage / 3.3, 1);
      return {
        ...prev,
        dynamo: { ...prev.dynamo, dynamosOnline: count, generatedVoltageV: voltage, ledIlluminationLevel: led },
      };
    });
  }, []);

  const toggleSimulation = useCallback(() => {
    setState(prev => ({ ...prev, running: !prev.running }));
  }, []);

  const reset = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    setState(prev => ({
      ...prev,
      running: false,
      tick: 0,
      solar: { irradianceWm2: 600, pumpBoostFactor: 1.0, effectiveFlowMlPerSec: waterTableBase.flowRateMlPerSec, panelTiltDeg: 35 },
      piezo: { vibrationAmplitude: 0, harvestedMicrowatts: 0, accumulatedEnergyMj: 0, arrayCount: 12 },
      kinetic: { playerSteps: 0, energyPerStepMj: 2.4, hydraulicBoostPsi: 0, flywheelChargePct: 0 },
      dynamo: { flowVelocityMlPerSec: waterTableBase.flowRateMlPerSec, generatedVoltageV: 0, ledIlluminationLevel: 0, dynamosOnline: 6 },
    }));
  }, [waterTableBase.flowRateMlPerSec]);

  // Auto-simulation
  useEffect(() => {
    if (!state.running) {
      if (intervalRef.current) clearInterval(intervalRef.current);
      return;
    }
    intervalRef.current = setInterval(() => {
      setState(prev => {
        const t = prev.tick + 1;
        const sun = 400 + Math.sin(t * 0.05) * 350 + Math.random() * 80;
        const vib = Math.abs(Math.sin(t * 0.12)) * (prev.acPressure.waveformActive ? 0.85 : 0.4);
        const microwatts = vib * prev.piezo.arrayCount * 18;
        const accumulated = prev.piezo.accumulatedEnergyMj + microwatts * 0.12 * 0.001;
        const fly = Math.min(prev.kinetic.flywheelChargePct + (t % 15 === 0 ? 5 : -0.3), 100);
        const solarBoost = 1 + (sun / 1000) * 0.4;
        const flowWithSolar = prev.waterTable.flowRateMlPerSec * solarBoost;
        const dynVoltage = (flowWithSolar / 100) * prev.dynamo.dynamosOnline * 0.35;
        const led = Math.min(dynVoltage / 3.3, 1);

        return {
          ...prev,
          tick: t,
          solar: {
            ...prev.solar,
            irradianceWm2: Math.round(sun),
            pumpBoostFactor: solarBoost,
            effectiveFlowMlPerSec: flowWithSolar,
          },
          piezo: {
            ...prev.piezo,
            vibrationAmplitude: vib,
            harvestedMicrowatts: microwatts,
            accumulatedEnergyMj: accumulated,
          },
          kinetic: { ...prev.kinetic, flywheelChargePct: Math.max(fly, 0), hydraulicBoostPsi: (Math.max(fly, 0) / 100) * 0.8 },
          dynamo: {

            ...prev.dynamo,
            flowVelocityMlPerSec: flowWithSolar,
            generatedVoltageV: dynVoltage,
            ledIlluminationLevel: led,
          },
        };
      });
    }, 150);
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [state.running]);

  return {
    state,
    setActiveTab,
    setIrradiance,
    setPanelTilt,
    triggerPlayerStep,
    setVibrationAmplitude,
    setDynamosOnline,
    toggleSimulation,
    reset,
  };
}

/**
 * useFeatureFlag — React Hook for Feature Flag State
 * K525 · Phase D.1 · Innovation #2277
 *
 * Wraps the `getFeatureFlag()` client with `@tanstack/react-query` so the
 * Conductor tab and other gated UI surfaces can render conditionally with
 * minimal boilerplate.
 *
 * Usage:
 *   const { enabled, isLoading } = useFeatureFlag("CONDUCTOR_BATON_ENABLED");
 *   if (!enabled) return null;
 */

import { useQuery } from "@tanstack/react-query";
import {
  getFeatureFlag,
  type FeatureFlagKey,
  type FeatureFlagState,
} from "@/lib/conductor/featureFlag";

const STALE_MS = 30_000;

export function useFeatureFlag(key: FeatureFlagKey): {
  enabled: boolean;
  rolloutWave: string | null;
  isLoading: boolean;
} {
  const { data, isLoading } = useQuery<FeatureFlagState>({
    queryKey: ["feature-flag", key],
    queryFn: () => getFeatureFlag(key),
    staleTime: STALE_MS,
  });

  return {
    enabled: data?.enabled ?? false,
    rolloutWave: data?.rolloutWave ?? null,
    isLoading,
  };
}

/**
 * useGhostSession — Centralized ghost browsing session for unauthenticated visitors.
 *
 * Ghost Marks half-life: 50% decay every 24 hours of inactivity.
 * After 72 hours with no activity, session expires completely.
 * localStorage only — no Supabase auth required.
 */

import { useState, useEffect, useCallback, useMemo } from 'react';
import { useAuth } from '@/contexts/AuthContext';

const STORAGE_KEY = 'lb_ghost_browsing_session';
const HALF_LIFE_MS = 24 * 60 * 60 * 1000; // 24 hours
const EXPIRY_MS = 72 * 60 * 60 * 1000; // 72 hours

export interface GhostBrowsingSession {
  ghostId: string;
  createdAt: string;
  lastActiveAt: string;
  tempMarks: number;
  pagesVisited: string[];
  actionsAttempted: string[];
  goldenKeysFound: number;
  beaconRunsCompleted: number;
}

function generateGhostId(): string {
  return `ghost_${Date.now()}_${Math.random().toString(36).slice(2, 11)}`;
}

function loadSession(): GhostBrowsingSession | null {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;
    return JSON.parse(raw) as GhostBrowsingSession;
  } catch {
    return null;
  }
}

function saveSession(session: GhostBrowsingSession): void {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(session));
}

function applyDecay(session: GhostBrowsingSession): GhostBrowsingSession {
  const now = Date.now();
  const lastActive = new Date(session.lastActiveAt).getTime();
  const elapsed = now - lastActive;

  if (elapsed >= EXPIRY_MS) {

    return createFreshSession();
  }

  if (elapsed >= HALF_LIFE_MS) {
    const decayPeriods = Math.floor(elapsed / HALF_LIFE_MS);
    const decayFactor = Math.pow(0.5, decayPeriods);
    return {
      ...session,
      tempMarks: Math.floor(session.tempMarks * decayFactor),
      lastActiveAt: new Date().toISOString(),
    };
  }

  return session;
}

function createFreshSession(): GhostBrowsingSession {
  return {
    ghostId: generateGhostId(),
    createdAt: new Date().toISOString(),
    lastActiveAt: new Date().toISOString(),
    tempMarks: 0,
    pagesVisited: [],
    actionsAttempted: [],
    goldenKeysFound: 0,
    beaconRunsCompleted: 0,
  };
}

// Marks awards
const MARKS_AWARD = {
  viewTreasureMap: 5,
  completeBeaconRun: 10,
  findGoldenKey: 25,
  visitFivePages: 5,
  viewCueCard: 2,
  flipCard: 1,
} as const;

export function useGhostSession() {
  const { user } = useAuth();
  const [session, setSession] = useState<GhostBrowsingSession | null>(null);

  // On mount: load or create session (only for non-authed users)
  useEffect(() => {
    if (user) {
      setSession(null);
      return;
    }

    let loaded = loadSession();
    if (loaded) {
      loaded = applyDecay(loaded);
    } else {
      loaded = createFreshSession();
    }
    saveSession(loaded);
    setSession(loaded);
    localStorage.setItem('ghost_mode', 'true');
  }, [user]);

  const isGhost = !user && session !== null;
  const tempMarks = session?.tempMarks ?? 0;

  const updateSession = useCallback((updater: (prev: GhostBrowsingSession) => GhostBrowsingSession) => {
    setSession(prev => {
      if (!prev) return prev;
      const next = updater({ ...prev, lastActiveAt: new Date().toISOString() });
      saveSession(next);
      return next;
    });
  }, []);

  const awardMarks = useCallback((amount: number) => {
    updateSession(s => ({ ...s, tempMarks: s.tempMarks + amount }));
  }, [updateSession]);

  const trackPageVisit = useCallback((path: string) => {
    updateSession(s => {
      const alreadyVisited = s.pagesVisited.includes(path);
      const pages = alreadyVisited ? s.pagesVisited : [...s.pagesVisited, path];
      const bonus = !alreadyVisited && pages.length === 5 ? MARKS_AWARD.visitFivePages : 0;
      return { ...s, pagesVisited: pages, tempMarks: s.tempMarks + bonus };
    });
  }, [updateSession]);

  const trackActionAttempted = useCallback((action: string) => {
    updateSession(s => ({
      ...s,
      actionsAttempted: s.actionsAttempted.includes(action)
        ? s.actionsAttempted
        : [...s.actionsAttempted, action],
    }));
  }, [updateSession]);

  const awardTreasureMapView = useCallback(() => {
    awardMarks(MARKS_AWARD.viewTreasureMap);
  }, [awardMarks]);

  const awardBeaconRunComplete = useCallback(() => {

    updateSession(s => ({
      ...s,
      tempMarks: s.tempMarks + MARKS_AWARD.completeBeaconRun,
      beaconRunsCompleted: s.beaconRunsCompleted + 1,
    }));
  }, [updateSession]);

  const awardGoldenKeyFound = useCallback(() => {
    updateSession(s => ({
      ...s,
      tempMarks: s.tempMarks + MARKS_AWARD.findGoldenKey,
      goldenKeysFound: s.goldenKeysFound + 1,
    }));
  }, [updateSession]);

  const awardFlipCard = useCallback(() => {
    awardMarks(MARKS_AWARD.flipCard);
  }, [awardMarks]);

  const awardCueCardView = useCallback(() => {
    awardMarks(MARKS_AWARD.viewCueCard);
  }, [awardMarks]);

  // Check if Ghost Marks are fading (48+ hours since last activity)
  const isFading = useMemo(() => {
    if (!session) return false;
    const elapsed = Date.now() - new Date(session.lastActiveAt).getTime();
    return elapsed >= 48 * 60 * 60 * 1000;
  }, [session]);

  // For conversion on signup: returns session data then clears ghost storage
  const consumeForConversion = useCallback((): GhostBrowsingSession | null => {
    const current = loadSession();
    if (current) {
      localStorage.removeItem(STORAGE_KEY);
      localStorage.removeItem('ghost_mode');
      localStorage.removeItem('ghost_entry_path');
    }
    setSession(null);
    return current;
  }, []);

  return {
    isGhost,
    session,
    tempMarks,
    isFading,
    awardMarks,
    trackPageVisit,
    trackActionAttempted,

    awardTreasureMapView,
    awardBeaconRunComplete,
    awardGoldenKeyFound,
    awardFlipCard,
    awardCueCardView,
    consumeForConversion,
    MARKS_AWARD,
  };
}

import { useState, useCallback, useRef, useEffect } from 'react';

// MISS-009 — Gravity-Powered Baseline
// Standalone — no deps.
// 8-foot column provides gravity-fed pressure (~2.17 psi at 5-foot effective head).
// No pumps, no batteries. Water source: 5-gallon jug on telescoping legs (flat-pack ship).

export interface GravityBaselineState {
  jugVolumeGallons: number;    // current water in jug (0..5)
  columnHeightFt: number;      // physical column height (0..8)
  effectiveHeadFt: number;     // head pressure height (0..8)
  pressurePsi: number;         // computed PSI
  flowRateGPM: number;         // gallons per minute at current pressure
  isFlowing: boolean;
  telescopingLegExtended: boolean;
  elapsedSeconds: number;
}

export interface GravityBaselineConfig {
  maxColumnHeightFt: number;   // default 8
  jugCapacityGallons: number;  // default 5
  outletDiameterInch: number;  // default 0.5
}

const DEFAULT_CONFIG: GravityBaselineConfig = {
  maxColumnHeightFt: 8,
  jugCapacityGallons: 5,
  outletDiameterInch: 0.5,
};

// PSI from head: 1 ft H2O = 0.4335 psi
function computePressure(effectiveHeadFt: number): number {
  return Math.max(0, effectiveHeadFt * 0.4335);
}

// Torricelli-derived flow: Q = Cd * A * sqrt(2 * g * h)
// Simplified to GPM with empirical coefficients matching the spec (~2.17 psi at 5 ft)
function computeFlowGPM(pressurePsi: number, outletDiameterInch: number): number {
  if (pressurePsi <= 0) return 0;
  const area = Math.PI * Math.pow(outletDiameterInch / 2, 2); // in²
  const Cd = 0.61;
  const velocity = Cd * Math.sqrt(2 * 32.2 * (pressurePsi / 0.4335)); // ft/s
  return velocity * area * (1 / 144) * 7.48052 * 60; // GPM
}

export function useGravityPoweredBaseline(config: Partial<GravityBaselineConfig> = {}) {
  const cfg = { ...DEFAULT_CONFIG, ...config };

  const [state, setState] = useState<GravityBaselineState>({
    jugVolumeGallons: cfg.jugCapacityGallons,

    columnHeightFt: cfg.maxColumnHeightFt,
    effectiveHeadFt: 5,
    pressurePsi: computePressure(5),
    flowRateGPM: 0,
    isFlowing: false,
    telescopingLegExtended: true,
    elapsedSeconds: 0,
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const setColumnHeight = useCallback((heightFt: number) => {
    const h = Math.max(0, Math.min(cfg.maxColumnHeightFt, heightFt));
    setState(prev => {
      const eff = Math.min(h, 5); // effective head capped at 5 ft per spec
      const psi = computePressure(eff);
      return {
        ...prev,
        columnHeightFt: h,
        effectiveHeadFt: eff,
        pressurePsi: psi,
        flowRateGPM: prev.isFlowing ? computeFlowGPM(psi, cfg.outletDiameterInch) : 0,
      };
    });
  }, [cfg]);

  const toggleFlow = useCallback(() => {
    setState(prev => {
      const nowFlowing = !prev.isFlowing;
      return {
        ...prev,
        isFlowing: nowFlowing,
        flowRateGPM: nowFlowing ? computeFlowGPM(prev.pressurePsi, cfg.outletDiameterInch) : 0,
      };
    });
  }, [cfg.outletDiameterInch]);

  const toggleTelescopingLegs = useCallback(() => {
    setState(prev => ({ ...prev, telescopingLegExtended: !prev.telescopingLegExtended }));
  }, []);

  const refillJug = useCallback(() => {
    setState(prev => ({ ...prev, jugVolumeGallons: cfg.jugCapacityGallons }));
  }, [cfg.jugCapacityGallons]);

  // Drain jug when flowing
  useEffect(() => {
    if (state.isFlowing) {
      intervalRef.current = setInterval(() => {
        setState(prev => {

          if (!prev.isFlowing) return prev;
          const drained = (prev.flowRateGPM / 60) * 0.5; // per 500ms tick
          const newVol = Math.max(0, prev.jugVolumeGallons - drained);
          const stillFlowing = newVol > 0;
          return {
            ...prev,
            jugVolumeGallons: newVol,
            isFlowing: stillFlowing,
            flowRateGPM: stillFlowing ? prev.flowRateGPM : 0,
            elapsedSeconds: prev.elapsedSeconds + 0.5,
          };
        });
      }, 500);
    } else {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    }
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [state.isFlowing]);

  return {
    state,
    config: cfg,
    setColumnHeight,
    toggleFlow,
    toggleTelescopingLegs,
    refillJug,
  };
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface TreasuryTransaction {
  id: string;
  group_type: "guild" | "tribe";
  group_id: string;
  user_id: string | null;
  transaction_type: string;
  amount: number;
  direction: "in" | "out";
  description: string | null;
  approved_by: string | null;
  vote_id: string | null;
  created_at: string;
}

export function useTreasury(groupType: "guild" | "tribe", groupId: string | undefined) {
  return useQuery({
    queryKey: ["treasury", groupType, groupId],
    queryFn: async () => {
      if (!groupId) return [];
      const { data, error } = await supabase
        .from("group_treasury_transactions" as any)
        .select("*")
        .eq("group_type", groupType)
        .eq("group_id", groupId)
        .order("created_at", { ascending: false })
        .limit(50);
      if (error) throw error;
      return (data ?? []) as TreasuryTransaction[];
    },
    enabled: !!groupId,
  });
}

export function useContribute() {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async ({
      groupType,
      groupId,
      amount,
      description,
    }: {
      groupType: "guild" | "tribe";
      groupId: string;

      amount: number;
      description?: string;
    }) => {
      if (!user) throw new Error("Must be logged in");
      if (amount <= 0) throw new Error("Amount must be positive");

      const { data, error } = await supabase
        .from("group_treasury_transactions" as any)
        .insert({
          group_type: groupType,
          group_id: groupId,
          user_id: user.id,
          transaction_type: "contribution",
          amount,
          direction: "in",
          description: description || "Member contribution",
        })
        .select()
        .single();
      if (error) throw error;

      const table = groupType === "guild" ? "guilds" : "tribes";
      await supabase.rpc("increment_field" as any, {
        table_name: table,
        row_id: groupId,
        field_name: "treasury_credits",
        increment_by: amount,
      }).then(() => {}).catch(() => {
        // Fallback: direct update if RPC doesn't exist
      });

      return data as TreasuryTransaction;
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ["treasury", vars.groupType, vars.groupId] });
      queryClient.invalidateQueries({
        queryKey: [vars.groupType === "guild" ? "guild" : "tribe"],
      });
    },
  });
}

export function useRequestSpend() {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async ({
      groupType,
      groupId,

      amount,
      transactionType,
      description,
    }: {
      groupType: "guild" | "tribe";
      groupId: string;
      amount: number;
      transactionType: "contest_prize" | "purchase" | "bounty" | "event";
      description: string;
    }) => {
      if (!user) throw new Error("Must be logged in");

      const { data, error } = await supabase
        .from("group_treasury_transactions" as any)
        .insert({
          group_type: groupType,
          group_id: groupId,
          user_id: user.id,
          transaction_type: transactionType,
          amount,
          direction: "out",
          description,
        })
        .select()
        .single();
      if (error) throw error;
      return data as TreasuryTransaction;
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ["treasury", vars.groupType, vars.groupId] });
    },
  });
}

import { useEffect, useMemo, useReducer } from "react";

export const GUIDED_TOUR_STORAGE_KEY = "lb_guided_tour_state_v1";

export type TourMode = "idle" | "intro" | "running" | "completed" | "skipped";

export type TourStop = {
  id: string;
