};

type TourState = {
  mode: TourMode;
  currentStopIndex: number;
  stops: TourStop[];
};

type TourAction =
  | { type: "OPEN_INTRO" }
  | { type: "START" }
  | { type: "NEXT" }
  | { type: "BACK" }
  | { type: "SKIP" }
  | { type: "COMPLETE" }
  | { type: "RESET" };

