  body: string | null;
  fire_at: string;
  channel: "email" | "sms" | "in_app" | "all";
  priority_tier: number;
  state: "pending" | "fired" | "snoozed" | "completed" | "cancelled" | "failed";
  source_kind: string | null;
  source_ref: string | null;
  hemispheric_aware: boolean;
  created_at: string;
  updated_at: string;
  fired_at: string | null;
  completed_at: string | null;
  metadata: Record<string, unknown>;
}

export function useHelmTasks(memberId: string | undefined) {
  const [tasks, setTasks] = useState<HelmTask[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!memberId) return;

    let mounted = true;

    const load = async () => {
      const { data, error } = await (supabase
        .from("helm_tasks" as never)
        .select("*") as any)
        .eq("member_id", memberId)
        .in("state", ["pending", "snoozed", "fired"])
        .order("fire_at", { ascending: true });

      if (mounted && !error) {
        setTasks((data || []) as HelmTask[]);
        setLoading(false);

      }
    };

    load();

    const channel = supabase
      .channel(`helm_tasks:${memberId}`)
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "helm_tasks",
          filter: `member_id=eq.${memberId}`,
        },
        () => load(),
      )
      .subscribe();

    return () => {
      mounted = false;
      supabase.removeChannel(channel);
    };
  }, [memberId]);

  const createTask = async (
    task: Partial<HelmTask> & { title: string; fire_at: string },
  ) => {
    const { data, error } = await (supabase
      .from("helm_tasks" as never)
      .insert({ member_id: memberId, ...task } as never) as any)
      .select()
      .single();
    return { data: data as HelmTask | null, error };
  };

  const completeTask = async (task_id: string) => {
    return (supabase
      .from("helm_tasks" as never)
      .update({
        state: "completed",
        completed_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      } as never) as any)
      .eq("task_id", task_id);
  };

  const cancelTask = async (task_id: string) => {
    return (supabase
      .from("helm_tasks" as never)

      .update({
        state: "cancelled",
        updated_at: new Date().toISOString(),
      } as never) as any)
      .eq("task_id", task_id);
  };

  const snoozeTask = async (task_id: string, hours: number) => {
    const newFireAt = new Date(Date.now() + hours * 3600 * 1000).toISOString();
    return (supabase
      .from("helm_tasks" as never)
      .update({
        state: "pending",
        fire_at: newFireAt,
        updated_at: new Date().toISOString(),
      } as never) as any)
      .eq("task_id", task_id);
  };

  return { tasks, loading, createTask, completeTask, cancelTask, snoozeTask };
}

/**
