/**
 * useHydraulictoPneumaticPlantSystem
 * ====================================
 * MISS-005 — Hydraulic-to-Pneumatic Plant System
 * Wave 2 / Old One: urIm / Bushel 29 (BP025)
 *
 * Depends on MISS-001 (Inverse Hydraulic Coupling).
 * Water pressure at the Hexel base converts to air pressure for above-water
 * plant mechanisms. Differential pressure seal at 5mm lift point enables
 * pneumatic actuation without external pumps.
 */

import { useState, useCallback, useEffect, useRef } from 'react';

// ── Interfaces ────────────────────────────────────────────────────────────────

export interface InverseHydraulicInterface {
  /** Piston A displacement in mm (positive = extended) */
  pistonADisplacementMm: number;
  /** Piston B displacement in mm (inverse of A) */
  pistonBDisplacementMm: number;
  /** System water pressure in psi */
  waterPressurePsi: number;
  /** Daisy-chain linkage active */
  linkageActive: boolean;
}

export interface PneumaticActuationState {
  /** Air pressure produced above the seal (psi) */
  airPressurePsi: number;
  /** Seal lift height in mm (threshold: 5mm) */
  sealLiftMm: number;
  /** Whether pneumatic actuation is engaged */
  actuationEngaged: boolean;
  /** Plant mechanism angle (0–90°) driven by air pressure */
  plantMechanismAngleDeg: number;
}

export interface HydraulictoPneumaticState {
  inverse: InverseHydraulicInterface;
  pneumatic: PneumaticActuationState;
  /** Simulation running */
  running: boolean;
  /** Elapsed simulation ticks */
  tick: number;
  /** Log of key events */
  eventLog: string[];
}

// ── Constants ─────────────────────────────────────────────────────────────────

const SEAL_LIFT_THRESHOLD_MM = 5;
const WATER_PRESSURE_TO_AIR_RATIO = 0.72; // empirical conversion factor for 5mm seal
const MAX_PLANT_ANGLE_DEG = 90;

// ── Hook ──────────────────────────────────────────────────────────────────────

export function useHydraulictoPneumaticPlantSystem() {
  const [state, setState] = useState<HydraulictoPneumaticState>({
    inverse: {
      pistonADisplacementMm: 0,
      pistonBDisplacementMm: 0,
      waterPressurePsi: 1.3, // baseline from PHYSICS.operatingPressure
      linkageActive: false,
    },
    pneumatic: {
      airPressurePsi: 0,
      sealLiftMm: 0,
      actuationEngaged: false,
      plantMechanismAngleDeg: 0,
    },
    running: false,
    tick: 0,
    eventLog: [],
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const addLog = useCallback((msg: string) => {
    setState(prev => ({
      ...prev,
      eventLog: [`[T${prev.tick}] ${msg}`, ...prev.eventLog].slice(0, 30),
    }));
  }, []);

  /** Drive piston A manually (simulates inverse hydraulic input) */
  const drivePistonA = useCallback((displacementMm: number) => {
    setState(prev => {
      const pistonB = -displacementMm; // inverse coupling
      const linkageActive = Math.abs(displacementMm) > 0.5;
      // Seal lift is proportional to net piston displacement
      const sealLiftMm = Math.min(Math.abs(displacementMm) * 0.6, 12);
      const actuationEngaged = sealLiftMm >= SEAL_LIFT_THRESHOLD_MM;
      const airPressurePsi = actuationEngaged
        ? prev.inverse.waterPressurePsi * WATER_PRESSURE_TO_AIR_RATIO * (sealLiftMm / SEAL_LIFT_THRESHOLD_MM)
        : 0;
      const plantMechanismAngleDeg = Math.min(
        (airPressurePsi / (prev.inverse.waterPressurePsi * WATER_PRESSURE_TO_AIR_RATIO)) * MAX_PLANT_ANGLE_DEG,
        MAX_PLANT_ANGLE_DEG,
      );

      return {
        ...prev,
        inverse: {
          ...prev.inverse,
          pistonADisplacementMm: displacementMm,
          pistonBDisplacementMm: pistonB,
          linkageActive,
        },
        pneumatic: {
          airPressurePsi,
          sealLiftMm,
          actuationEngaged,
          plantMechanismAngleDeg,
        },
      };
    });
  }, []);

  /** Set base water pressure (psi) */
  const setWaterPressure = useCallback((psi: number) => {
    setState(prev => ({ ...prev, inverse: { ...prev.inverse, waterPressurePsi: psi } }));
  }, []);

  /** Toggle auto simulation */
  const toggleSimulation = useCallback(() => {
    setState(prev => ({ ...prev, running: !prev.running }));
  }, []);

  const reset = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    setState(prev => ({
      ...prev,
      running: false,
      tick: 0,
      inverse: { pistonADisplacementMm: 0, pistonBDisplacementMm: 0, waterPressurePsi: 1.3, linkageActive: false },
      pneumatic: { airPressurePsi: 0, sealLiftMm: 0, actuationEngaged: false, plantMechanismAngleDeg: 0 },
      eventLog: [],
    }));
  }, []);

  // Auto-simulation tick
  useEffect(() => {
    if (!state.running) {
      if (intervalRef.current) clearInterval(intervalRef.current);
      return;
    }
    intervalRef.current = setInterval(() => {
      setState(prev => {
        const t = prev.tick + 1;

        const wave = Math.sin(t * 0.18) * 8; // oscillating piston drive
        const pistonB = -wave;
        const sealLiftMm = Math.min(Math.abs(wave) * 0.6, 12);
        const actuationEngaged = sealLiftMm >= SEAL_LIFT_THRESHOLD_MM;
        const airPressurePsi = actuationEngaged
          ? prev.inverse.waterPressurePsi * WATER_PRESSURE_TO_AIR_RATIO * (sealLiftMm / SEAL_LIFT_THRESHOLD_MM)
          : 0;
        const plantMechanismAngleDeg = Math.min(
          (airPressurePsi / (prev.inverse.waterPressurePsi * WATER_PRESSURE_TO_AIR_RATIO)) * MAX_PLANT_ANGLE_DEG,
          MAX_PLANT_ANGLE_DEG,
        );

        const newLog = actuationEngaged && !prev.pneumatic.actuationEngaged
          ? [`[T${t}] Pneumatic seal engaged at ${sealLiftMm.toFixed(1)}mm lift`, ...prev.eventLog]
          : !actuationEngaged && prev.pneumatic.actuationEngaged
          ? [`[T${t}] Seal released — plant retracts`, ...prev.eventLog]
          : prev.eventLog;

        return {
          ...prev,
          tick: t,
          inverse: { ...prev.inverse, pistonADisplacementMm: wave, pistonBDisplacementMm: pistonB, linkageActive: Math.abs(wave) > 0.5 },
          pneumatic: { airPressurePsi, sealLiftMm, actuationEngaged, plantMechanismAngleDeg },
          eventLog: newLog.slice(0, 30),
        };
      });
    }, 120);
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [state.running]);

  return {
    state,
    drivePistonA,
    setWaterPressure,
    toggleSimulation,
    reset,
    SEAL_LIFT_THRESHOLD_MM,
  };
}

import { useState, useCallback, useRef, useEffect } from 'react';

// MISS-001 — Inverse Hydraulic Coupling (#2)
// When piston A moves, piston B moves opposite direction.
// Daisy chain linkage enables bidirectional pressure propagation
// through Hexel water channel network.

export type PistonDirection = 'up' | 'down' | 'neutral';

export interface Piston {
  id: string;
  label: string;
  positionMm: number;     // -20 to +20mm from center
  direction: PistonDirection;
  pressureBar: number;    // 0–1.5 bar
  velocityMmPerS: number; // mm per second
  isActive: boolean;
}

export interface CouplingLink {
  fromId: string;
  toId: string;
  transmissionRatio: number; // typically -1.0 for inverse
  linkPressureBar: number;
}

export interface InverseHydraulicState {
  pistons: Piston[];
  links: CouplingLink[];
  daisyChainDepth: number;   // how many pistons in chain
  propagationCycleMs: number; // time for pressure to propagate chain
  totalPressureWork: number;  // cumulative bar·mm
  cycleCount: number;
  gameTurn: number;
  isRunning: boolean;
  tickMs: number;
  activePistonId: string;    // which piston is driven this step
}

export interface InverseHydraulicControls {
  start: () => void;
  pause: () => void;
  reset: () => void;
  tick: () => void;
  pushPiston: (id: string) => void;
  setTickMs: (ms: number) => void;
}

function buildPistons(count = 5): Piston[] {
  return Array.from({ length: count }, (_, i) => ({

    id: `P${i + 1}`,
    label: String.fromCharCode(65 + i), // A, B, C, D, E
    positionMm: 0,
    direction: 'neutral',
    pressureBar: 0,
    velocityMmPerS: 0,
    isActive: false,
  }));
}

function buildLinks(pistons: Piston[]): CouplingLink[] {
  return pistons.slice(0, -1).map((p, i) => ({
    fromId: p.id,
    toId: pistons[i + 1].id,
    transmissionRatio: -1.0, // inverse coupling
    linkPressureBar: 0,
  }));
}

export function useInverseHydraulicCoupling(initialTickMs = 500): {
  state: InverseHydraulicState;
  controls: InverseHydraulicControls;
} {
  const pistonBase = buildPistons(5);

  const [state, setState] = useState<InverseHydraulicState>({
    pistons: pistonBase,
    links: buildLinks(pistonBase),
    daisyChainDepth: 5,
    propagationCycleMs: 2500,
    totalPressureWork: 0,
    cycleCount: 0,
    gameTurn: 0,
    isRunning: false,
    tickMs: initialTickMs,
    activePistonId: 'P1',
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const tick = useCallback(() => {
    setState(prev => {
      // Advance which piston is driven (oscillate P1 up/down)
      const cycleCount = prev.cycleCount + 1;
      const gameTurn = Math.floor(cycleCount / 12);
      const driveUp = cycleCount % 2 === 0;
      const driveAmp = 18; // mm

      const pistons = prev.pistons.map((p, i) => {
        // Each piston is inverse of the one before it in chain

        const sign = driveUp ? (i % 2 === 0 ? 1 : -1) : (i % 2 === 0 ? -1 : 1);
        const decay = Math.pow(0.85, i); // pressure decays along chain
        const pos = parseFloat((driveAmp * sign * decay).toFixed(2));
        const direction: PistonDirection = pos > 0.5 ? 'up' : pos < -0.5 ? 'down' : 'neutral';
        const pressureBar = parseFloat((Math.abs(pos) / driveAmp * 1.3 * decay).toFixed(3));
        return { ...p, positionMm: pos, direction, pressureBar, velocityMmPerS: Math.abs(pos) * 2, isActive: true };
      });

      const links = prev.links.map((l, i) => ({
        ...l,
        linkPressureBar: parseFloat(((pistons[i].pressureBar + pistons[i + 1].pressureBar) / 2).toFixed(3)),
      }));

      const totalPressureWork = parseFloat(
        (prev.totalPressureWork + pistons.reduce((sum, p) => sum + Math.abs(p.positionMm) * p.pressureBar, 0) / 100).toFixed(3)
      );

      return { ...prev, pistons, links, cycleCount, gameTurn, totalPressureWork };
    });
  }, []);

  const pushPiston = useCallback((id: string) => {
    setState(prev => ({
      ...prev,
      activePistonId: id,
    }));
    tick();
  }, [tick]);

  const start = useCallback(() => setState(prev => ({ ...prev, isRunning: true })), []);
  const pause = useCallback(() => setState(prev => ({ ...prev, isRunning: false })), []);

  const reset = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    const pistonBase = buildPistons(5);
    setState(prev => ({
      ...prev,
      pistons: pistonBase,
      links: buildLinks(pistonBase),
      totalPressureWork: 0,
      cycleCount: 0,
      gameTurn: 0,
      isRunning: false,
      activePistonId: 'P1',
    }));
  }, []);

  const setTickMs = useCallback((ms: number) => {
    setState(prev => ({ ...prev, tickMs: ms }));
  }, []);

  useEffect(() => {
    if (state.isRunning) {
      intervalRef.current = setInterval(tick, state.tickMs);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [state.isRunning, state.tickMs, tick]);

  return { state, controls: { start, pause, reset, tick, pushPiston, setTickMs } };
}

