      const { data, error } = await (supabase as any)
        .from("bounties")
        .select("*")
        .eq("campaign_id", campaignId)
        .eq("status", "open")
        .order("created_at", { ascending: false })
        .limit(5);
      if (error) return [];
      return data ?? [];
    },
    enabled: !!campaignId,
  });
}

