import { useState, useCallback } from 'react';

// STUB-005 — Lithographic Dual-Process Design (#28)
// Two-step lithographic production.
// Step 1: mold impression (pattern layer).
// Step 2: material casting (functional layer).
// Each step can use different materials.
// Enables complex pattern/color combinations without painting.

export type ProcessStep = 'idle' | 'mold_prep' | 'pattern_layer' | 'cure_pattern' | 'material_cast' | 'cure_functional' | 'demold' | 'complete';
export type MaterialType = 'resin_standard' | 'resin_flexible' | 'resin_rigid' | 'polymer_clear' | 'polymer_tinted' | 'nylon_sls';
export type PatternType = 'hexel_base' | 'terrain_surface' | 'channel_lock' | 'character_detail' | 'text_glyph';

export interface LithographicLayer {
  type: 'pattern' | 'functional';
  material: MaterialType;
  pattern: PatternType;
  thicknessMm: number;
  cureTimeMinutes: number;
  isComplete: boolean;
  qualityScore: number;  // 0–100
}

export interface LithographicDualProcessState {
  currentStep: ProcessStep;
  stepProgress: number;          // 0–1
  patternLayer: LithographicLayer | null;
  functionalLayer: LithographicLayer | null;
  selectedPatternMaterial: MaterialType;
  selectedFunctionalMaterial: MaterialType;
  selectedPattern: PatternType;
  moldTemperatureC: number;
  completedPieces: number;
  successRate: number;           // 0–1
  defectCount: number;
  totalProcessTimeMinutes: number;
  isMoldReady: boolean;
}

export interface LithographicControls {
  startProcess: () => void;
  advanceStep: () => void;
  setPatternMaterial: (m: MaterialType) => void;
  setFunctionalMaterial: (m: MaterialType) => void;
  setPattern: (p: PatternType) => void;
  reset: () => void;
}

const STEP_ORDER: ProcessStep[] = [
  'idle', 'mold_prep', 'pattern_layer', 'cure_pattern',

  'material_cast', 'cure_functional', 'demold', 'complete',
];

const MATERIAL_CURE_TIME: Record<MaterialType, number> = {
  resin_standard: 15,
  resin_flexible: 20,
  resin_rigid: 12,
  polymer_clear: 25,
  polymer_tinted: 25,
  nylon_sls: 40,
};

const MATERIAL_QUALITY: Record<MaterialType, number> = {
  resin_standard: 82,
  resin_flexible: 75,
  resin_rigid: 91,
  polymer_clear: 88,
  polymer_tinted: 85,
  nylon_sls: 95,
};

export function useLithographicDualProcess(): {
  state: LithographicDualProcessState;
  controls: LithographicControls;
} {
  const [state, setState] = useState<LithographicDualProcessState>({
    currentStep: 'idle',
    stepProgress: 0,
    patternLayer: null,
    functionalLayer: null,
    selectedPatternMaterial: 'resin_standard',
    selectedFunctionalMaterial: 'polymer_tinted',
    selectedPattern: 'hexel_base',
    moldTemperatureC: 22,
    completedPieces: 0,
    successRate: 0.94,
    defectCount: 0,
    totalProcessTimeMinutes: 0,
    isMoldReady: false,
  });

  const advanceStep = useCallback(() => {
    setState(prev => {
      const currentIdx = STEP_ORDER.indexOf(prev.currentStep);
      if (currentIdx >= STEP_ORDER.length - 1) return prev;
      const nextStep = STEP_ORDER[currentIdx + 1];

      let patternLayer = prev.patternLayer;
      let functionalLayer = prev.functionalLayer;
      let completedPieces = prev.completedPieces;

      let defectCount = prev.defectCount;
      let totalProcessTimeMinutes = prev.totalProcessTimeMinutes;
      let isMoldReady = prev.isMoldReady;

      if (nextStep === 'pattern_layer') {
        patternLayer = {
          type: 'pattern',
          material: prev.selectedPatternMaterial,
          pattern: prev.selectedPattern,
          thicknessMm: 0.8,
          cureTimeMinutes: MATERIAL_CURE_TIME[prev.selectedPatternMaterial],
          isComplete: false,
          qualityScore: MATERIAL_QUALITY[prev.selectedPatternMaterial],
        };
      }
      if (nextStep === 'cure_pattern' && patternLayer) {
        patternLayer = { ...patternLayer, isComplete: true };
        totalProcessTimeMinutes += patternLayer.cureTimeMinutes;
      }
      if (nextStep === 'material_cast') {
        functionalLayer = {
          type: 'functional',
          material: prev.selectedFunctionalMaterial,
          pattern: prev.selectedPattern,
          thicknessMm: 2.4,
          cureTimeMinutes: MATERIAL_CURE_TIME[prev.selectedFunctionalMaterial],
          isComplete: false,
          qualityScore: MATERIAL_QUALITY[prev.selectedFunctionalMaterial],
        };
        isMoldReady = true;
      }
      if (nextStep === 'cure_functional' && functionalLayer) {
        functionalLayer = { ...functionalLayer, isComplete: true };
        totalProcessTimeMinutes += functionalLayer.cureTimeMinutes;
      }
      if (nextStep === 'complete') {
        const isSuccess = Math.random() < prev.successRate;
        completedPieces = isSuccess ? prev.completedPieces + 1 : prev.completedPieces;
        defectCount = isSuccess ? prev.defectCount : prev.defectCount + 1;
      }

      const stepProgress = nextStep === 'complete' ? 1 : (currentIdx + 1) / (STEP_ORDER.length - 1);

      return {
        ...prev,
        currentStep: nextStep,
        stepProgress,
        patternLayer,
        functionalLayer,
        completedPieces,

        defectCount,
        totalProcessTimeMinutes,
        isMoldReady,
        moldTemperatureC: Math.round(22 + Math.random() * 3),
      };
    });
  }, []);

  const startProcess = useCallback(() => {
    setState(prev => ({ ...prev, currentStep: 'mold_prep', stepProgress: 0.1, isMoldReady: false }));
  }, []);

  const setPatternMaterial = useCallback((m: MaterialType) => {
    setState(prev => ({ ...prev, selectedPatternMaterial: m }));
  }, []);

  const setFunctionalMaterial = useCallback((m: MaterialType) => {
    setState(prev => ({ ...prev, selectedFunctionalMaterial: m }));
  }, []);

  const setPattern = useCallback((p: PatternType) => {
    setState(prev => ({ ...prev, selectedPattern: p }));
  }, []);

  const reset = useCallback(() => {
    setState(prev => ({
      ...prev,
      currentStep: 'idle',
      stepProgress: 0,
      patternLayer: null,
      functionalLayer: null,
      isMoldReady: false,
      moldTemperatureC: 22,
    }));
  }, []);

  return { state, controls: { startProcess, advanceStep, setPatternMaterial, setFunctionalMaterial, setPattern, reset } };
}

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

type Tier = 'bounty_hunter' | 'contractor' | 'senior_contractor' | 'partner' | 'senior_partner';

interface TierThreshold {
  marks: number;
  tier: Tier;
  label: string;
  benefits: string[];
}

const TIERS: TierThreshold[] = [
  { marks: 0, tier: 'bounty_hunter', label: 'Bounty Hunter', benefits: ['Access to open bounties', 'Kit eligibility'] },
  { marks: 500, tier: 'contractor', label: 'Contractor', benefits: ['1.5x multiplier', 'Priority bounty access'] },
  { marks: 1000, tier: 'senior_contractor', label: 'Senior Contractor', benefits: ['1.75x multiplier', 'Bench equipment eligibility'] },
  { marks: 2000, tier: 'partner', label: 'Partner', benefits: ['2.0x multiplier', 'Revenue share', 'Node eligibility', 'IP Ledger entry'] },
  { marks: 5000, tier: 'senior_partner', label: 'Senior Partner', benefits: ['2.5x multiplier', 'Factory Node eligibility', 'Governance vote'] },
];

const MULTIPLIERS: Record<Tier, number> = {
  bounty_hunter: 1.0,
  contractor: 1.5,
  senior_contractor: 1.75,
  partner: 2.0,
  senior_partner: 2.5,
};

function resolveTier(marks: number): TierThreshold {
  for (let i = TIERS.length - 1; i >= 0; i--) {
    if (marks >= TIERS[i].marks) return TIERS[i];
  }
  return TIERS[0];
}

function resolveNext(marks: number): TierThreshold | null {
  for (const t of TIERS) {
    if (marks < t.marks) return t;
  }
  return null;
}

export interface ManufacturingStatus {
  aggregateMarks: number;
  currentTier: Tier;
  currentTierLabel: string;
  multiplier: number;
  nextThreshold: { marks: number; tier: string; benefits: string[] } | null;

  bountiesCompleted: number;
  bountiesInProgress: number;
  totalEarned: number;
  isEligibleForEquipment: (level: 1 | 2 | 3 | 4) => boolean;
  isLoading: boolean;
}

export function useManufacturingStatus(): ManufacturingStatus {
  const { user } = useAuth();

  const { data, isLoading } = useQuery({
    queryKey: ['manufacturing-status', user?.id],
    enabled: !!user,
    queryFn: async () => {
      const uid = user!.id;

      const [statsRes, bountiesRes] = await Promise.all([
        supabase
          .from('xray_daily_stats' as never)
          .select('marks_earned')
          .eq('user_id', uid) as { data: { marks_earned: number }[] | null; error: unknown },
        supabase
          .from('bounties' as never)
          .select('status, reward_amount')
          .eq('claimed_by', uid) as { data: { status: string; reward_amount: number }[] | null; error: unknown },
      ]);

      const totalMarks = (statsRes.data ?? []).reduce((s, r) => s + (r.marks_earned ?? 0), 0);
      const bounties = bountiesRes.data ?? [];
      const completed = bounties.filter(b => b.status === 'completed').length;
      const inProgress = bounties.filter(b => b.status === 'in_progress').length;
      const earned = bounties.filter(b => b.status === 'completed').reduce((s, b) => s + (b.reward_amount ?? 0), 0);

      return { totalMarks, completed, inProgress, earned };
    },
    staleTime: 2 * 60 * 1000,
  });

  const marks = data?.totalMarks ?? 0;
  const tier = resolveTier(marks);
  const next = resolveNext(marks);

  const isEligibleForEquipment = useMemo(() => {
    return (level: 1 | 2 | 3 | 4) => {
      const thresholds = [0, 500, 2000, 5000];
      return marks >= thresholds[level - 1];
    };
  }, [marks]);

  return {

    aggregateMarks: marks,
    currentTier: tier.tier,
    currentTierLabel: tier.label,
    multiplier: MULTIPLIERS[tier.tier],
    nextThreshold: next ? { marks: next.marks, tier: next.label, benefits: next.benefits } : null,
    bountiesCompleted: data?.completed ?? 0,
    bountiesInProgress: data?.inProgress ?? 0,
    totalEarned: data?.earned ?? 0,
    isEligibleForEquipment,
    isLoading,
  };
}

export { TIERS, MULTIPLIERS, resolveTier, resolveNext };
export type { Tier, TierThreshold };

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

const MILESTONES = [1, 10, 25, 50, 75, 100, 250, 500, 1000] as const;
const LS_KEY = 'marks_milestone_last_shown';

export interface CategoryBreakdown {
  category: string;
  total: number;
}

const CATEGORY_EMOJI: Record<string, string> = {
  photography: '📸',
  bounty_photo: '📸',
  pearl_diver: '🐚',
  deals: '🐚',
  scouting: '🐚',
  feedback: '✍️',
  cooking: '🍳',
  food: '🍳',
  teaching: '📚',
  classroom: '📚',
  general: '⭐',
  backing: '🏗️',
  campaign: '📢',
  delivery: '🚗',
  tour_package_completion: '🎒',
  captain: '⚓',
  coordination: '⚓',
};

export function getCategoryEmoji(cat: string): string {
  return CATEGORY_EMOJI[cat] || '⭐';
}

export function useMarksMilestone() {
  const { user } = useAuth();

  const { data, isLoading } = useQuery({
    queryKey: ['marks-milestone', user?.id ?? 'anon'],
    queryFn: async () => {
      if (!user) return { totalMarks: 0, categories: [] as CategoryBreakdown[] };

      const { data: rows, error } = await supabase
        .from('mark_work_records' as never)
        .select('marks_earned, category, work_type')
        .eq('user_id', user.id) as {
          data: Array<{ marks_earned: number; category: string | null; work_type: string | null }> | null;
          error: unknown;

        };
      if (error) throw error;

      let totalMarks = 0;
      const catMap: Record<string, number> = {};

      for (const row of rows ?? []) {
        totalMarks += row.marks_earned || 0;
        const cat = row.category || row.work_type || 'general';
        catMap[cat] = (catMap[cat] || 0) + (row.marks_earned || 0);
      }

      const categories: CategoryBreakdown[] = Object.entries(catMap)
        .map(([category, total]) => ({ category, total }))
        .sort((a, b) => b.total - a.total);

      return { totalMarks, categories };
    },
    staleTime: 30_000,
    enabled: !!user,
  });

  const totalMarks = data?.totalMarks ?? 0;
  const categories = data?.categories ?? [];
  const primaryCategory = categories[0]?.category || 'general';

  const lastShown = typeof window !== 'undefined'
    ? parseInt(localStorage.getItem(LS_KEY) || '0', 10)
    : 0;

  const currentMilestone = [...MILESTONES]
    .reverse()
    .find(m => totalMarks >= m) ?? 0;

  const showMilestone = currentMilestone > 0 && currentMilestone > lastShown;

  const nextMilestone = MILESTONES.find(m => m > totalMarks) ?? 1000;
  const progressTo100 = Math.min(totalMarks, 100);

  function dismiss() {
    if (currentMilestone > 0) {
      localStorage.setItem(LS_KEY, String(currentMilestone));
    }
  }

  return {
    totalMarks,
    categories,
    primaryCategory,
    showMilestone,

    currentMilestone,
    nextMilestone,
    progressTo100,
    isPrizePanel: currentMilestone >= 100,
    isLoading,
    dismiss,
  };
}

/**
 * useMarksPaybackProgress — K151 Marks Payback dashboard hook
 * Queries Marks earned in the current membership year to show
 * progress toward the 100-Mark free-renewal threshold.
 *
 * K157 fix: aligned with actual transaction_ledger schema
 * (payee_id/payer_id, amount_cents, currency, status).
 */

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface MarksPaybackProgress {
  marksEarned: number;
  qualifies: boolean;
  creditBalance: number;
  renewalDate: string | null;
}

export function useMarksPaybackProgress() {
  const { user } = useAuth();

  return useQuery({
    queryKey: ["marks-payback-progress", user?.id],
    queryFn: async (): Promise<MarksPaybackProgress> => {
      if (!user) return { marksEarned: 0, qualifies: false, creditBalance: 0, renewalDate: null };

      const { data: membership } = await supabase
        .from("membership_subscriptions")
        .select("current_period_end, current_period_start")
        .eq("user_id", user.id)
        .eq("status", "active")
        .single();

      const renewalDate = membership?.current_period_end || null;
      const yearStart = membership?.current_period_start
        || new Date(Date.now() - 365 * 24 * 60 * 60 * 1000).toISOString();

      // Marks earned = rows where user is payee, currency=marks, status=completed
      const { count } = await supabase
        .from("transaction_ledger" as never)
        .select("*", { count: "exact", head: true })
        .eq("payee_id", user.id)
        .eq("currency", "marks")
        .eq("status", "completed")
        .gte("created_at", yearStart);

      const marksEarned = count || 0;

      // Credit balance = sum(payee amounts) - sum(payer amounts) in cents
      const { data: creditRows } = await supabase
        .from("transaction_ledger" as never)
        .select("amount_cents, payer_id, payee_id")
        .or(`payer_id.eq.${user.id},payee_id.eq.${user.id}`)
        .eq("currency", "credits")
        .eq("status", "completed");

      let balanceCents = 0;
      for (const row of (creditRows || []) as { amount_cents: number; payer_id: string; payee_id: string }[]) {
        if (row.payee_id === user.id) balanceCents += row.amount_cents || 0;
        if (row.payer_id === user.id) balanceCents -= row.amount_cents || 0;
      }
      const creditBalance = balanceCents / 100;

      return {
        marksEarned,
        qualifies: marksEarned >= 100 && creditBalance >= 5,
        creditBalance,
        renewalDate,
      };
    },
    enabled: !!user,
    staleTime: 5 * 60 * 1000,
  });
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export type DayOfWeek = "mon" | "tue" | "wed" | "thu" | "fri" | "sat" | "sun";
export type MealType = "breakfast" | "lunch" | "dinner";
export type MealSource = "home" | "restaurant" | "grocery";

export interface MealSlot {
  day: DayOfWeek;
  meal_type: MealType;
  source: MealSource;
  restaurant_id?: string;
  restaurant_name?: string;
  menu_items?: { id: string; name: string; quantity: number; price: number }[];
  scheduled_pickup_time?: string;
  servings: number;
  recipe_id?: string;
  recipe_name?: string;
  estimated_cost: number;
  discount_tier?: string;
}

export interface MealPlan {
  id: string;
  user_id: string;
  week_start: string;
  meals: MealSlot[];
  submitted: boolean;
  total_estimated_cost: number;
  total_savings: number;
  created_at: string;
  updated_at: string;
}

const DAYS: DayOfWeek[] = ["mon", "tue", "wed", "thu", "fri", "sat", "sun"];
const DAY_LABELS: Record<DayOfWeek, string> = {
  mon: "Monday",
  tue: "Tuesday",
  wed: "Wednesday",
  thu: "Thursday",
  fri: "Friday",
  sat: "Saturday",
  sun: "Sunday",
};

export { DAYS, DAY_LABELS };

function getWeekStart(date: Date = new Date()): string {
  const d = new Date(date);

  const day = d.getDay();
  const diff = d.getDate() - day + (day === 0 ? -6 : 1);
  d.setDate(diff);
  return d.toISOString().split("T")[0];
}

export { getWeekStart };

export function useMealPlan(weekStart?: string) {
  const { user } = useAuth();
  const week = weekStart ?? getWeekStart();

  return useQuery({
    queryKey: ["meal-plan", user?.id, week],
    enabled: !!user,
    queryFn: async () => {
      const { data, error } = await (supabase
        .from("meal_plans" as never)
        .select("*")
        .eq("user_id", user!.id)
        .eq("week_start", week)
        .maybeSingle() as unknown as Promise<{ data: MealPlan | null; error: unknown }>);

      if (error) return null;
      if (data) {
        return {
          ...data,
          meals: (typeof data.meals === "string" ? JSON.parse(data.meals) : data.meals) as MealSlot[],
        } as MealPlan;
      }
      return null;
    },
  });
}

export function useSaveMealPlan() {
  const { user } = useAuth();
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (plan: { week_start: string; meals: MealSlot[] }) => {
      if (!user) throw new Error("Not authenticated");

      const totalCost = plan.meals.reduce((s, m) => s + m.estimated_cost, 0);
      const totalSavings = plan.meals.reduce((s, m) => {
        if (m.source === "restaurant" && m.menu_items) {
          const retail = m.menu_items.reduce((a, i) => a + i.price * i.quantity, 0);
          return s + (retail - m.estimated_cost);
        }
        return s;

      }, 0);

      const { data, error } = await (supabase
        .from("meal_plans" as never)
        .upsert(
          {
            user_id: user.id,
            week_start: plan.week_start,
            meals: JSON.stringify(plan.meals),
            total_estimated_cost: Math.round(totalCost * 100) / 100,
            total_savings: Math.round(totalSavings * 100) / 100,
            updated_at: new Date().toISOString(),
          },
          { onConflict: "user_id,week_start" }
        )
        .select()
        .single() as unknown as Promise<{ data: MealPlan | null; error: unknown }>);

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["meal-plan"] });
    },
  });
}

export function useSubmitMealPlan() {
  const { user } = useAuth();
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (planId: string) => {
      if (!user) throw new Error("Not authenticated");

      const { error } = await (supabase
        .from("meal_plans" as never)
        .update({ submitted: true })
        .eq("id", planId)
        .eq("user_id", user.id) as unknown as Promise<{ error: unknown }>);

      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["meal-plan"] });
      qc.invalidateQueries({ queryKey: ["scheduled-orders"] });
    },
  });
}

import { useQuery, useMutation } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export type MembershipTier = "free" | "member" | "builder" | "patron";

export interface MembershipSubscription {
  tier: MembershipTier;
  status: string;
  price_usd: number | null;
  current_period_end: string | null;
  cancel_at_period_end: boolean;
  stripe_customer_id: string | null;
}

export function useMembership() {
  const { user } = useAuth();
  return useQuery({
    queryKey: ["membership-subscription", user?.id],
    queryFn: async (): Promise<MembershipSubscription> => {
      if (!user) return { tier: "free", status: "none", price_usd: null, current_period_end: null, cancel_at_period_end: false, stripe_customer_id: null };

      const { data, error } = await supabase
        .from("membership_subscriptions" as never)
        .select("tier, status, price_usd, current_period_end, cancel_at_period_end, stripe_customer_id")
        .eq("user_id", user.id)
        .maybeSingle() as { data: MembershipSubscription | null; error: any };

      if (error || !data) {
        return { tier: "free", status: "none", price_usd: null, current_period_end: null, cancel_at_period_end: false, stripe_customer_id: null };
      }

      return data;
    },
    enabled: !!user,
    staleTime: 60_000,
  });
}

export function useCreateCheckout() {
  return useMutation({
    mutationFn: async (params: { type: "membership" | "credits"; tier?: string; quantity?: number }) => {
      const { data, error } = await supabase.functions.invoke(
        "stripe-create-checkout-session",
        { body: params }
      );
      if (error) throw error;
      const body = data as { url?: string; error?: string };
      if (body.error) throw new Error(body.error);
      if (body.url) window.location.href = body.url;

      return body;
    },
  });
}

export function useManageSubscription() {
  return useMutation({
    mutationFn: async () => {
      const { data, error } = await supabase.functions.invoke(
        "stripe-create-portal-session",
        { body: {} }
      );
      if (error) throw error;
      const body = data as { url?: string; error?: string };
      if (body.error) throw new Error(body.error);
      if (body.url) window.location.href = body.url;
      return body;
    },
  });
}

import { useQuery } from '@tanstack/react-query';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';

export type MembershipLevel = 'free' | 'active' | 'expired' | 'lifetime';

interface MembershipInfo {
  status: MembershipLevel;
  expiresAt: string | null;
  isGated: boolean;
}

export function useMembershipStatus(): MembershipInfo & { isLoading: boolean } {
  const { user } = useAuth();

  const { data, isLoading } = useQuery({
    queryKey: ['membership-level', user?.id],
    queryFn: async (): Promise<MembershipInfo> => {
      if (!user) return { status: 'free', expiresAt: null, isGated: true };

      const { data: mp } = await supabase
        .from('member_profiles' as never)
        .select('membership_status, membership_expires_at')
        .eq('user_id', user.id)
        .maybeSingle() as { data: { membership_status: string; membership_expires_at: string | null } | null };

      if (mp?.membership_status === 'active' || mp?.membership_status === 'lifetime') {
        return {
          status: mp.membership_status as MembershipLevel,
          expiresAt: mp.membership_expires_at,
          isGated: false,
        };
      }

      // Fallback: user_credits
      const { data: uc } = await supabase
        .from('user_credits')
        .select('membership_stake_paid')
        .eq('user_id', user.id)
        .maybeSingle();

      if (uc?.membership_stake_paid) {
        return { status: 'active', expiresAt: null, isGated: false };
      }

      const status = (mp?.membership_status as MembershipLevel) || 'free';
      return { status, expiresAt: mp?.membership_expires_at || null, isGated: status !== 'active' && status !== 'lifetime' };
    },
    enabled: !!user,
    staleTime: 2 * 60 * 1000,

  });

  return {
    status: data?.status ?? 'free',
    expiresAt: data?.expiresAt ?? null,
    isGated: data?.isGated ?? true,
    isLoading,
  };
}

import { useState, useCallback, useRef, useEffect } from 'react';

// STUB-004 — Modular Canoe-to-Viking Ship Transform (#19)
// Ships grow by snapping additional hull segments each tide cycle.
// Start as canoe (1 segment), grow to Viking longship (5 segments) over 4 tide turns.
// Each segment adds speed and cargo capacity.

export type ShipStage = 'canoe' | 'rowboat' | 'knarr' | 'longship' | 'drakkar';

export interface HullSegment {
  id: number;
  name: string;
  addedOnTurn: number;
  speedBonus: number;       // knots added
  cargoCapacityKg: number;  // kg cargo added
  isSnapped: boolean;
  snapProgress: number;     // 0–1 during snap animation
}

export interface ShipState {
  stage: ShipStage;
  segments: HullSegment[];
  segmentCount: number;
  totalSpeed: number;         // knots
  totalCargoKg: number;       // total cargo capacity
  tideTurn: number;
  tickCount: number;
  isRunning: boolean;
  tickMs: number;
  snapAnimating: boolean;
  maxSegments: number;
}

export interface ShipControls {
  start: () => void;
  pause: () => void;
  reset: () => void;
  tick: () => void;
  addSegment: () => void;
  setTickMs: (ms: number) => void;
}

const SHIP_STAGES: ShipStage[] = ['canoe', 'rowboat', 'knarr', 'longship', 'drakkar'];

const SEGMENT_DEFINITIONS: Omit<HullSegment, 'addedOnTurn' | 'isSnapped' | 'snapProgress'>[] = [
  { id: 1, name: 'Bow Section',    speedBonus: 2, cargoCapacityKg: 50 },
  { id: 2, name: 'Mid Hull A',     speedBonus: 1, cargoCapacityKg: 120 },
  { id: 3, name: 'Mid Hull B',     speedBonus: 1, cargoCapacityKg: 120 },
  { id: 4, name: 'Stern Section',  speedBonus: 2, cargoCapacityKg: 80 },
  { id: 5, name: 'Dragon Prow',    speedBonus: 3, cargoCapacityKg: 30 },

];

function buildInitialSegments(): HullSegment[] {
  return [{ ...SEGMENT_DEFINITIONS[0], addedOnTurn: 0, isSnapped: true, snapProgress: 1 }];
}

function computeShipStage(count: number): ShipStage {
  return SHIP_STAGES[Math.min(count - 1, SHIP_STAGES.length - 1)];
}

export function useModularCanoeToVikingShip(initialTickMs = 1000): {
  state: ShipState;
  controls: ShipControls;
} {
  const [state, setState] = useState<ShipState>({
    stage: 'canoe',
    segments: buildInitialSegments(),
    segmentCount: 1,
    totalSpeed: 2,
    totalCargoKg: 50,
    tideTurn: 0,
    tickCount: 0,
    isRunning: false,
    tickMs: initialTickMs,
    snapAnimating: false,
    maxSegments: 5,
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const tick = useCallback(() => {
    setState(prev => {
      const tickCount = prev.tickCount + 1;
      // Every 12 ticks = 1 tide turn
      const tideTurn = Math.floor(tickCount / 12);
      // Auto-add segment at each new tide turn if not at max
      if (tideTurn > prev.tideTurn && prev.segmentCount < prev.maxSegments) {
        const nextSegDef = SEGMENT_DEFINITIONS[prev.segmentCount];
        const newSeg: HullSegment = { ...nextSegDef, addedOnTurn: tideTurn, isSnapped: true, snapProgress: 1 };
        const segments = [...prev.segments, newSeg];
        const segmentCount = segments.length;
        const totalSpeed = segments.reduce((s, seg) => s + seg.speedBonus, 0);
        const totalCargoKg = segments.reduce((s, seg) => s + seg.cargoCapacityKg, 0);
        return { ...prev, segments, segmentCount, stage: computeShipStage(segmentCount), totalSpeed, totalCargoKg, tideTurn, tickCount, snapAnimating: true };
      }
      return { ...prev, tideTurn, tickCount, snapAnimating: false };
    });
  }, []);

  const addSegment = useCallback(() => {

    setState(prev => {
      if (prev.segmentCount >= prev.maxSegments) return prev;
      const nextSegDef = SEGMENT_DEFINITIONS[prev.segmentCount];
      const newSeg: HullSegment = { ...nextSegDef, addedOnTurn: prev.tideTurn, isSnapped: true, snapProgress: 1 };
      const segments = [...prev.segments, newSeg];
      const segmentCount = segments.length;
      const totalSpeed = segments.reduce((s, seg) => s + seg.speedBonus, 0);
      const totalCargoKg = segments.reduce((s, seg) => s + seg.cargoCapacityKg, 0);
      return { ...prev, segments, segmentCount, stage: computeShipStage(segmentCount), totalSpeed, totalCargoKg, snapAnimating: true };
    });
  }, []);

  const start = useCallback(() => setState(prev => ({ ...prev, isRunning: true })), []);
  const pause = useCallback(() => setState(prev => ({ ...prev, isRunning: false })), []);

  const reset = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    setState(prev => ({
      ...prev,
      stage: 'canoe',
      segments: buildInitialSegments(),
      segmentCount: 1,
      totalSpeed: 2,
      totalCargoKg: 50,
      tideTurn: 0,
      tickCount: 0,
      isRunning: false,
      snapAnimating: false,
    }));
  }, []);

  const setTickMs = useCallback((ms: number) => setState(prev => ({ ...prev, tickMs: ms })), []);

  useEffect(() => {
    if (state.isRunning) {
      intervalRef.current = setInterval(tick, state.tickMs);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [state.isRunning, state.tickMs, tick]);

  return { state, controls: { start, pause, reset, tick, addSegment, setTickMs } };
}

import { useState, useCallback } from 'react';

// MISS-014 — Multi-Color Cost-Efficient Assembly
// Each Hexel component color-coded by function.
// Single-color-per-piece enables cost-efficient multi-cavity injection molding.

export type ComponentFunction = 'water' | 'terrain' | 'mechanism' | 'constraint';

export interface HexelComponent {
  id: string;
  name: string;
  function: ComponentFunction;
  color: string;       // hex color string
  colorName: string;   // human label
  moldCavity: number;  // which cavity in the mold (1–4)
  partNumber: string;
  isAssembled: boolean;
  quantity: number;
}

export interface MoldSpec {
  cavityCount: number;
  colorPerCavity: Record<number, { color: string; function: ComponentFunction; colorName: string }>;
  cycleTimeSec: number;
  partsPerShot: number;
}

export interface ColorAssemblyState {
  components: HexelComponent[];
  mold: MoldSpec;
  assembledCount: number;
  totalParts: number;
  costEfficiencyScore: number;  // 0–100
  activeFunction: ComponentFunction | 'all';
}

export interface ColorAssemblyControls {
  init: () => void;
  assembleComponent: (componentId: string) => void;
  assembleAll: () => void;
  disassembleAll: () => void;
  setActiveFilter: (fn: ComponentFunction | 'all') => void;
  reset: () => void;
}

const FUNCTION_PALETTE: Record<ComponentFunction, { color: string; colorName: string; cavity: number }> = {
  water:     { color: '#3b82f6', colorName: 'Ocean Blue',    cavity: 1 },
  terrain:   { color: '#22c55e', colorName: 'Forest Green',  cavity: 2 },
  mechanism: { color: '#f59e0b', colorName: 'Golden Amber',  cavity: 3 },
  constraint:{ color: '#ef4444', colorName: 'Signal Red',    cavity: 4 },

};

const DEFAULT_COMPONENTS: Omit<HexelComponent, 'isAssembled'>[] = [
  { id: 'c01', name: 'Water Channel A',     function: 'water',      color: '#3b82f6', colorName: 'Ocean Blue',   moldCavity: 1, partNumber: 'HX-W-001', quantity: 4 },
  { id: 'c02', name: 'Water Channel B',     function: 'water',      color: '#3b82f6', colorName: 'Ocean Blue',   moldCavity: 1, partNumber: 'HX-W-002', quantity: 2 },
  { id: 'c03', name: 'Tide Valve Seat',     function: 'water',      color: '#3b82f6', colorName: 'Ocean Blue',   moldCavity: 1, partNumber: 'HX-W-003', quantity: 1 },
  { id: 'c04', name: 'Hexel Base Plate',    function: 'terrain',    color: '#22c55e', colorName: 'Forest Green', moldCavity: 2, partNumber: 'HX-T-001', quantity: 1 },
  { id: 'c05', name: 'Terrain Cap',         function: 'terrain',    color: '#22c55e', colorName: 'Forest Green', moldCavity: 2, partNumber: 'HX-T-002', quantity: 1 },
  { id: 'c06', name: 'Shore Ring',          function: 'terrain',    color: '#22c55e', colorName: 'Forest Green', moldCavity: 2, partNumber: 'HX-T-003', quantity: 1 },
  { id: 'c07', name: 'Rotor Disk',          function: 'mechanism',  color: '#f59e0b', colorName: 'Golden Amber', moldCavity: 3, partNumber: 'HX-M-001', quantity: 1 },
  { id: 'c08', name: 'Gear Rack',           function: 'mechanism',  color: '#f59e0b', colorName: 'Golden Amber', moldCavity: 3, partNumber: 'HX-M-002', quantity: 2 },
  { id: 'c09', name: 'Lotus Petal',         function: 'mechanism',  color: '#f59e0b', colorName: 'Golden Amber', moldCavity: 3, partNumber: 'HX-M-003', quantity: 8 },
  { id: 'c10', name: 'Snap-Fit Pin',        function: 'constraint', color: '#ef4444', colorName: 'Signal Red',   moldCavity: 4, partNumber: 'HX-C-001', quantity: 6 },
  { id: 'c11', name: 'Locking Collar',      function: 'constraint', color: '#ef4444', colorName: 'Signal Red',   moldCavity: 4, partNumber: 'HX-C-002', quantity: 3 },
  { id: 'c12', name: 'Alignment Guide',     function: 'constraint', color: '#ef4444', colorName: 'Signal Red',   moldCavity: 4, partNumber: 'HX-C-003', quantity: 2 },
];

function buildComponents(): HexelComponent[] {
  return DEFAULT_COMPONENTS.map(c => ({ ...c, isAssembled: false }));
}

function computeCostEfficiency(components: HexelComponent[]): number {
  const colorGroups = new Set(components.map(c => c.moldCavity)).size;
  const assembledRatio = components.filter(c => c.isAssembled).length / components.length;
  // 4 cavities = max efficiency (one color per function = one mold run per color)
  const cavityScore = (1 - (colorGroups - 1) / 8) * 60;
  const assemblyScore = assembledRatio * 40;
  return Math.min(100, cavityScore + assemblyScore);
}

export function useMultiColorCostEfficientAssembly(): {
  state: ColorAssemblyState;
  controls: ColorAssemblyControls;
} {
  const [state, setState] = useState<ColorAssemblyState>({
    components: buildComponents(),
    mold: {
      cavityCount: 4,
      colorPerCavity: {
        1: { color: '#3b82f6', function: 'water',      colorName: 'Ocean Blue' },
        2: { color: '#22c55e', function: 'terrain',    colorName: 'Forest Green' },
        3: { color: '#f59e0b', function: 'mechanism',  colorName: 'Golden Amber' },
        4: { color: '#ef4444', function: 'constraint', colorName: 'Signal Red' },
      },
      cycleTimeSec: 18,
      partsPerShot: 12,
    },
    assembledCount: 0,
    totalParts: DEFAULT_COMPONENTS.length,
    costEfficiencyScore: 60,

    activeFunction: 'all',
  });

  const init = useCallback(() => {
    setState(prev => ({
      ...prev,
      components: buildComponents(),
      assembledCount: 0,
      costEfficiencyScore: 60,
    }));
  }, []);

  const assembleComponent = useCallback((componentId: string) => {
    setState(prev => {
      const components = prev.components.map(c =>
        c.id === componentId ? { ...c, isAssembled: true } : c
      );
      return {
        ...prev,
        components,
        assembledCount: components.filter(c => c.isAssembled).length,
        costEfficiencyScore: computeCostEfficiency(components),
      };
    });
  }, []);

  const assembleAll = useCallback(() => {
    setState(prev => {
      const components = prev.components.map(c => ({ ...c, isAssembled: true }));
      return { ...prev, components, assembledCount: components.length, costEfficiencyScore: computeCostEfficiency(components) };
    });
  }, []);

  const disassembleAll = useCallback(() => {
    setState(prev => {
      const components = prev.components.map(c => ({ ...c, isAssembled: false }));
      return { ...prev, components, assembledCount: 0, costEfficiencyScore: computeCostEfficiency(components) };
    });
  }, []);

  const setActiveFilter = useCallback((fn: ComponentFunction | 'all') => {
    setState(prev => ({ ...prev, activeFunction: fn }));
  }, []);

  const reset = useCallback(() => {
    setState({
      components: buildComponents(),
      mold: {
        cavityCount: 4,
        colorPerCavity: {

          1: { color: '#3b82f6', function: 'water',      colorName: 'Ocean Blue' },
          2: { color: '#22c55e', function: 'terrain',    colorName: 'Forest Green' },
          3: { color: '#f59e0b', function: 'mechanism',  colorName: 'Golden Amber' },
          4: { color: '#ef4444', function: 'constraint', colorName: 'Signal Red' },
        },
        cycleTimeSec: 18,
        partsPerShot: 12,
      },
      assembledCount: 0,
      totalParts: DEFAULT_COMPONENTS.length,
      costEfficiencyScore: 60,
      activeFunction: 'all',
    });
  }, []);

  return { state, controls: { init, assembleComponent, assembleAll, disassembleAll, setActiveFilter, reset } };
}

