import { useState, useCallback, useRef, useEffect } from 'react';

// MISS-002 — Ouralis Tidal Mechanism
// 12-rotation tide cycle = one game turn. Golden Lotus rotor drives the clock.

export type TidePhase = 'ebb' | 'flow' | 'peak' | 'slack';

export interface RotorChamber {
  index: number;       // 0–11
  angle: number;       // degrees, 0–330
  filled: boolean;
  flowRate: number;    // 0–1
}

export interface TidalState {
  rotation: number;          // 0–11 (current chamber index)
  totalRotations: number;    // total rotations this game
  gameTurn: number;          // increments every 12 rotations
  phase: TidePhase;
  chambers: RotorChamber[];
  lotusAngle: number;        // Golden Lotus visual angle (degrees)
  isRunning: boolean;
  tickMs: number;            // milliseconds per rotation step
}

export interface TidalControls {
  start: () => void;
  pause: () => void;
  reset: () => void;
  tick: () => void;
  setTickMs: (ms: number) => void;
}

function buildChambers(): RotorChamber[] {
  return Array.from({ length: 12 }, (_, i) => ({
    index: i,
    angle: i * 30,
    filled: false,
    flowRate: 0,
  }));
}

function derivePhase(rotation: number): TidePhase {
  if (rotation <= 2) return 'flow';
  if (rotation <= 5) return 'peak';
  if (rotation <= 8) return 'ebb';
  return 'slack';
}

export function useOuralisTidalMechanism(initialTickMs = 800): {

  state: TidalState;
  controls: TidalControls;
} {
  const [state, setState] = useState<TidalState>({
    rotation: 0,
    totalRotations: 0,
    gameTurn: 0,
    phase: 'slack',
    chambers: buildChambers(),
    lotusAngle: 0,
    isRunning: false,
    tickMs: initialTickMs,
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const tick = useCallback(() => {
    setState(prev => {
      const nextRotation = (prev.rotation + 1) % 12;
      const nextTotal = prev.totalRotations + 1;
      const nextTurn = Math.floor(nextTotal / 12);
      const phase = derivePhase(nextRotation);
      const lotusAngle = (prev.lotusAngle + 30) % 360;

      const chambers = prev.chambers.map(ch => {
        const distFromCurrent = Math.abs(ch.index - nextRotation);
        const dist = Math.min(distFromCurrent, 12 - distFromCurrent);
        const flowRate = Math.max(0, 1 - dist * 0.35);
        return { ...ch, filled: ch.index <= nextRotation, flowRate };
      });

      return { ...prev, rotation: nextRotation, totalRotations: nextTotal, gameTurn: nextTurn, phase, chambers, lotusAngle };
    });
  }, []);

  const start = useCallback(() => {
    setState(prev => ({ ...prev, isRunning: true }));
  }, []);

  const pause = useCallback(() => {
    setState(prev => ({ ...prev, isRunning: false }));
  }, []);

  const reset = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    setState(prev => ({
      ...prev,
      rotation: 0,
      totalRotations: 0,
      gameTurn: 0,

      phase: 'slack',
      chambers: buildChambers(),
      lotusAngle: 0,
      isRunning: false,
    }));
  }, []);

  const setTickMs = useCallback((ms: number) => {
    setState(prev => ({ ...prev, tickMs: ms }));
  }, []);

  useEffect(() => {
    if (state.isRunning) {
      intervalRef.current = setInterval(tick, state.tickMs);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [state.isRunning, state.tickMs, tick]);

  return { state, controls: { start, pause, reset, tick, setTickMs } };
}

/**
 * useOutreachLetters — React hook for Glass Door outreach letters
 * ================================================================
 * K412 / B099 — The Glass Door Phase 2
 * Innovation #2262 The Glass Door
 */

import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";

export interface OutreachLetter {
  letter_id: string;
  slug: string;
  recipient_name: string;
  recipient_category: string;
  recipient_tier: number;
  state: string;
  full_text: string;
  substantive_summary: string | null;
  what_we_are_asking: string;
  what_we_are_not_asking: string | null;
  why_this_recipient: string | null;
  source_innovation_refs: number[];
  wave_label: string | null;
  scheduled_dispatch: string | null;
  dispatched_at: string | null;
  voting_mode: "advisory" | "binding";
  voting_window_start: string | null;
  voting_window_end: string | null;
  vote_threshold_approval_pct: number;
  vote_threshold_veto_pct: number;
  created_at: string;
  updated_at: string;
}

export interface OutreachVote {
  vote_id: string;
  letter_id: string;
  member_id: string;
  vote_type: "approve" | "request_edit" | "delay" | "redirect" | "veto" | "abstain";
  six_degrees_flag: boolean;
  comment: string | null;
  proposed_edit: string | null;
  proposed_delay_days: number | null;
  proposed_redirect_recipient: string | null;
  voted_at: string;
}

export interface OutreachVerdict {
  total_votes: number;

  approve_count: number;
  veto_count: number;
  approval_pct: number;
  veto_pct: number;
  verdict: string;
  next_action: string;
}

export interface OutreachResponse {
  response_id: string;
  letter_id: string;
  response_received_at: string;
  response_summary: string;
  response_classifier: string | null;
}

export function useOutreachLetters(filterState?: string) {
  const [letters, setLetters] = useState<OutreachLetter[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      let query = (supabase
        .from("outreach_letters" as never)
        .select("*") as any)
        .neq("state", "draft")
        .order("scheduled_dispatch", { ascending: true, nullsFirst: false });

      if (filterState) {
        query = query.eq("state", filterState);
      }

      const { data, error } = await query;
      if (!error) {
        setLetters((data || []) as OutreachLetter[]);
      }
      setLoading(false);
    };

    load();
  }, [filterState]);

  return { letters, loading };
}

export function useOutreachLetter(slug: string) {
  const [letter, setLetter] = useState<OutreachLetter | null>(null);
  const [votes, setVotes] = useState<OutreachVote[]>([]);
  const [verdict, setVerdict] = useState<OutreachVerdict | null>(null);
  const [responses, setResponses] = useState<OutreachResponse[]>([]);

  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!slug) return;

    const load = async () => {
      // Fetch letter
      const { data: letterData } = await (supabase
        .from("outreach_letters" as never)
        .select("*") as any)
        .eq("slug", slug)
        .single();

      if (!letterData) {
        setLoading(false);
        return;
      }

      setLetter(letterData as OutreachLetter);

      // Fetch votes
      const { data: voteData } = await (supabase
        .from("outreach_letter_votes" as never)
        .select("*") as any)
        .eq("letter_id", letterData.letter_id)
        .order("voted_at", { ascending: false });

      setVotes((voteData || []) as OutreachVote[]);

      // Compute verdict
      const { data: verdictData } = await (supabase as any).rpc(
        "compute_outreach_letter_verdict",
        { p_letter_id: letterData.letter_id },
      );
      if (verdictData?.[0]) {
        setVerdict(verdictData[0] as OutreachVerdict);
      }

      // Fetch responses
      const { data: respData } = await (supabase
        .from("outreach_letter_responses" as never)
        .select("*") as any)
        .eq("letter_id", letterData.letter_id)
        .order("response_received_at", { ascending: false });

      setResponses((respData || []) as OutreachResponse[]);
      setLoading(false);
    };

    load();

  }, [slug]);

  const castVote = async (
    voteType: string,
    opts?: { comment?: string; proposed_edit?: string; proposed_delay_days?: number; proposed_redirect_recipient?: string },
  ) => {
    if (!letter) return;
    const session = await supabase.auth.getSession();
    const token = session.data.session?.access_token;
    if (!token) return;

    const res = await fetch(
      `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/cast-outreach-letter-vote`,
      {
        method: "POST",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          letter_id: letter.letter_id,
          vote_type: voteType,
          ...opts,
        }),
      },
    );

    const data = await res.json();
    if (data.verdict) {
      setVerdict(data.verdict);
    }
    return data;
  };

  const flagSixDegrees = async (flagValue: boolean) => {
    if (!letter) return;
    const session = await supabase.auth.getSession();
    const token = session.data.session?.access_token;
    if (!token) return;

    const res = await fetch(
      `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/cast-outreach-letter-vote`,
      {
        method: "POST",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          letter_id: letter.letter_id,

          six_degrees_flag: flagValue,
        }),
      },
    );

    return res.json();
  };

  return { letter, votes, verdict, responses, loading, castVote, flagSixDegrees };
}

import { useEffect, useState } from 'react';
import { toast } from 'sonner';

interface BeforeInstallPromptEvent extends Event {
  prompt: () => Promise<void>;
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>;
}

export function usePWA() {
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null);
  const [isInstallable, setIsInstallable] = useState(false);
  const [isInstalled, setIsInstalled] = useState(false);

  useEffect(() => {
    // Check if already installed
    if (window.matchMedia('(display-mode: standalone)').matches) {
      setIsInstalled(true);
    }

    // Listen for install prompt
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e as BeforeInstallPromptEvent);
      setIsInstallable(true);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    // Listen for successful installation
    const handleAppInstalled = () => {
      setIsInstalled(true);
      setIsInstallable(false);
      setDeferredPrompt(null);
      toast.success('App installed successfully!');
    };

    window.addEventListener('appinstalled', handleAppInstalled);

    // Register service worker
    if ('serviceWorker' in navigator) {
      navigator.serviceWorker
        .register('/sw.js')
        .then((registration) => {
          // Check for updates
          registration.addEventListener('updatefound', () => {
            const newWorker = registration.installing;
            if (newWorker) {
              newWorker.addEventListener('statechange', () => {
                if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
                  toast.info('New version available!', {

                  action: {
                    label: 'Refresh',
                    onClick: () => {
                      newWorker.postMessage({ type: 'SKIP_WAITING' });
                      window.location.reload();
                    },
                  },
                });
              }
            });
          }
        });
      })
      .catch((error) => {
        console.error('Service Worker registration failed:', error);
      });
  }

  return () => {
    window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    window.removeEventListener('appinstalled', handleAppInstalled);
  };
}, []);

const installApp = async () => {
  if (!deferredPrompt) {
    toast.error('Installation not available');
    return;
  }

  deferredPrompt.prompt();
  const { outcome } = await deferredPrompt.userChoice;

  // outcome is either 'accepted' or 'dismissed' — no action needed either way

  setDeferredPrompt(null);
  setIsInstallable(false);
};

const requestSync = async () => {
  if ('serviceWorker' in navigator && 'sync' in (ServiceWorkerRegistration.prototype as any)) {
    const registration = await navigator.serviceWorker.ready;
    await (registration as any).sync.register('sync-data');
    toast.success('Background sync scheduled');
  } else {
    toast.error('Background sync not supported');
  }
};

return {

    isInstallable,
    isInstalled,
    installApp,
    requestSync,
  };
}

