  reviewer_id: string | null;
  reviewer_notes: string | null;
  reviewed_at: string | null;
  marks_awarded: number;
  is_process_pioneer: boolean;
  ip_ledger_entry: string | null;
  created_at: string;
  updated_at: string;
}

export interface PiggybackReview {
