import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

export type SearchFilter = 'all' | 'products' | 'projects' | 'makers' | 'cards';

export interface SearchResultProduct {
  id: string;
  name: string;
  description: string | null;
  slug: string;
  category: string | null;
}

export interface SearchResultProject {
  id: string;
  title: string;
  description: string | null;
  slug: string;
  category: string;
  status: string;
}

export interface SearchResultMaker {
  id: string;
  user_id: string;
  display_name: string;
  bio: string | null;
  city: string | null;
  state: string | null;
}

export interface SearchResultCueCard {
  id: string;
  title: string;
  slug: string;
  craft_type: string;
  icon: string;
}

export interface SearchResults {
  products: SearchResultProduct[];
  projects: SearchResultProject[];
  makers: SearchResultMaker[];
  cards: SearchResultCueCard[];
}

async function searchProducts(q: string): Promise<SearchResultProduct[]> {
  const pattern = `%${q}%`;
  const { data } = await supabase
    .from('turnkey_projects' as never)

    .select('id, title, description, slug, category')
    .or(`title.ilike.${pattern},description.ilike.${pattern}`)
    .eq('status', 'showcased')
    .limit(20) as { data: any[] | null };
  return (data || []).map((r: any) => ({
    id: r.id,
    name: r.title,
    description: r.description,
    slug: r.slug,
    category: r.category,
  }));
}

async function searchProjects(q: string): Promise<SearchResultProject[]> {
  const pattern = `%${q}%`;
  const { data } = await supabase
    .from('turnkey_projects' as never)
    .select('id, title, description, slug, category, status')
    .or(`title.ilike.${pattern},description.ilike.${pattern}`)
    .neq('status', 'draft')
    .limit(20) as { data: SearchResultProject[] | null };
  return data || [];
}

async function searchMakers(q: string): Promise<SearchResultMaker[]> {
  const pattern = `%${q}%`;
  const { data } = await supabase
    .from('member_profiles' as never)
    .select('id, user_id, display_name, bio, city, state')
    .or(`display_name.ilike.${pattern},bio.ilike.${pattern}`)
    .limit(20) as { data: SearchResultMaker[] | null };
  return data || [];
}

async function searchCueCards(q: string): Promise<SearchResultCueCard[]> {
  const pattern = `%${q}%`;
  const { data } = await supabase
    .from('cue_card_campaigns' as never)
    .select('id, title, slug, craft_type, icon')
    .or(`title.ilike.${pattern},craft_type.ilike.${pattern}`)
    .eq('is_active', true)
    .limit(20) as { data: SearchResultCueCard[] | null };
  return data || [];
}

export function useSearch(query: string, filter: SearchFilter = 'all') {
  return useQuery({
    queryKey: ['global-search', query, filter],
    queryFn: async (): Promise<SearchResults> => {
      const [products, projects, makers, cards] = await Promise.all([

        filter === 'all' || filter === 'products' ? searchProducts(query) : [],
        filter === 'all' || filter === 'projects' ? searchProjects(query) : [],
        filter === 'all' || filter === 'makers' ? searchMakers(query) : [],
        filter === 'all' || filter === 'cards' ? searchCueCards(query) : [],
      ]);
      return { products, projects, makers, cards };
    },
    enabled: query.length >= 2,
    staleTime: 30_000,
  });
}

import { useMutation } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

type EmailType =
  | 'welcome'
  | 'pledge_confirmation'
  | 'credit_purchase'
  | 'pledge_cancellation'
  | 'milestone_update'
  | 'project_claimed'
  | 'delivery_confirmation_request'
  | 'contest_entry_received'
  | 'membership_confirmed'
  | 'payout_sent'
  | 'outreach';

interface SendEmailParams {
  email: string;
  type: EmailType;
  data?: Record<string, unknown>;
}

function generateSlug(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .trim();
}

/**
 * K202 (B053): After a successful outreach email, auto-register the recipient
 * in red_carpet_registry so they get Red Carpet access without a code deploy.
 */
async function autoRegisterRedCarpetAccess(
  email: string,
  data?: Record<string, unknown>
): Promise<void> {
  const recipientName = (data?.recipientName as string) || (data?.name as string) || '';
  if (!recipientName) return;

  const slug = generateSlug(recipientName);
  const senderName = (data?.senderName as string) || 'A Liana Banyan member';
  const businessName = (data?.businessName as string) || (data?.organization as string) || '';

  await supabase.from('red_carpet_registry').upsert({
    slug,
    name: recipientName,
    organization: businessName,

    purpose: `Cue Card from ${senderName}`,
    known_emails: [email.toLowerCase()],
    categories: ['cue-card'],
    source: 'cue_card',
    is_active: true,
  }, { onConflict: 'slug' }).then(({ error }) => {
    if (error) console.error('Red carpet auto-register error:', error);
  });
}

export function useSendEmail() {
  return useMutation({
    mutationFn: async ({ email, type, data }: SendEmailParams) => {
      const { data: result, error } = await supabase.functions.invoke(
        'send-transactional-email',
        { body: { email, type, data } }
      );
      if (error) throw error;

      if (type === 'outreach') {
        autoRegisterRedCarpetAccess(email, data).catch(() => {});
      }

      return result;
    },
  });
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export interface ShareChain {
  id: string;
  user_id: string;
  current_streak: number;
  highest_streak: number;
  bonus_pct: number;
  sustained: boolean;
  last_share_at: string | null;
  chain_expires_at: string | null;
  total_shares: number;
  total_bonus_points: number;
  total_bonus_marks: number;
  created_at: string;
  updated_at: string;
}

function computeChainBonus(streak: number, sustained: boolean): number {
  if (sustained) return 20;
  return Math.min(streak * 5, 100);
}

function computeChainExpiry(engagement: {
  views: number;
  clicks: number;
}): string {
  const baseHours = 48;
  const viewBonus = Math.floor(engagement.views / 10);
  const clickBonus = engagement.clicks * 4;
  const totalHours = Math.min(baseHours + viewBonus + clickBonus, 168);
  return new Date(Date.now() + totalHours * 3_600_000).toISOString();
}

export function useShareChain() {
  const { user } = useAuth();
  const qc = useQueryClient();

  const query = useQuery({
    queryKey: ["share-chain", user?.id],
    queryFn: async () => {
      if (!user) return null;
      const { data, error } = await supabase
        .from("share_chains" as any)
        .select("*")
        .eq("user_id", user.id)
        .maybeSingle();
      if (error) throw error;

      return data as ShareChain | null;
    },
    enabled: !!user,
  });

  const recordShare = useMutation({
    mutationFn: async (engagement?: { views: number; clicks: number }) => {
      if (!user) throw new Error("Must be logged in");
      const eng = engagement ?? { views: 0, clicks: 0 };

      const existing = query.data;
      const now = new Date().toISOString();
      const newExpiry = computeChainExpiry(eng);

      if (!existing) {
        const bonus = computeChainBonus(1, false);
        const { data, error } = await supabase
          .from("share_chains" as any)
          .insert({
            user_id: user.id,
            current_streak: 1,
            highest_streak: 1,
            bonus_pct: bonus,
            sustained: false,
            last_share_at: now,
            chain_expires_at: newExpiry,
            total_shares: 1,
          })
          .select()
          .single();
        if (error) throw error;
        return data as ShareChain;
      }

      const chainAlive =
        existing.chain_expires_at != null &&
        new Date(existing.chain_expires_at) > new Date();

      let newStreak: number;
      let sustained = existing.sustained;

      if (chainAlive) {
        newStreak = existing.current_streak + 1;
      } else {
        newStreak = 1;
        sustained = false;
      }

      if (newStreak >= 21 && !sustained) {
        sustained = true;

        newStreak = 0;
      }

      const bonus = computeChainBonus(newStreak, sustained);
      const highestStreak = Math.max(existing.highest_streak, newStreak);

      const { data, error } = await supabase
        .from("share_chains" as any)
        .update({
          current_streak: newStreak,
          highest_streak: highestStreak,
          bonus_pct: bonus,
          sustained,
          last_share_at: now,
          chain_expires_at: newExpiry,
          total_shares: existing.total_shares + 1,
          updated_at: now,
        })
        .eq("user_id", user.id)
        .select()
        .single();

      if (error) throw error;
      return data as ShareChain;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["share-chain"] });
    },
  });

  const chain = query.data;
  const isAlive =
    chain?.chain_expires_at != null &&
    new Date(chain.chain_expires_at) > new Date();

  const hoursRemaining =
    chain?.chain_expires_at != null
      ? Math.max(
          0,
          Math.round(
            (new Date(chain.chain_expires_at).getTime() - Date.now()) /
              3_600_000,
          ),
        )
      : 0;

  return {
    chain,
    isAlive,
    hoursRemaining,

    bonusPct: chain?.bonus_pct ?? 0,
    streak: chain?.current_streak ?? 0,
    isSustained: chain?.sustained ?? false,
    recordShare: recordShare.mutateAsync,
    isRecording: recordShare.isPending,
    isLoading: query.isLoading,
  };
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

interface DemandSignal {
  id: string;
  project_id: string;
  user_id: string;
  signal_type: 'want' | 'pledge' | 'comment';
  credits_pledged: number;
  comment_text: string | null;
  created_at: string;
}

interface EscrowRecord {
  id: string;
  project_id: string;
  user_id: string;
  credits_amount: number;
  status: 'held' | 'converted' | 'refunded';
  escrowed_at: string;
}

export interface ShowcaseDemand {
  wantCount: number;
  pledgeTotal: number;
  pledgerCount: number;
  comments: DemandSignal[];
  signals: DemandSignal[];
  escrow: EscrowRecord[];
  isLoading: boolean;
  userWanted: boolean;
  userPledged: boolean;
}

export function useShowcaseDemand(projectId: string | undefined): ShowcaseDemand {
  const signalsQuery = useQuery({
    queryKey: ['showcase-signals', projectId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('showcase_demand_signals' as never)
        .select('*')
        .eq('project_id', projectId!) as { data: DemandSignal[] | null; error: unknown };
      if (error) throw error;
      return (data || []) as DemandSignal[];
    },
    enabled: !!projectId,
  });

  const escrowQuery = useQuery({
    queryKey: ['showcase-escrow', projectId],

    queryFn: async () => {
      const { data, error } = await supabase
        .from('showcase_pledge_escrow' as never)
        .select('*')
        .eq('project_id', projectId!)
        .eq('status', 'held') as { data: EscrowRecord[] | null; error: unknown };
      if (error) throw error;
      return (data || []) as EscrowRecord[];
    },
    enabled: !!projectId,
  });

  const signals = signalsQuery.data ?? [];
  const escrow = escrowQuery.data ?? [];
  const wantSignals = signals.filter(s => s.signal_type === 'want');
  const pledgeSignals = signals.filter(s => s.signal_type === 'pledge');
  const comments = signals
    .filter(s => s.signal_type === 'comment')
    .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());

  const userId = supabase.auth.getUser ? undefined : undefined;

  return {
    wantCount: wantSignals.length,
    pledgeTotal: escrow.reduce((sum, e) => sum + e.credits_amount, 0),
    pledgerCount: pledgeSignals.length,
    comments,
    signals,
    escrow,
    isLoading: signalsQuery.isLoading || escrowQuery.isLoading,
    userWanted: false,
    userPledged: false,
  };
}

