import { useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

const LOCK_COUNT = 12;
const LOCK_NAMES = [
  "The Lighthouse",
  "The Four Judges",
  "The Cornerstone",
  "The Spyglass",
  "The Forge",
  "The Bridge",
  "The Labyrinth Key",
  "The Beacon Trail",
  "The Durin Door",
  "The Candle Complete",
  "The Mirror Room",
  "The Two Mirrors",
] as const;

export function useSnowGateProgress() {
  const { user } = useAuth();

  const { data, isLoading } = useQuery({
    queryKey: ["snow-gate-progress", user?.id],
    enabled: !!user?.id,
    queryFn: async () => {
      const userId = user!.id;

      const safeCount = async (
        promise: Promise<{ count: number | null; error: unknown }>,
      ): Promise<number> => {
        try {
          const { count, error } = await promise;
          if (error) return 0;
          return Number(count ?? 0);
        } catch {
          return 0;
        }
      };

      const existingLocks = await supabase
        .from("snow_gate_progress" as never)
        .select("lock_number")
        .eq("user_id", userId);

      const papers = await safeCount(
        supabase
          .from("paper_read_completions")

          .select("id", { count: "exact", head: true })
          .eq("user_id", userId),
      );
      const verdicts = await safeCount(
        supabase
          .from("star_chamber_verdicts")
          .select("id", { count: "exact", head: true })
          .eq("user_id", userId),
      );
      const discoveries = await safeCount(
        supabase
          .from("discovery_gates")
          .select("id", { count: "exact", head: true })
          .eq("user_id", userId),
      );
      const production = await safeCount(
        supabase
          .from("production_campaigns")
          .select("id", { count: "exact", head: true })
          .eq("captain_user_id", userId),
      );
      const peerAsCreator = await safeCount(
        supabase
          .from("peer_contracts")
          .select("id", { count: "exact", head: true })
          .eq("creator_id", userId),
      );
      const peerAsAcceptor = await safeCount(
        supabase
          .from("peer_contracts")
          .select("id", { count: "exact", head: true })
          .eq("acceptor_id", userId),
      );
      const candleFragments = await safeCount(
        supabase
          .from("babylon_candle_fragments" as never)
          .select("id", { count: "exact", head: true })
          .eq("user_id", userId),
      );

      const sponsorProfilesRes = await supabase
        .from("sponsor_profiles")
        .select("id")
        .eq("user_id", userId);
      const sponsorIds = ((sponsorProfilesRes.data as { id: string }[] | null) ?? []).map((x) => x.id);
      const sponsorCount =
        sponsorIds.length > 0
          ? await safeCount(
              supabase
                .from("sponsorships")

                .select("id", { count: "exact", head: true })
                .in("sponsor_id", sponsorIds),
            )
          : 0;
      const sponsorRecipientCount =
        sponsorIds.length > 0
          ? await safeCount(
              supabase
                .from("sponsorships")
                .select("id", { count: "exact", head: true })
                .in("sponsor_id", sponsorIds)
                .not("recipient_id", "is", null),
            )
          : 0;

      const reportsVerified = await safeCount(
        supabase
          .from("arena_reports")
          .select("id", { count: "exact", head: true })
          .eq("reporter_id", userId)
          .in("status", ["verified", "reviewed", "resolved"]),
      );

      const beaconsRes = await supabase
        .from("beacons")
        .select("beacon_color")
        .eq("user_id", userId);
      const distinctBeaconColors = new Set(
        ((beaconsRes.data as { beacon_color: string | null }[] | null) ?? [])
          .map((b) => b.beacon_color)
          .filter(Boolean),
      ).size;

      const durinUnlocksRes = await supabase
        .from("durin_door_unlocks")
        .select("door_id")
        .eq("user_id", userId);
      const durinDoorCount = new Set(
        ((durinUnlocksRes.data as { door_id: string }[] | null) ?? []).map((d) => d.door_id),
      ).size;

      const userCandlesRes = await supabase
        .from("user_candles")
        .select("babylon_amount")
        .eq("user_id", userId)
        .maybeSingle();
      const babylonAmount = Number(userCandlesRes.data?.babylon_amount ?? 0);

      const ambassadorRes = await supabase
        .from("ambassadors")

        .select("id")
        .eq("user_id", userId);
      const ambassadorIds = ((ambassadorRes.data as { id: string }[] | null) ?? []).map((a) => a.id);
      const ambassadorAssessments =
        ambassadorIds.length > 0
          ? await safeCount(
              supabase
                .from("ambassador_certifications")
                .select("id", { count: "exact", head: true })
                .in("ambassador_id", ambassadorIds),
            )
          : 0;

      const lockSet = new Set<number>(
        ((existingLocks.data as { lock_number: number }[] | null) ?? []).map((x) => x.lock_number),
      );

      const conditionMet: boolean[] = [
        papers >= 1, // Lock 1: Lighthouse
        verdicts >= 4, // Lock 2: Four Judges
        sponsorCount >= 1, // Lock 3: Cornerstone (contribution behavior)
        discoveries >= 20, // Lock 4: Spyglass
        production >= 1, // Lock 5: Forge
        sponsorRecipientCount >= 1, // Lock 6: Bridge (sponsor someone)
        reportsVerified >= 3, // Lock 7: Labyrinth Key
        distinctBeaconColors >= 6, // Lock 8: Beacon Trail
        durinDoorCount >= 3, // Lock 9: Durin Door
        candleFragments >= 7 || babylonAmount >= 1, // Lock 10: Candle Complete
        ambassadorAssessments >= 1, // Lock 11: Mirror Room (assessment)
        peerAsCreator >= 1 && peerAsAcceptor >= 1, // Lock 12: Two Mirrors
      ];

      conditionMet.forEach((ok, idx) => {
        if (ok) lockSet.add(idx + 1);
      });

      const unlockRows = conditionMet
        .map((ok, idx) => ({ ok, lock_number: idx + 1 }))
        .filter((x) => x.ok)
        .filter((x) => !((existingLocks.data as { lock_number: number }[] | null) ?? []).some((l) => l.lock_number === x.lock_number))
        .map((x) => ({
          user_id: userId,
          lock_number: x.lock_number,
          lock_name: LOCK_NAMES[x.lock_number - 1],
          reward_claimed: false,
        }));

      if (unlockRows.length > 0) {
        await supabase
          .from("snow_gate_progress" as never)

          .upsert(unlockRows as never, { onConflict: "user_id,lock_number" });
      }

      const locks = Array.from({ length: LOCK_COUNT }, (_, i) => lockSet.has(i + 1));
      const totalCompleted = locks.filter(Boolean).length;
      const fragments = candleFragments;

      return {
        locks,
        totalCompleted,
        candleFragments: fragments,
        hasAccess: totalCompleted >= LOCK_COUNT,
      };
    },
    staleTime: 30_000,
  });

  return useMemo(
    () =>
      data ?? {
        locks: Array.from({ length: LOCK_COUNT }, () => false),
        totalCompleted: 0,
        candleFragments: 0,
        hasAccess: false,
      },
    [data, isLoading],
  );
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface SocialImport {
  id: string;
  user_id: string;
  source_platform: string;
  source_url: string;
  source_title: string | null;
  source_description: string | null;
  source_images: string[];
  status: 'imported' | 'draft' | 'converted';
  project_id: string | null;
  created_at: string;
}

interface ExtractedMetadata {
  title: string;
  description: string;
  images: string[];
  platform: string;
  source_url: string;
}

function detectPlatform(url: string): string {
  const host = new URL(url).hostname.toLowerCase();
  if (host.includes('reddit.com') || host.includes('redd.it')) return 'reddit';
  if (host.includes('discord.com') || host.includes('discord.gg')) return 'discord';
  if (host.includes('instagram.com')) return 'instagram';
  if (host.includes('etsy.com')) return 'etsy';
  if (host.includes('twitter.com') || host.includes('x.com')) return 'twitter';
  if (host.includes('tiktok.com')) return 'tiktok';
  return 'website';
}

export function useExtractFromUrl() {
  const [extracting, setExtracting] = useState(false);
  const [metadata, setMetadata] = useState<ExtractedMetadata | null>(null);
  const [error, setError] = useState<string | null>(null);

  const extract = async (url: string) => {
    setExtracting(true);
    setError(null);
    setMetadata(null);

    try {
      new URL(url);
    } catch {

      setError('Please enter a valid URL');
      setExtracting(false);
      return null;
    }

    try {
      const { data, error: fnErr } = await supabase.functions.invoke('extract-url-metadata', {
        body: { url },
      });

      if (fnErr) throw fnErr;

      const result: ExtractedMetadata = {
        title: data?.title || '',
        description: data?.description || '',
        images: data?.images || [],
        platform: data?.platform || detectPlatform(url),
        source_url: url,
      };

      setMetadata(result);
      return result;
    } catch (err) {
      const platform = detectPlatform(url);
      const fallback: ExtractedMetadata = {
        title: '',
        description: '',
        images: [],
        platform,
        source_url: url,
      };
      setMetadata(fallback);
      setError('Could not auto-extract metadata — you can fill in details manually.');
      return fallback;
    } finally {
      setExtracting(false);
    }
  };

  return { extract, extracting, metadata, setMetadata, error };
}

export function useCreateImport() {
  const { user } = useAuth();
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: {
      source_platform: string;
      source_url: string;

      source_title?: string;
      source_description?: string;
      source_images?: string[];
    }) => {
      if (!user) throw new Error('Not authenticated');

      const { data, error } = await supabase
        .from('social_imports' as never)
        .insert({
          user_id: user.id,
          source_platform: input.source_platform,
          source_url: input.source_url,
          source_title: input.source_title || null,
          source_description: input.source_description || null,
          source_images: input.source_images || [],
          status: 'imported',
        } as never)
        .select('*')
        .single() as { data: SocialImport | null; error: unknown };

      if (error || !data) throw error || new Error('Failed to save import');
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['social-imports'] });
    },
  });
}

export function useConvertImport() {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async ({ importId, projectId }: { importId: string; projectId: string }) => {
      const { error } = await supabase
        .from('social_imports' as never)
        .update({ status: 'converted', project_id: projectId } as never)
        .eq('id', importId) as { error: unknown };

      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['social-imports'] });
    },
  });
}

export function useMyImports() {
  const { user } = useAuth();

  return useQuery({
    queryKey: ['social-imports', user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('social_imports' as never)
        .select('*')
        .eq('user_id', user!.id)
        .order('created_at', { ascending: false }) as { data: SocialImport[] | null; error: unknown };

      if (error) throw error;
      return (data || []) as SocialImport[];
    },
    enabled: !!user,
  });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface SponsoredCard {
  id: string;
  sponsor_id: string;
  card_type: 'physical' | 'digital' | 'both';
  preloaded_amount: number;
  include_membership: boolean;
  door_config_id: string | null;
  activation_code: string;
  activated: boolean;
  activated_by: string | null;
  activated_at: string | null;
  status: 'created' | 'distributed' | 'activated' | 'expired';
  created_at: string;
  expires_at: string | null;
}

function generateActivationCode(): string {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let code = '';
  for (let i = 0; i < 8; i++) {
    code += chars[Math.floor(Math.random() * chars.length)];
  }
  return `LB-${code}`;
}

export function useMySponsoredCards() {
  const { user } = useAuth();
  return useQuery({
    queryKey: ['sponsored-cards', user?.id],
    queryFn: async () => {
      const { data } = await supabase
        .from('sponsored_cards' as never)
        .select('*')
        .eq('sponsor_id', user!.id)
        .order('created_at', { ascending: false }) as { data: SponsoredCard[] | null };
      return data || [];
    },
    enabled: !!user,
  });
}

export function useCreateSponsoredCard() {
  const qc = useQueryClient();
  const { user } = useAuth();

  return useMutation({

    mutationFn: async (params: {
      card_type?: 'physical' | 'digital' | 'both';
      preloaded_amount?: number;
      include_membership?: boolean;
      door_config_id?: string | null;
      expires_at?: string | null;
    }) => {
      const { data, error } = await supabase
        .from('sponsored_cards' as never)
        .insert({
          sponsor_id: user!.id,
          activation_code: generateActivationCode(),
          ...params,
        } as never)
        .select()
        .single();
      if (error) throw error;
      return data as unknown as SponsoredCard;
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['sponsored-cards'] }),
  });
}

export function useActivateCard() {
  const qc = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async (activationCode: string) => {
      const { data: cards } = await supabase
        .from('sponsored_cards' as never)
        .select('*')
        .eq('activation_code', activationCode)
        .eq('activated', false) as { data: SponsoredCard[] | null };

      if (!cards || cards.length === 0) throw new Error('Invalid or already-used activation code');

      const card = cards[0];
      if (card.expires_at && new Date(card.expires_at) < new Date()) {
        throw new Error('This card has expired');
      }

      const { data, error } = await supabase
        .from('sponsored_cards' as never)
        .update({
          activated: true,
          activated_by: user!.id,
          activated_at: new Date().toISOString(),
          status: 'activated',
        } as never)

        .eq('id', card.id)
        .select()
        .single();

      if (error) throw error;

      // Create sponsorship attribution (ONE LEVEL ONLY)
      await supabase
        .from('sponsorship_attributions' as never)
        .insert({
          sponsor_id: card.sponsor_id,
          sponsored_user_id: user!.id,
          card_id: card.id,
          marks_earned_signup: 10,
        } as never);

      return data as unknown as SponsoredCard;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['sponsored-cards'] });
    },
  });
}

export function useSponsorCardByCode(code: string | undefined) {
  return useQuery({
    queryKey: ['sponsor-card-lookup', code],
    queryFn: async () => {
      if (!code) return null;
      const { data } = await supabase
        .from('sponsored_cards' as never)
        .select('*')
        .eq('activation_code', code)
        .single() as { data: SponsoredCard | null };
      return data;
    },
    enabled: !!code,
  });
}

import { useState, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { SEED_CARDS, SPOTLIGHT_CATEGORIES, selectCards, type SpotlightCard, type AlgorithmConfig } from '@/lib/spotlightAlgorithm';

const DEFAULT_ALGO_CONFIG: AlgorithmConfig = {
  timeOfDayWeight: 0.2,
  recencyWeight: 0.3,
  viewRatioWeight: 0.3,
  randomSalt: 0.2,
};

export function useSpotlightCarousel(
  pageContext: string = 'landing',
  defaultCategory: string = 'all',
) {
  const [category, setCategory] = useState(defaultCategory);
  const impressionCounts = useRef<Record<string, number>>({});
  const sessionId = useRef(
    typeof crypto !== 'undefined' && crypto.randomUUID
      ? crypto.randomUUID()
      : `${Date.now()}-${Math.random().toString(36).slice(2)}`,
  );

  const cards = selectCards(
    SEED_CARDS,
    category,
    DEFAULT_ALGO_CONFIG,
    impressionCounts.current,
  );

  const logEvent = useCallback(
    async (
      cardId: string,
      action: 'impression' | 'click' | 'spotlight' | 'cta_click' | 'dismiss',
      positionInCarousel?: number,
      dwellMs?: number,
    ) => {
      impressionCounts.current[cardId] = (impressionCounts.current[cardId] || 0) + 1;

      try {
        await supabase.from('spotlight_impressions' as any).insert({
          card_id: cardId,
          category,
          position_in_carousel: positionInCarousel ?? null,
          action,
          session_id: sessionId.current,
          dwell_ms: dwellMs ?? null,
          algorithm_config: DEFAULT_ALGO_CONFIG,
          page_context: pageContext,
        });

      } catch {
        // Non-critical — don't block UX
      }
    },
    [category, pageContext],
  );

  return {
    cards,
    category,
    setCategory,
    categories: SPOTLIGHT_CATEGORIES,
    logEvent,
  };
}

