import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

export interface TurnKeyProject {
  id: string;
  creator_id: string;
  title: string;
  slug: string;
  description: string | null;
  category: string;
  images: string[];
  status: string;
  creator_backing_credits: number;
  community_matched: number;
  matching_cap: number;
  current_tier: string;
  early_adopter_slots: number;
  early_adopter_filled: number;
  production_method: string | null;
  stl_file_url: string | null;
  cue_card_id: string | null;
  created_at: string;
  updated_at: string;
  creator_display_name?: string;
  creator_avatar_url?: string;
}

interface UseProjectsOptions {
  category?: string;
  cueCardSlug?: string;
  sort?: 'newest' | 'most_backed' | 'almost_funded' | 'most_wanted' | 'most_pledged';
  showcaseOnly?: boolean;
}

export function useTurnKeyProjects(opts: UseProjectsOptions = {}) {
  return useQuery({
    queryKey: ['turnkey-projects', opts],
    queryFn: async () => {
      let query = supabase
        .from('turnkey_projects' as never)
        .select('*')
        .neq('status', 'draft');

      if (opts.showcaseOnly) {
        query = query.eq('is_showcased', true).eq('status', 'showcased');
      }

      if (opts.category) {
        query = query.eq('category', opts.category);
      }

      if (opts.sort === 'most_backed' || opts.sort === 'most_pledged') {
        query = query.order('community_matched', { ascending: false });
      } else if (opts.sort === 'almost_funded') {
        query = query.order('early_adopter_filled', { ascending: false });
      } else {
        query = query.order('created_at', { ascending: false });
      }

      const { data, error } = await query as { data: TurnKeyProject[] | null; error: unknown };
      if (error) throw error;
      return (data || []) as TurnKeyProject[];
    },
    staleTime: 30_000,
  });
}

import { useState, useCallback } from 'react';

// MISS-004 — Universal Scale Adapter (#9)
// 25mm/28mm/32mm compatibility via adapter rings.
// Three concentric adapter rings snap onto Hexel tile base,
// each step adding 1.5mm height.
// Visual snap indicator shows which scale is active.

export type ScaleMode = '25mm' | '28mm' | '32mm';
export type RingState = 'retracted' | 'extending' | 'snapped' | 'locked';

export interface AdapterRing {
  id: number;
  heightAddMm: number;    // 0, 1.5, 3.0
  snapState: RingState;
  isRequired: boolean;    // required for current scale
  snapForceN: number;     // Newtons to engage
  color: string;
}

export interface ScaleAdapterState {
  targetScale: ScaleMode;
  activeScale: ScaleMode;
  rings: AdapterRing[];
  totalHeightMm: number;    // base 25mm + ring additions
  compatibilityScore: number; // 0–100%
  snapComplete: boolean;
  miniatureCount: number;   // how many minis fit current scale
  ringChangeCount: number;
}

export interface ScaleAdapterControls {
  setScale: (scale: ScaleMode) => void;
  snapRings: () => void;
  resetRings: () => void;
  addMiniature: () => void;
}

const SCALE_CONFIG: Record<ScaleMode, { ringsRequired: number; miniatureCount: number }> = {
  '25mm': { ringsRequired: 0, miniatureCount: 6 },
  '28mm': { ringsRequired: 1, miniatureCount: 5 },
  '32mm': { ringsRequired: 2, miniatureCount: 4 },
};

const RING_COLORS = ['#f59e0b', '#22d3ee', '#a78bfa'];

function buildRings(): AdapterRing[] {
  return [
    { id: 1, heightAddMm: 1.5, snapState: 'retracted', isRequired: false, snapForceN: 8.5, color: RING_COLORS[0] },
    { id: 2, heightAddMm: 1.5, snapState: 'retracted', isRequired: false, snapForceN: 9.2, color: RING_COLORS[1] },

    { id: 3, heightAddMm: 1.5, snapState: 'retracted', isRequired: false, snapForceN: 10.0, color: RING_COLORS[2] },
  ];
}

export function useUniversalScaleAdapter(): {
  state: ScaleAdapterState;
  controls: ScaleAdapterControls;
} {
  const [state, setState] = useState<ScaleAdapterState>({
    targetScale: '25mm',
    activeScale: '25mm',
    rings: buildRings(),
    totalHeightMm: 25,
    compatibilityScore: 100,
    snapComplete: true,
    miniatureCount: 6,
    ringChangeCount: 0,
  });

  const setScale = useCallback((scale: ScaleMode) => {
    setState(prev => {
      const config = SCALE_CONFIG[scale];
      const rings = buildRings().map((r, i) => ({
        ...r,
        isRequired: i < config.ringsRequired,
        snapState: ('retracted' as RingState),
      }));
      return { ...prev, targetScale: scale, rings, snapComplete: false, miniatureCount: config.miniatureCount };
    });
  }, []);

  const snapRings = useCallback(() => {
    setState(prev => {
      const config = SCALE_CONFIG[prev.targetScale];
      const rings = prev.rings.map((r, i) => ({
        ...r,
        snapState: (i < config.ringsRequired ? 'snapped' : 'retracted') as RingState,
      }));
      const totalHeightMm = 25 + config.ringsRequired * 1.5;
      const compatibilityScore = Math.round(92 + config.ringsRequired * 3);
      return {
        ...prev,
        rings,
        activeScale: prev.targetScale,
        totalHeightMm,
        compatibilityScore,
        snapComplete: true,
        ringChangeCount: prev.ringChangeCount + 1,
      };
    });

  }, []);

  const resetRings = useCallback(() => {
    setState(prev => ({
      ...prev,
      targetScale: '25mm',
      activeScale: '25mm',
      rings: buildRings(),
      totalHeightMm: 25,
      compatibilityScore: 100,
      snapComplete: true,
      miniatureCount: 6,
    }));
  }, []);

  const addMiniature = useCallback(() => {
    setState(prev => ({
      ...prev,
      miniatureCount: Math.min(prev.miniatureCount + 1, 8),
    }));
  }, []);

  return { state, controls: { setScale, snapRings, resetRings, addMiniature } };
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export type AppRole = 'admin' | 'project_owner' | 'user';

export const useUserRole = () => {
  const { user } = useAuth();

  const { data: roles, isLoading } = useQuery({
    queryKey: ['user-roles', user?.id],
    queryFn: async () => {
      if (!user) return ['user' as AppRole];

      const derivedRoles: AppRole[] = ['user']; // Everyone is at least a user

      // Check if project owner
      const { data: ownedProjects } = await supabase
        .from('projects')
        .select('id')
        .eq('owner_id', user.id)
        .limit(1);

      if (ownedProjects && ownedProjects.length > 0) {
        derivedRoles.push('project_owner');
      }

      // Check if crown holder (admin-level)
      const { data: crownPositions } = await supabase
        .from('crown_positions')
        .select('id')
        .eq('holder_user_id', user.id)
        .limit(1);

      if (crownPositions && crownPositions.length > 0) {
        derivedRoles.push('admin');
      }

      // Check if guild master (admin-level)
      const { data: guildMaster } = await supabase
        .from('guilds')
        .select('id')
        .eq('guild_master_id', user.id)
        .limit(1);

      if (guildMaster && guildMaster.length > 0) {
        if (!derivedRoles.includes('admin')) derivedRoles.push('admin');
      }

      return derivedRoles;

    },
    enabled: !!user,
  });

  const hasRole = (role: AppRole) => {
    return roles?.includes(role) ?? false;
  };

  const isAdmin = hasRole('admin');
  const isProjectOwner = hasRole('project_owner');
  const isBasicUser = hasRole('user');

  return {
    roles: roles || [],
    hasRole,
    isAdmin,
    isProjectOwner,
    isBasicUser,
    isLoading,
  };
};

import { useState, useCallback, useRef, useEffect } from 'react';

// MISS-012 — Water Table Gravity Engine (#22)
// 5+ gallon reservoir at elevation provides sustained hydraulic power.
// Pressure output = reservoir_volume_gallons × gravity_factor × elevation_cm.
// Depletes over time; refill mechanic via rainfall events.

export type ReservoirStatus = 'full' | 'adequate' | 'low' | 'critical' | 'empty';

export interface RainfallEvent {
  id: number;
  volumeGallons: number;
  isActive: boolean;
  ticksRemaining: number;
}

export interface WaterTableGravityState {
  reservoirVolumeGallons: number;
  maxVolumeGallons: number;
  elevationCm: number;
  gravityFactor: number;       // constant: 9.81 m/s²
  pressureOutputPsi: number;   // calculated
  pressureOutputBar: number;
  flowRateGpm: number;         // gallons per minute
  status: ReservoirStatus;
  depletionRateGpm: number;    // consumption per tick
  rainfallEvents: RainfallEvent[];
  totalRainfallGallons: number;
  gameTurn: number;
  tickCount: number;
  isRunning: boolean;
  tickMs: number;
  powerOutputWatts: number;
}

export interface WaterTableGravityControls {
  start: () => void;
  pause: () => void;
  reset: () => void;
  tick: () => void;
  triggerRainfall: (volumeGallons: number) => void;
  setElevation: (cm: number) => void;
  setTickMs: (ms: number) => void;
}

const GRAVITY = 9.81;
const PSI_PER_METER = 1.422; // 1 meter head = 1.422 psi

function computePressure(reservoirGal: number, elevCm: number): { psi: number; bar: number } {
  const headM = elevCm / 100;

  const volumeFactor = Math.min(1, reservoirGal / 5); // normalizes to 5-gal reference
  const psi = parseFloat((headM * PSI_PER_METER * volumeFactor).toFixed(3));
  const bar = parseFloat((psi * 0.0689476).toFixed(4));
  return { psi, bar };
}

function deriveStatus(gallons: number, max: number): ReservoirStatus {
  const frac = gallons / max;
  if (frac >= 0.9) return 'full';
  if (frac >= 0.5) return 'adequate';
  if (frac >= 0.25) return 'low';
  if (frac > 0) return 'critical';
  return 'empty';
}

let rainfallIdCounter = 0;

export function useWaterTableGravity(initialTickMs = 800): {
  state: WaterTableGravityState;
  controls: WaterTableGravityControls;
} {
  const [state, setState] = useState<WaterTableGravityState>(() => {
    const elevation = 91.44; // 3-foot head
    const volume = 5.5;
    const { psi, bar } = computePressure(volume, elevation);
    return {
      reservoirVolumeGallons: volume,
      maxVolumeGallons: 10,
      elevationCm: elevation,
      gravityFactor: GRAVITY,
      pressureOutputPsi: psi,
      pressureOutputBar: bar,
      flowRateGpm: parseFloat((psi * 0.12).toFixed(3)),
      status: 'adequate',
      depletionRateGpm: 0.08,
      rainfallEvents: [],
      totalRainfallGallons: 0,
      gameTurn: 0,
      tickCount: 0,
      isRunning: false,
      tickMs: initialTickMs,
      powerOutputWatts: 0,
    };
  });

  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const tick = useCallback(() => {
    setState(prev => {
      const tickCount = prev.tickCount + 1;

      const gameTurn = Math.floor(tickCount / 12);

      // Process rainfall events
      let rainfallAdd = 0;
      const rainfallEvents = prev.rainfallEvents
        .map(e => {
          if (!e.isActive) return e;
          rainfallAdd += e.volumeGallons / Math.max(e.ticksRemaining, 1);
          return { ...e, ticksRemaining: e.ticksRemaining - 1, isActive: e.ticksRemaining > 1 };
        })
        .filter(e => e.isActive || e.ticksRemaining > 0);

      // Deplete reservoir by consumption, add rainfall
      const depleteAmount = prev.status === 'empty' ? 0 : prev.depletionRateGpm;
      const newVolume = Math.max(0, Math.min(prev.maxVolumeGallons, prev.reservoirVolumeGallons - depleteAmount + rainfallAdd));

      const { psi, bar } = computePressure(newVolume, prev.elevationCm);
      const flowRateGpm = parseFloat((psi * 0.12).toFixed(3));
      const powerOutputWatts = parseFloat((bar * 1e5 * flowRateGpm * 6.309e-5).toFixed(3)); // P = pressure × volumetric flow
      const status = deriveStatus(newVolume, prev.maxVolumeGallons);

      return {
        ...prev,
        reservoirVolumeGallons: parseFloat(newVolume.toFixed(3)),
        pressureOutputPsi: psi,
        pressureOutputBar: bar,
        flowRateGpm,
        powerOutputWatts,
        status,
        rainfallEvents,
        gameTurn,
        tickCount,
      };
    });
  }, []);

  const triggerRainfall = useCallback((volumeGallons: number) => {
    setState(prev => {
      const event: RainfallEvent = {
        id: ++rainfallIdCounter,
        volumeGallons,
        isActive: true,
        ticksRemaining: 6,
      };
      return {
        ...prev,
        rainfallEvents: [...prev.rainfallEvents, event],
        totalRainfallGallons: parseFloat((prev.totalRainfallGallons + volumeGallons).toFixed(2)),
      };
    });

  }, []);

  const setElevation = useCallback((cm: number) => {
    setState(prev => {
      const { psi, bar } = computePressure(prev.reservoirVolumeGallons, cm);
      return { ...prev, elevationCm: cm, pressureOutputPsi: psi, pressureOutputBar: bar };
    });
  }, []);

  const start = useCallback(() => setState(prev => ({ ...prev, isRunning: true })), []);
  const pause = useCallback(() => setState(prev => ({ ...prev, isRunning: false })), []);

  const reset = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    setState(prev => {
      const elevation = 91.44;
      const volume = 5.5;
      const { psi, bar } = computePressure(volume, elevation);
      return {
        ...prev,
        reservoirVolumeGallons: volume,
        elevationCm: elevation,
        pressureOutputPsi: psi,
        pressureOutputBar: bar,
        flowRateGpm: parseFloat((psi * 0.12).toFixed(3)),
        status: 'adequate',
        rainfallEvents: [],
        totalRainfallGallons: 0,
        gameTurn: 0,
        tickCount: 0,
        isRunning: false,
        powerOutputWatts: 0,
      };
    });
  }, []);

  const setTickMs = useCallback((ms: number) => setState(prev => ({ ...prev, tickMs: ms })), []);

  useEffect(() => {
    if (state.isRunning) {
      intervalRef.current = setInterval(tick, state.tickMs);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [state.isRunning, state.tickMs, tick]);

  return { state, controls: { start, pause, reset, tick, triggerRainfall, setElevation, setTickMs } };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

/* ──────────────────────────────────────────────
 * SHARED TYPES
 * ────────────────────────────────────────────── */

type ErrorType = 'visual' | 'layout' | 'typo' | 'broken' | 'accessibility' | 'performance' | 'other';
type ErrorStatus = 'open' | 'documented' | 'fix_proposed' | 'fix_accepted' | 'resolved' | 'duplicate' | 'invalid';
type Severity = 'critical' | 'major' | 'minor' | 'cosmetic';
type FixType = 'css' | 'content' | 'layout' | 'functional' | 'other';
type BountyStatus = 'open' | 'claimed' | 'fulfilled' | 'expired' | 'cancelled';
type ProposalStatus = 'pending' | 'approved' | 'rejected' | 'implemented';

export interface ErrorReport {
  id: string;
  reporter_id: string;
  page_url: string;
  element_selector?: string;
  element_screenshot_url?: string;
  error_type: ErrorType;
  status: ErrorStatus;
  marks_allocated: number;
  created_at: string;
}

export interface ErrorDoc {
  id: string;
  error_id: string;
  documenter_id: string;
  description: string;
  expected_behavior?: string;
  browser_info?: string;
  device_info?: string;
  steps_to_reproduce?: string;
  severity?: Severity;
  marks_earned: number;
  created_at: string;
}

export interface FixProposal {
  id: string;
  error_id: string;
  proposer_id: string;
  fix_type: FixType;
  proposed_css?: string;
  proposed_html?: string;
  proposed_content?: string;
  description: string;

  marks_earned: number;
  status: ProposalStatus;
  created_at: string;
}

export interface Bounty {
  id: string;
  error_id?: string;
  creator_id: string;
  title: string;
  description: string;
  marks_reward: number;
  marks_pool: number;
  status: BountyStatus;
  fulfilled_by?: string;
  fulfilled_at?: string;
  expires_at?: string;
  created_at: string;
}

export interface AuctionEntry {
  id: string;
  fix_proposal_id?: string;
  element_overlay_id?: string;
  submitter_id: string;
  auction_cycle: string;
  title: string;
  nickname?: string;
  bid_total: number;
  display_duration_seconds: number;
  is_winner: boolean;
  created_at: string;
}

export interface DailyStats {
  id: string;
  user_id: string;
  stat_date: string;
  errors_found: number;
  errors_documented: number;
  fixes_proposed: number;
  bounties_created: number;
  bounties_fulfilled: number;
  marks_earned: number;
  streak_days: number;
}

/* ──────────────────────────────────────────────
 * HOOK: useErrorReports
 * ────────────────────────────────────────────── */

export function useErrorReports(pageUrl?: string) {
  const { user } = useAuth();
  const qc = useQueryClient();

  const openErrors = useQuery({
    queryKey: ['error-reports', pageUrl ?? 'all'],
    queryFn: async () => {
      let q = supabase.from('error_reports' as never).select('*').order('created_at', { ascending: false });
      if (pageUrl) q = q.eq('page_url', pageUrl);
      const { data } = await q;
      return (data ?? []) as unknown as ErrorReport[];
    },
  });

  const myReports = useQuery({
    queryKey: ['error-reports', 'mine', user?.id],
    enabled: !!user,
    queryFn: async () => {
      const { data } = await supabase
        .from('error_reports' as never)
        .select('*')
        .eq('reporter_id', user!.id)
        .order('created_at', { ascending: false });
      return (data ?? []) as unknown as ErrorReport[];
    },
  });

  const reportError = useMutation({
    mutationFn: async (args: { pageUrl: string; elementSelector?: string; errorType: ErrorType }) => {
      const { data, error } = await supabase.from('error_reports' as never).insert({
        reporter_id: user!.id,
        page_url: args.pageUrl,
        element_selector: args.elementSelector,
        error_type: args.errorType,
      } as never).select().single();
      if (error) throw error;
      return data as unknown as ErrorReport;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['error-reports'] });
      qc.invalidateQueries({ queryKey: ['xray-daily-stats'] });
    },
  });

  const updateStatus = useMutation({
    mutationFn: async (args: { id: string; status: ErrorStatus }) => {
      const { error } = await supabase
        .from('error_reports' as never)
        .update({ status: args.status } as never)

        .eq('id', args.id);
      if (error) throw error;
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['error-reports'] }),
  });

  return { openErrors, myReports, reportError, updateStatus };
}

/* ──────────────────────────────────────────────
 * HOOK: useErrorDocumentation
 * ────────────────────────────────────────────── */

export function useErrorDocumentation(errorId?: string) {
  const { user } = useAuth();
  const qc = useQueryClient();

  const docs = useQuery({
    queryKey: ['error-documentation', errorId],
    enabled: !!errorId,
    queryFn: async () => {
      const { data } = await supabase
        .from('error_documentation' as never)
        .select('*')
        .eq('error_id', errorId!)
        .order('created_at', { ascending: false });
      return (data ?? []) as unknown as ErrorDoc[];
    },
  });

  const documentError = useMutation({
    mutationFn: async (args: {
      errorId: string;
      description: string;
      severity?: Severity;
      expectedBehavior?: string;
      stepsToReproduce?: string;
    }) => {
      const { data, error } = await supabase.from('error_documentation' as never).insert({
        error_id: args.errorId,
        documenter_id: user!.id,
        description: args.description,
        severity: args.severity,
        expected_behavior: args.expectedBehavior,
        steps_to_reproduce: args.stepsToReproduce,
        browser_info: navigator.userAgent,
        device_info: `${screen.width}x${screen.height}`,
      } as never).select().single();
      if (error) throw error;
      return data as unknown as ErrorDoc;

    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['error-documentation'] });
      qc.invalidateQueries({ queryKey: ['xray-daily-stats'] });
    },
  });

  return { docs, documentError };
}

/* ──────────────────────────────────────────────
 * HOOK: useFixProposals
 * ────────────────────────────────────────────── */

export function useFixProposals(errorId?: string) {
  const { user } = useAuth();
  const qc = useQueryClient();

  const proposals = useQuery({
    queryKey: ['fix-proposals', errorId],
    enabled: !!errorId,
    queryFn: async () => {
      const { data } = await supabase
        .from('fix_proposals' as never)
        .select('*')
        .eq('error_id', errorId!)
        .order('created_at', { ascending: false });
      return (data ?? []) as unknown as FixProposal[];
    },
  });

  const proposeFix = useMutation({
    mutationFn: async (args: {
      errorId: string;
      fixType: FixType;
      description: string;
      proposedCss?: string;
      proposedHtml?: string;
      proposedContent?: string;
    }) => {
      const { data, error } = await supabase.from('fix_proposals' as never).insert({
        error_id: args.errorId,
        proposer_id: user!.id,
        fix_type: args.fixType,
        description: args.description,
        proposed_css: args.proposedCss,
        proposed_html: args.proposedHtml,
        proposed_content: args.proposedContent,
      } as never).select().single();
      if (error) throw error;

      return data as unknown as FixProposal;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['fix-proposals'] });
      qc.invalidateQueries({ queryKey: ['xray-daily-stats'] });
    },
  });

  const approveProposal = useMutation({
    mutationFn: async (proposalId: string) => {
      const { error } = await supabase
        .from('fix_proposals' as never)
        .update({ status: 'approved' } as never)
        .eq('id', proposalId);
      if (error) throw error;
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['fix-proposals'] }),
  });

  return { proposals, proposeFix, approveProposal };
}

/* ──────────────────────────────────────────────
 * HOOK: useBounties
 * ────────────────────────────────────────────── */

export function useBounties() {
  const { user } = useAuth();
  const qc = useQueryClient();

  const openBounties = useQuery({
    queryKey: ['bounties', 'open'],
    queryFn: async () => {
      const { data } = await supabase
        .from('error_bounties' as never)
        .select('*')
        .eq('status', 'open')
        .order('marks_reward', { ascending: false });
      return (data ?? []) as unknown as Bounty[];
    },
  });

  const myBounties = useQuery({
    queryKey: ['bounties', 'mine', user?.id],
    enabled: !!user,
    queryFn: async () => {
      const { data } = await supabase
        .from('error_bounties' as never)
        .select('*')
        .eq('creator_id', user!.id)

        .order('created_at', { ascending: false });
      return (data ?? []) as unknown as Bounty[];
    },
  });

  const createBounty = useMutation({
    mutationFn: async (args: {
      title: string;
      description: string;
      marksReward: number;
      errorId?: string;
      expiresAt?: string;
    }) => {
      const { data, error } = await supabase.from('error_bounties' as never).insert({
        creator_id: user!.id,
        title: args.title,
        description: args.description,
        marks_reward: args.marksReward,
        marks_pool: args.marksReward,
        error_id: args.errorId,
        expires_at: args.expiresAt,
      } as never).select().single();
      if (error) throw error;
      return data as unknown as Bounty;
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['bounties'] }),
  });

  const contributeToBounty = useMutation({
    mutationFn: async (args: { bountyId: string; marksAmount: number }) => {
      const { error } = await supabase.from('bounty_contributions' as never).insert({
        bounty_id: args.bountyId,
        contributor_id: user!.id,
        marks_amount: args.marksAmount,
      } as never);
      if (error) throw error;
      // Also increment the pool total
      const { error: upErr } = await supabase.rpc('increment_bounty_pool' as never, {
        p_bounty_id: args.bountyId,
        p_amount: args.marksAmount,
      } as never);
      if (upErr) {
        // Fallback: direct update if RPC doesn't exist yet
        await supabase
          .from('error_bounties' as never)
          .update({ marks_pool: args.marksAmount } as never)
          .eq('id', args.bountyId);
      }
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['bounties'] }),

  });

  const fulfillBounty = useMutation({
    mutationFn: async (bountyId: string) => {
      const { error } = await supabase
        .from('error_bounties' as never)
        .update({
          status: 'fulfilled',
          fulfilled_by: user!.id,
          fulfilled_at: new Date().toISOString(),
        } as never)
        .eq('id', bountyId);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['bounties'] });
      qc.invalidateQueries({ queryKey: ['xray-daily-stats'] });
    },
  });

  return { openBounties, myBounties, createBounty, contributeToBounty, fulfillBounty };
}

/* ──────────────────────────────────────────────
 * HOOK: useDesignAuction
 * ────────────────────────────────────────────── */

